  // ============================================================================
  // 🆕 SISTEMA DE CACHÉ PARA ANÁLISIS MORFOLÓGICOS
  // ============================================================================
  
  /**
   * Guarda el análisis morfológico completo en el objeto para recuperación posterior
   */
  function guardarAnalisisEnCache(obj, metricas) {
    console.log(`💾 Guardando análisis en caché para ${obj.id}`);
    
    // 🔍 Buscar el objeto original en el array objects
    const objetoOriginal = objects.find(o => o.id === obj.id);
    
    // Usar el objeto original si existe, o el recibido como fallback
    // (caso: análisis abierto desde gestión de proyectos, obj no está en objects[])
    const targetObj = objetoOriginal || obj;
    
    if (!objetoOriginal) {
      console.warn(`⚠️ No se encontró el objeto ${obj.id} en el array objects — usando objeto recibido como fallback`);
    }
    
    // Capturar estado de los canvas
    const canvasData = capturarCanvasData();
    
    // 🔧 CRÍTICO: Incluir perforaciones y horadaciones en las métricas del caché
    const metricasConPH = {
      ...metricas,
      // Asegurar que P/H estén incluidas
      perforaciones: obj.perforaciones || metricas.perforaciones || [],
      horadaciones: obj.horadaciones || metricas.horadaciones || [],
      // ADR-009: candidatos P/H seedless (sugerencias sin confirmar) persistidos
      phCandidatos: obj.phCandidatos || metricas.phCandidatos || []
    };
    
    targetObj.analisisCached = {
      metricas: metricasConPH, // Métricas con P/H incluidas
      canvasData: canvasData,
      timestamp: new Date().toISOString(),
      escalaUsada: scale,
      escalaCorregida: window.escalaCorregida?.activa || false
    };
    
    console.log(`✅ Análisis guardado en caché para ${targetObj === objetoOriginal ? 'objeto original' : 'copia'}:`, {
      canvas: canvasData.morphological ? 'SÍ' : 'NO',
      perforaciones: metricasConPH.perforaciones.length,
      horadaciones: metricasConPH.horadaciones.length
    });
  }
  
  /**
   * Captura los datos de imagen de los canvas morfológicos
   */
  function capturarCanvasData() {
    const data = {};
    
    // Canvas morfológico principal
    const morphCanvas = document.getElementById('morphologicalCanvas');
    if (morphCanvas && morphCanvas.width > 0) {
      try {
        data.morphological = morphCanvas.toDataURL('image/png');
        console.log('  ✓ Canvas morfológico capturado');
      } catch (e) {
        console.warn('  ⚠️ No se pudo capturar canvas morfológico:', e.message);
      }
    }
    
    // Canvas de forma idealizada
    const idealCanvas = document.getElementById('idealizedShapeCanvas');
    if (idealCanvas && idealCanvas.width > 0) {
      try {
        data.idealized = idealCanvas.toDataURL('image/png');
        console.log('  ✓ Canvas idealizado capturado');
      } catch (e) {
        console.warn('  ⚠️ No se pudo capturar canvas idealizado:', e.message);
      }
    }
    
    // Canvas esquemático
    const schematicCanvas = document.getElementById('schematicCanvas');
    if (schematicCanvas && schematicCanvas.width > 0) {
      try {
        data.schematic = schematicCanvas.toDataURL('image/png');
        console.log('  ✓ Canvas esquemático capturado');
      } catch (e) {
        console.warn('  ⚠️ No se pudo capturar canvas esquemático:', e.message);
      }
    }
    
    return data;
  }

  /**
   * Captura los tres canvas (morfológico, idealizado, esquemático) y los persiste
   * en obj.canvasImgenes. Si obj pertenece a analisisMorfologicos.objetos también
   * actualiza esa copia, de modo que la exportación PDF siempre encuentre las
   * imágenes al leer obj.canvasImgenes sin acceder al DOM.
   *
   * @param {object} obj  - Objeto de detección (debe tener .id y .analisisCached u obj.metricas)
   * @returns {boolean}   - true si al menos el canvas morfológico fue capturado
   */
  function guardarCanvasEnObjeto(obj) {
    if (!obj) return false;

    const data = capturarCanvasData();
    if (!data.morphological && !data.idealized && !data.schematic) return false;

    // Persistir en el objeto de detección (objects[])
    if (!obj.canvasImgenes) obj.canvasImgenes = {};
    if (data.morphological) obj.canvasImgenes.morphological = data.morphological;
    if (data.idealized)     obj.canvasImgenes.idealized     = data.idealized;
    if (data.schematic)     obj.canvasImgenes.schematic     = data.schematic;

    // Persistir en analisisMorfologicos.objetos para que el PDF lo encuentre incluso si
    // el objeto exportado viene de esa colección y no de objects[].
    if (analisisMorfologicos && analisisMorfologicos.objetos) {
      const guardado = analisisMorfologicos.objetos.find(o => o.id === obj.id);
      if (guardado) {
        if (!guardado.canvasImgenes) guardado.canvasImgenes = {};
        if (data.morphological) guardado.canvasImgenes.morphological = data.morphological;
        if (data.idealized)     guardado.canvasImgenes.idealized     = data.idealized;
        if (data.schematic)     guardado.canvasImgenes.schematic     = data.schematic;
      }
    }

    // Persistir también en analisisCached para que los proyectos cargados los conserven
    if (obj.analisisCached) {
      if (!obj.analisisCached.canvasData) obj.analisisCached.canvasData = {};
      if (data.morphological) obj.analisisCached.canvasData.morphological = data.morphological;
      if (data.idealized)     obj.analisisCached.canvasData.idealized     = data.idealized;
      if (data.schematic)     obj.analisisCached.canvasData.schematic     = data.schematic;
    }

    console.log(`[canvasGuardado] ${obj.id} — morfológico:${!!data.morphological} idealizado:${!!data.idealized} esquemático:${!!data.schematic}`);
    return !!data.morphological;
  }

  /**
   * Restaura los canvas desde los datos guardados
   */
  function restaurarCanvasDesdeCache(canvasData) {
    console.log('🔄 Restaurando canvas desde caché...');
    
    let restaurados = 0;
    
    // Restaurar canvas morfológico
    if (canvasData.morphological) {
      const morphCanvas = document.getElementById('morphologicalCanvas');
      if (morphCanvas) {
        const img = new Image();
        img.onload = function() {
          const ctx = morphCanvas.getContext('2d');
          morphCanvas.width = img.width;
          morphCanvas.height = img.height;
          ctx.drawImage(img, 0, 0);
          console.log('  ✓ Canvas morfológico restaurado');
        };
        img.src = canvasData.morphological;
        restaurados++;
      }
    }
    
    // Restaurar canvas idealizado
    if (canvasData.idealized) {
      const idealCanvas = document.getElementById('idealizedShapeCanvas');
      if (idealCanvas) {
        const img = new Image();
        img.onload = function() {
          const ctx = idealCanvas.getContext('2d');
          idealCanvas.width = img.width;
          idealCanvas.height = img.height;
          ctx.drawImage(img, 0, 0);
          console.log('  ✓ Canvas idealizado restaurado');
        };
        img.src = canvasData.idealized;
        restaurados++;
      }
    }
    
    // Restaurar canvas esquemático
    if (canvasData.schematic) {
      const schematicCanvas = document.getElementById('schematicCanvas');
      if (schematicCanvas) {
        const img = new Image();
        img.onload = function() {
          const ctx = schematicCanvas.getContext('2d');
          schematicCanvas.width = img.width;
          schematicCanvas.height = img.height;
          ctx.drawImage(img, 0, 0);
          console.log('  ✓ Canvas esquemático restaurado');
        };
        img.src = canvasData.schematic;
        restaurados++;
      }
    }
    
    console.log(`✅ ${restaurados} canvas(es) restaurado(s) desde caché`);
  }

  /**
   * Limpia el caché de análisis de un objeto específico o de todos
   */
  function limpiarCacheAnalisis(objetoId = null) {
    if (objetoId) {
      const obj = objects.find(o => o.id === objetoId);
      if (obj && obj.analisisCached) {
        delete obj.analisisCached;
        console.log(`🧹 Caché eliminado para ${objetoId}`);
        return true;
      }
      return false;
    } else {
      // Limpiar todos los cachés
      let eliminados = 0;
      objects.forEach(obj => {
        if (obj.analisisCached) {
          delete obj.analisisCached;
          eliminados++;
        }
      });
      console.log(`🧹 ${eliminados} caché(s) de análisis eliminado(s)`);
      return eliminados;
    }
  }
  
  /**
   * Invalida caché si la escala cambió (por ejemplo, al aplicar corrección)
   */
  function invalidarCachePorCambioEscala() {
    const objetosConCache = objects.filter(o => o.analisisCached);
    if (objetosConCache.length === 0) return;
    
    console.log(`⚠️ Escala modificada - Invalidando ${objetosConCache.length} análisis cacheados`);
    
    objetosConCache.forEach(obj => {
      if (obj.analisisCached.escalaUsada !== scale) {
        const anterior = obj.analisisCached.escalaUsada;
        if (anterior != null) {
          console.log(`  • ${obj.id}: escala cambió de ${anterior.toFixed(6)} a ${scale.toFixed(6)}`);
        } else {
          console.log(`  • ${obj.id}: escalaUsada no definida — invalidando caché`);
        }
        delete obj.analisisCached;
      }
    });
  }

  // =====================================================================================
  // CLASES DE OPTIMIZACIÓN DE MEMORIA Y RENDIMIENTO
  // =====================================================================================

  // Canvas Pool Manager - Reutilización de canvas para evitar fugas de memoria (OPTIMIZADO)
  class CanvasPool {
    constructor() {
      this.pool = [];
      this.maxSize = Math.min(8, navigator.hardwareConcurrency || 4); // Dinámico basado en hardware
      this.statsCreated = 0;
      this.statsReused = 0;
      this.maxMemoryUsage = 200 * 1024 * 1024; // 200MB máximo para canvas pool
      this.currentMemoryUsage = 0;
      this.lastCleanup = Date.now();
      this.cleanupInterval = 30000; // Limpiar cada 30 segundos
    }
    
    getCanvas(width, height) {
      // Buscar canvas existente que sea suficientemente grande
      for (let i = 0; i < this.pool.length; i++) {
        const canvas = this.pool[i];
        if (canvas.width >= width && canvas.height >= height) {
          this.pool.splice(i, 1); // Remover del pool
          canvas.width = width;   // Redimensionar exacto
          canvas.height = height;
          this.statsReused++;
          console.log(`Canvas reutilizado: ${width}×${height} (reutilizados: ${this.statsReused})`);
          return canvas;
        }
      }
      
      // Crear nuevo canvas si no hay disponible
      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      this.statsCreated++;
      console.log(`Canvas creado: ${width}×${height} (creados: ${this.statsCreated})`);
      return canvas;
    }
    
    returnCanvas(canvas) {
      if (this.pool.length < this.maxSize) {
        // Limpiar canvas antes de retornar
        const ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        this.pool.push(canvas);
        console.log(`Canvas retornado al pool (${this.pool.length}/${this.maxSize})`);
      } else {
        // Pool lleno, forzar liberación
        canvas.width = 0;
        canvas.height = 0;
        console.log('Canvas liberado (pool lleno)');
      }
    }
    
    clearPool() {
      this.pool.forEach(canvas => {
        canvas.width = 0;
        canvas.height = 0;
      });
      this.pool = [];
      console.log('Pool de canvas limpiado completamente');
    }
    
    getStats() {
      return {
        poolSize: this.pool.length,
        maxSize: this.maxSize,
        created: this.statsCreated,
        reused: this.statsReused,
        efficiency: this.statsCreated > 0 ? ((this.statsReused / (this.statsCreated + this.statsReused)) * 100).toFixed(1) : 0
      };
    }
  }

  // Memory Monitor - Seguimiento en tiempo real del uso de memoria
  class MemoryMonitor {
    constructor() {
      this.maxMemoryMB = 1024; // Límite 1GB por defecto
      this.checkInterval = 5000; // Revisar cada 5 segundos
      this.isMonitoring = false;
      this.alertThreshold = 0.8; // Alerta al 80% de uso
    }
    
    startMonitoring() {
      if (this.isMonitoring) return;
      
      this.isMonitoring = true;
      this.monitorInterval = setInterval(() => {
        this.checkMemoryUsage();
      }, this.checkInterval);
      
      console.log('🔍 Monitor de memoria activado');
      this.createMemoryIndicator();
    }
    
    checkMemoryUsage() {
      if ('memory' in performance) {
        const memInfo = performance.memory;
        const usedMB = (memInfo.usedJSHeapSize / 1024 / 1024).toFixed(1);
        const totalMB = (memInfo.totalJSHeapSize / 1024 / 1024).toFixed(1);
        const limitMB = (memInfo.jsHeapSizeLimit / 1024 / 1024).toFixed(1);
        const usagePercent = (memInfo.usedJSHeapSize / memInfo.jsHeapSizeLimit * 100).toFixed(1);
        
        // Alerta si uso excesivo
        if (usagePercent > this.alertThreshold * 100) {
          console.warn(`⚠️ USO EXCESIVO DE MEMORIA: ${usagePercent}%`);
          this.triggerMemoryCleanup();
        }
        
        // Actualizar UI
        this.updateMemoryUI(usedMB, totalMB, limitMB, usagePercent);
        
        return {
          used: parseFloat(usedMB),
          total: parseFloat(totalMB),
          limit: parseFloat(limitMB),
          percentage: parseFloat(usagePercent)
        };
      }
      return null;
    }
    
    triggerMemoryCleanup() {
      console.log('🧹 Ejecutando limpieza de memoria de emergencia...');
      
      // Limpiar pool de canvas
      if (window.canvasPool) {
        window.canvasPool.clearPool();
      }
      
      // Forzar recolección de basura si está disponible
      if (window.gc && typeof window.gc === 'function') {
        window.gc();
      }
      
      // Notificar al usuario
      if (typeof setStatus === 'function') {
        UtilityHelpers.setStatus('Limpieza de memoria ejecutada. Considere usar imágenes más pequeñas.', true);
      }
    }
    
    createMemoryIndicator() {
      // Indicador de RAM eliminado de la UI (monitor interno activo en consola).
    }
    
    updateMemoryUI(used, total, limit, percentage) {
      // Sin indicador visual; los datos siguen disponibles en checkMemoryUsage().
    }
    
    stopMonitoring() {
      if (this.monitorInterval) {
        clearInterval(this.monitorInterval);
      }
      this.isMonitoring = false;
      
      // Remover indicador UI
      const indicator = document.getElementById('memory-indicator');
      if (indicator) {
        indicator.remove();
      }
      console.log('Monitor de memoria desactivado');
    }
  }

