  function setStatus(msg, isError=false){
    statusDiv.textContent = msg;
    statusDiv.style.color = isError ? '#777' : '#555';
  }
  
  function actualizarEstadisticas() {
    const totalObjectsEl = document.getElementById('totalObjects');
    const avgAreaEl = document.getElementById('avgArea');
    const lastAnalysisEl = document.getElementById('lastAnalysis');
    
    if (!totalObjectsEl || !avgAreaEl || !lastAnalysisEl) return;
    
    // Actualizar total de objetos
    totalObjectsEl.textContent = objects.length;
    
    // Calcular área promedio usando métricas reales
    if (objects.length > 0) {
      let totalArea = 0;
      let realContourCount = 0;
      
      objects.forEach(obj => {
        const useArea = obj.has_real_contour ? obj.real_area : obj.area;
        totalArea += useArea;
        if (obj.has_real_contour) realContourCount++;
      });
      
      const avgArea = totalArea / objects.length;
      // Usar la variable global 'scale' directamente en vez de llamar calcularEscala(),
      // que dispara redraw() → actualizarEstadisticas() → bucle infinito.
      if (scale && scale > 0) {
        const avgAreaMm2 = (avgArea * scale * scale).toFixed(2);
        const method = realContourCount > 0 ? 
          `${avgAreaMm2} mm² (${realContourCount}/${objects.length} REAL)` : 
          `${avgAreaMm2} mm² (APROX)`;
        avgAreaEl.textContent = method;
      } else {
        avgAreaEl.textContent = `${avgArea.toFixed(1)} px²`;
      }
    } else {
      avgAreaEl.textContent = '0 mm²';
    }
    
    // Actualizar timestamp del último análisis
    const now = new Date();
    lastAnalysisEl.textContent = now.toLocaleTimeString();
  }

  function validarEntradas(){
    if(!image) {
      UtilityHelpers.setStatus('Error: Cargue primero la imagen JPG o archivo RAW.', true);
      return false;
    }
    const focal = parseFloat(focalInput.value);
    const distancia = parseFloat(distanciaInput.value);
    const sensorWidth = parseFloat(sensorWidthInput.value);
    
    if(isNaN(focal) || focal <= 0) {
      UtilityHelpers.setStatus('Error: Distancia focal inválida.', true);
      return false;
    }
    if(isNaN(distancia) || distancia <= 0){
      UtilityHelpers.setStatus('Error: Distancia lente-objeto inválida.', true);
      return false;
    }
    if(isNaN(sensorWidth) || sensorWidth <= 0){
      UtilityHelpers.setStatus('Error: Dimensiones del sensor no disponibles.', true);
      return false;
    }
    UtilityHelpers.setStatus('Datos válidos.', false);
    return true;
  }

  // ============================================================================
  // 🔭 MODELO DE ERROR ÓPTICO POSICIONAL
  // Estima la incertidumbre de medición debida a:
  //   1. Distorsión radial del lente (k1 empírico según FOV)
  //   2. Error de perspectiva plana (objeto fuera del eje óptico)
  //
  // Parámetros:
  //   objCentroide {x, y}  – centroide del objeto en píxeles (coord. imagen completa)
  //   imgW, imgH           – dimensiones de la imagen en píxeles
  //   focalMM              – distancia focal en mm
  //   sensorW, sensorH     – dimensiones del sensor en mm
  //   distanciaObjMM       – distancia lente→objeto en mm
  //
  // Retorna: objeto con coeficientes y márgenes de error
  // ============================================================================
  function estimarErrorOptico({ objCentroide, imgW, imgH, focalMM, sensorW, sensorH, distanciaObjMM }) {
    if (!focalMM || !sensorW || !imgW || !distanciaObjMM) {
      return null; // Sin parámetros suficientes
    }

    // --- 1. Coeficiente de distorsión radial estimado (k1) ---
    // Basado en el campo visual diagonal (empírico, +/- 30% sin calibración)
    const diagSensor = Math.sqrt(sensorW * sensorW + (sensorH || sensorW) * (sensorH || sensorW));
    const fovDiagRad = 2 * Math.atan(diagSensor / (2 * focalMM));
    const fovDiagDeg = fovDiagRad * (180 / Math.PI);

    // Tabla de k1 típico por categoría de lente (valores negativos = distorsión barril)
    // Lente > 85 mm: prácticamente sin distorsión perceptible
    // Lente 35-84 mm: leve distorsión
    // Lente 20-34 mm: distorsión moderada
    // Lente < 20 mm: distorsión severa
    let k1;
    if (fovDiagDeg < 20) {
      k1 = -0.0003;               // Teleobjetivo muy largo
    } else if (fovDiagDeg < 30) {
      k1 = -0.0010;               // Teleobjetivo
    } else if (fovDiagDeg < 45) {
      k1 = -0.0035;               // Normal-tele
    } else if (fovDiagDeg < 60) {
      k1 = -0.0120;               // Normal-gran angular
    } else if (fovDiagDeg < 75) {
      k1 = -0.0400;               // Gran angular
    } else if (fovDiagDeg < 90) {
      k1 = -0.1000;               // Gran angular severo
    } else {
      k1 = -0.2200;               // Ultra-gran angular / ojo de pez
    }

    // --- 2. Posición radial normalizada del objeto ---
    const cx = imgW / 2;
    const cy = imgH / 2;
    const dx = (objCentroide?.x ?? cx) - cx;
    const dy = (objCentroide?.y ?? cy) - cy;
    const rPx = Math.sqrt(dx * dx + dy * dy);
    const rNorm = rPx / (imgW / 2); // 0 = centro, 1 = borde horizontal

    // --- 3. Desplazamiento por distorsión radial en píxeles ---
    const deltaDistorsionPx = Math.abs(k1) * rNorm * rNorm * rPx;
    const deltaDistorsionMm = deltaDistorsionPx * (sensorW / imgW); // en mm en el sensor

    // --- 4. Error de perspectiva sobre un plano plano ---
    // Para el píxel del centroide: ángulo real respecto al eje óptico
    const xSensorMm = dx * (sensorW / imgW);
    const ySensorMm = dy * ((sensorH || sensorW * imgH / imgW) / imgH);
    const rSensorMm = Math.sqrt(xSensorMm * xSensorMm + ySensorMm * ySensorMm);
    const theta = Math.atan2(rSensorMm, focalMM); // ángulo en radianes

    // Factor de magnificación local vs. centro (1/cos²θ - 1)
    const cosTheta = Math.cos(theta);
    const errorPerspPercent = ((1 / (cosTheta * cosTheta)) - 1) * 100;

    // --- 5. Error lineal y de área combinado (DRSS: cuadratura) ---
    const errorDistorsionPercent = Math.abs(k1) * rNorm * rNorm * 100;
    const errorLinealPercent = Math.sqrt(
      errorDistorsionPercent * errorDistorsionPercent +
      errorPerspPercent * errorPerspPercent
    );
    const errorAreaPercent = Math.sqrt(
      (2 * errorDistorsionPercent) * (2 * errorDistorsionPercent) +
      (2 * errorPerspPercent) * (2 * errorPerspPercent)
    );

    // --- 6. Categoría de confianza ---
    let confianzaCategoria;
    if (errorLinealPercent < 0.5) {
      confianzaCategoria = 'Muy Alta (< 0.5%)';
    } else if (errorLinealPercent < 1.5) {
      confianzaCategoria = 'Alta (< 1.5%)';
    } else if (errorLinealPercent < 3.0) {
      confianzaCategoria = 'Moderada (< 3%)';
    } else if (errorLinealPercent < 6.0) {
      confianzaCategoria = 'Baja (< 6%)';
    } else {
      confianzaCategoria = 'Muy Baja (> 6%)';
    }

    return {
      // Parámetros del modelo
      fovDiagDeg: parseFloat(fovDiagDeg.toFixed(2)),
      k1_estimado: parseFloat(k1.toFixed(6)),
      // Posición del objeto
      posicion_radial_norm: parseFloat(rNorm.toFixed(4)),
      posicion_radial_px: parseFloat(rPx.toFixed(1)),
      angulo_optico_deg: parseFloat((theta * 180 / Math.PI).toFixed(3)),
      // Errores individuales
      error_distorsion_percent: parseFloat(errorDistorsionPercent.toFixed(4)),
      error_perspectiva_percent: parseFloat(errorPerspPercent.toFixed(4)),
      // Errores combinados (los que se reportan)
      error_lineal_percent: parseFloat(errorLinealPercent.toFixed(3)),
      error_area_percent: parseFloat(errorAreaPercent.toFixed(3)),
      // Categoría legible
      confianza_optica: confianzaCategoria,
      // Nota metodológica
      nota: `k1 estimado para FOV ${fovDiagDeg.toFixed(1)}° (sin calibración de lente; incertidumbre del modelo ±30%)`
    };
  }

  // =============================================================================
  // PROPAGACIÓN DE INCERTIDUMBRE ÓPTICA A MÉTRICAS ABSOLUTAS
  // =============================================================================
  // Añade campos _incertidumbre_abs (±mm o ±mm²) y _rango_min / _rango_max
  // para todas las métricas en mm/mm² afectadas por el error óptico posicional.
  // Las métricas dimensionless (ratios en píxeles) NO se modifican porque el
  // factor de escala cancela en numerador y denominador.
  // =============================================================================
  function aplicarIncertidumbreOptica(metrics, errorOptico) {
    if (!errorOptico || typeof errorOptico !== 'object') return metrics;
    if (!metrics || typeof metrics !== 'object') return metrics;

    const eL = errorOptico.error_lineal_percent / 100;  // fracción lineal
    const eA = errorOptico.error_area_percent   / 100;  // fracción de área

    if (isNaN(eL) || isNaN(eA)) return metrics;

    // ----- Métricas lineales (mm) -----
    const metricasLineales = [
      'perimeter', 'width', 'height',
      'eje_mayor', 'eje_menor',
      'radio_maximo', 'radio_minimo', 'radio_medio',
      'feret_max', 'feret_min',
      'perimeter_fragmentado'
    ];

    // ----- Métricas de área (mm²) -----
    const metricasArea = [
      'area',
      'area_fragmentada'
    ];

    metricasLineales.forEach(k => {
      const v = parseFloat(metrics[k]);
      if (!isNaN(v) && isFinite(v)) {
        const err = Math.abs(v) * eL;
        metrics[`${k}_incertidumbre_abs`] = parseFloat(err.toFixed(4));
        metrics[`${k}_rango_min`]          = parseFloat((v - err).toFixed(4));
        metrics[`${k}_rango_max`]          = parseFloat((v + err).toFixed(4));
      }
    });

    metricasArea.forEach(k => {
      const v = parseFloat(metrics[k]);
      if (!isNaN(v) && isFinite(v)) {
        const err = Math.abs(v) * eA;
        metrics[`${k}_incertidumbre_abs`] = parseFloat(err.toFixed(4));
        metrics[`${k}_rango_min`]          = parseFloat((v - err).toFixed(4));
        metrics[`${k}_rango_max`]          = parseFloat((v + err).toFixed(4));
      }
    });

    // Bandera informativa: cuáles métricas NO son afectadas
    metrics._incertidumbre_optica_aplicada = true;
    metrics._metricas_no_afectadas = 'circularity,compactness,rectangularity,elongation,shape_factor,solidity,aspect_ratio,excentricidad,convexity,symmetry_score';

    return metrics;
  }

  // Exponer globalmente para recálculo retroactivo desde el visor de colección
  window.estimarErrorOptico        = MetricsOrchestrator.estimarErrorOptico;
  window.aplicarIncertidumbreOptica = MetricsOrchestrator.aplicarIncertidumbreOptica;

  function calcularEscala() {
    // ============================================================================
    // CÁLCULO DE ESCALA UNIFICADO (Monofacial y Bifacial)
    // ============================================================================
    // IMPORTANTE: Si existe una corrección manual activa, NO recalcular
    // ============================================================================
    if (window.escalaCorregida?.activa) {
      console.log('⚠️ Escala corregida manualmente activa - NO se recalcula automáticamente');
      console.log(`   Usando escala corregida: ${scale.toFixed(6)} mm/px (factor: ${window.escalaCorregida.factorCorreccion.toFixed(4)})`);
      return scale;
    }
    
    // ============================================================================
    // En modo BIFACIAL:
    //   - Se calcula UNA SOLA VEZ usando los metadatos de cualquier cara
    //   - La escala resultante se aplica a AMBAS caras
    //   - Justificación: La verificación de coherencia garantiza que ambas imágenes
    //     tienen los mismos parámetros (cámara, focal, apertura, sensor)
    //   - Por lo tanto, la escala mm/píxel es IDÉNTICA para ambas caras
    // ============================================================================
    
    // Verificar imagen según modo
    let imagenActual = null;
    // Usar variables globales anchoImagen y altoImagen (definidas arriba)
    
    if (modoAnalisis === 'bifacial') {
      // En modo bifacial, usar la primera imagen disponible (priorizar A)
      // NOTA: No importa cuál usemos, la escala será la misma debido a coherencia verificada
      if (imageCaraA) {
        imagenActual = imageCaraA;
        anchoImagen = imageWidthCaraA;
        altoImagen = imageHeightCaraA;
        console.log('   📸 Usando dimensiones de Cara A para cálculo');
      } else if (imageCaraB) {
        imagenActual = imageCaraB;
        anchoImagen = imageWidthCaraB;
        altoImagen = imageHeightCaraB;
        console.log('   📸 Usando dimensiones de Cara B para cálculo');
      }
    } else {
      // Modo monofacial tradicional
      imagenActual = image;
      anchoImagen = imageWidth;
      altoImagen = imageHeight;
    }
    
    if (!imagenActual) {
      scale = null;
      scaleDisplay.textContent = '-';
      console.warn('⚠️ No hay imagen cargada para calcular escala');
      return;
    }
    
    // Usar análisis híbrido si tenemos archivos complementarios (solo en monofacial)
    if (modoAnalisis === 'monofacial' && archivosComplementarios.vinculados) {
      calcularEscalaHibrida();
      return;
    }
    
    const focal = parseFloat(focalInput.value);
    const distancia = parseFloat(distanciaInput.value);
    const sensorWidth = parseFloat(sensorWidthInput.value);
    
    if (!focal || !distancia || !sensorWidth || !anchoImagen) {
      scale = null;
      scaleDisplay.textContent = '-';
      if (!focal) UtilityHelpers.setStatus('Falta: Distancia focal', true);
      else if (!distancia) UtilityHelpers.setStatus('Falta: Distancia lente-objeto', true);
      else if (!sensorWidth) UtilityHelpers.setStatus('Falta: Ancho del sensor', true);
      console.error('❌ Faltan parámetros para cálculo de escala:', {
        focal,
        distancia,
        sensorWidth,
        anchoImagen
      });
      return;
    }
    
    // Fórmula mejorada: escala = (ancho_sensor / ancho_imagen) * (distancia / focal)
    scale = (sensorWidth / anchoImagen) * (distancia / focal);
    scaleDisplay.textContent = scale.toFixed(6);
    
    // Mostrar información detallada sobre la escala calculada
    const pixelsPorMM = 1 / scale;
    const campoVisionW = (anchoImagen * scale).toFixed(1);
    const campoVisionH = (altoImagen * scale).toFixed(1);
    const modoTexto = modoAnalisis === 'bifacial' ? ' (Bifacial)' : '';

    // Estimar error óptico en esquina (peor caso) para orientar al usuario
    let errorEsquinaTxt = '';
    try {
      const errorEsquina = MetricsOrchestrator.estimarErrorOptico({
        objCentroide: { x: anchoImagen, y: altoImagen }, // esquina = peor caso
        imgW: anchoImagen, imgH: altoImagen,
        focalMM: focal, sensorW: sensorWidth,
        sensorH: parseFloat(sensorHeightInput.value) || null,
        distanciaObjMM: distancia
      });
      if (errorEsquina) {
        errorEsquinaTxt = ` | Error óptico: centro=0% → esquina=±${errorEsquina.error_lineal_percent.toFixed(1)}% (${errorEsquina.confianza_optica.split(' ')[0]})`;
      }
    } catch(_) { /* no crítico */ }

    const mensaje = `Escala${modoTexto}: ${scale.toFixed(6)} mm/píxel | Resolución: ${pixelsPorMM.toFixed(2)} px/mm | Campo: ${campoVisionW}×${campoVisionH}mm${errorEsquinaTxt}`;
    UtilityHelpers.setStatus(mensaje, false);
    
    // Log detallado
    console.log(`=== CÁLCULO DE ESCALA DETALLADO ===
    • Modo: ${modoAnalisis}
    • Sensor: ${sensorWidth}mm × ${sensorHeightInput.value}mm
    • Imagen: ${anchoImagen} × ${altoImagen} píxeles
    • Distancia focal: ${focal}mm
    • Distancia objeto: ${distancia}mm
    • Escala resultante: ${scale.toFixed(6)} mm/píxel
    • Resolución: ${pixelsPorMM.toFixed(2)} píxeles/mm
    • Campo de visión: ${(anchoImagen * scale).toFixed(1)}mm × ${(altoImagen * scale).toFixed(1)}mm
    =======================================`);
    
    // Si hay objetos detectados, actualizar automáticamente las mediciones (solo monofacial)
    if (modoAnalisis === 'monofacial' && objects.length > 0) {
      console.log('📐 Actualizando mediciones de objetos con nueva escala...');
      // Forzar redibujado para actualizar etiquetas con nuevas mediciones
      setTimeout(() => {
        requestAnimationFrame(() => redraw());
        // También actualizar objetos individuales si están visibles
        actualizarObjetosIndividuales();
      }, 50);
    }
  }

  /**
   * Cálculo de escala híbrido que combina metadatos RAW precisos con análisis visual JPG
   */
  function calcularEscalaHibrida() {
    // ============================================================================
    // IMPORTANTE: Si existe una corrección manual activa, NO recalcular
    // ============================================================================
    if (window.escalaCorregida?.activa) {
      console.log('⚠️ Escala corregida manualmente activa - NO se recalcula con método híbrido');
      console.log(`   Usando escala corregida: ${scale.toFixed(6)} mm/px (factor: ${window.escalaCorregida.factorCorreccion.toFixed(4)})`);
      return scale;
    }
    
    if (DEBUG_LOGS.detection) {
      console.log('🔗 Utilizando cálculo híbrido JPG+RAW');
    }
    
    // Priorizar metadatos del archivo RAW (más precisos) 
    const metadatos = archivosComplementarios.metadatosRAW || archivosComplementarios.metadatosJPG;
    
    if (!metadatos) {
      scale = null;
      scaleDisplay.textContent = '-';
      UtilityHelpers.setStatus('Error: No hay metadatos disponibles para análisis híbrido', true);
      return;
    }
    
    // Obtener datos más precisos del RAW
    const focalRAW = metadatos.FocalLength;
    const apertureRAW = metadatos.FNumber;
    const makeRAW = metadatos.Make;
    const modelRAW = metadatos.Model;
    
    // Usar distancia manual (siempre necesaria)
    const distancia = parseFloat(distanciaInput.value);
    
    if (!focalRAW || !distancia || !imageWidth) {
      scale = null;
      scaleDisplay.textContent = '-';
      if (!focalRAW) UtilityHelpers.setStatus('Error: No se encontró distancia focal en metadatos RAW', true);
      else if (!distancia) UtilityHelpers.setStatus('Falta: Distancia lente-objeto', true);
      return;
    }
    
    // Obtener dimensiones del sensor desde base de datos mejorada con información RAW
    let sensorWidth = null;
    const modeloCompleto = `${makeRAW} ${modelRAW}`.toLowerCase();
    
    // Base de datos expandida usando info de archivos RAW
    const sensoresRAW = {
      // Nikon
      'nikon d850': { width: 35.9, height: 23.9 },
      'nikon d780': { width: 35.9, height: 23.9 }, 
      'nikon z9': { width: 35.9, height: 23.9 },
      'nikon z7': { width: 35.9, height: 23.9 },
      'nikon d750': { width: 35.9, height: 24.0 },
      
      // Canon
      'canon eos r5': { width: 36.0, height: 24.0 },
      'canon eos r6': { width: 35.9, height: 23.9 },
      'canon eos 5d mark iv': { width: 36.0, height: 24.0 },
      'canon eos 90d': { width: 22.3, height: 14.8 },
      
      // Sony  
      'sony ilce-7rm5': { width: 35.7, height: 23.8 },
      'sony ilce-7rm4': { width: 35.7, height: 23.8 },
      'sony ilce-7m4': { width: 35.6, height: 23.8 },
      'sony ilce-a7riv': { width: 35.7, height: 23.8 }
    };
    
    const sensorInfo = sensoresRAW[modeloCompleto];
    if (sensorInfo) {
      sensorWidth = sensorInfo.width;
      sensorWidthInput.value = sensorWidth;
      sensorHeightInput.value = sensorInfo.height;
      sensorWidthInput.readOnly = true;
      sensorHeightInput.readOnly = true;
    } else {
      sensorWidth = parseFloat(sensorWidthInput.value);
      if (!sensorWidth) {
        scale = null;
        scaleDisplay.textContent = '-';
        UtilityHelpers.setStatus('Error: Dimensiones del sensor no encontradas para modelo RAW', true);
        return;
      }
    }
    
    // Cálculo híbrido con corrección de precisión RAW
    const escalaBase = (sensorWidth / imageWidth) * (distancia / focalRAW);
    
    // Factor de corrección basado en calidad RAW vs JPG
    const factorCorreccionRAW = 1.0; // Los metadatos RAW son más precisos
    scale = escalaBase * factorCorreccionRAW;
    
    scaleDisplay.textContent = scale.toFixed(6);
    
    // Información detallada del análisis híbrido
    const pixelsPorMM = 1 / scale;
    const campoVisionW = (imageWidth * scale).toFixed(1);
    const campoVisionH = (imageHeight * scale).toFixed(1);
    
    const mensaje = `HÍBRIDO: ${scale.toFixed(6)} mm/px | ${pixelsPorMM.toFixed(2)} px/mm | Campo: ${campoVisionW}×${campoVisionH}mm | RAW: f/${apertureRAW}`;
    UtilityHelpers.setStatus(mensaje, false);
    
    // Log detallado del análisis híbrido
    if (DEBUG_LOGS.detection) {
      console.log(`=== ANÁLISIS HÍBRIDO JPG+RAW ===
    • JPG: ${archivoJPGActual.name} (${imageWidth}×${imageHeight}px)
    • RAW: ${archivosComplementarios.raw.name} (${makeRAW} ${modelRAW})
    • Focal RAW: ${focalRAW}mm (f/${apertureRAW})
    • Sensor: ${sensorWidth}×${sensorHeightInput.value}mm
    • Distancia: ${distancia}mm
    • Escala híbrida: ${scale.toFixed(6)} mm/píxel
    • Ventaja: Metadatos RAW precisos + análisis visual JPG optimizado
    =====================================`);
    }
    
    // Si hay objetos detectados, actualizar automáticamente las mediciones
    if(objects.length > 0) {
      if (DEBUG_LOGS.measurements) {
        console.log('📐 Actualizando mediciones híbridas de objetos...');
      }
      setTimeout(() => {
        requestAnimationFrame(() => redraw());
        actualizarObjetosIndividuales();
      }, 50);
    }
  }

  function cargarMetadatos(file){
    // Detectar tipo de archivo para configuración optimizada
    const formatoRAW = detectarFormatoRAW(file);
    const esRAW = ['nef', 'cr2', 'cr3', 'arw', 'orf', 'raf', 'dng', 'rw2', 'pef', 'srw', '3fr', 'fff', 'erf', 'mef', 'mos', 'crw', 'x3f', 'rwl', 'iiq'].includes(formatoRAW);
    
    // Configuración mejorada para extraer TODOS los metadatos posibles
    const configuracion = {
      tiff: true, 
      ifd0: true, 
      ifd1: true,  // Agregar IFD1 para más metadatos
      exif: true, 
      gps: true,   // Habilitar GPS por si contiene info útil
      interop: true,  // Habilitar interoperabilidad
      thumbnail: false,
      translateKeys: true,
      translateValues: true,
      reviveValues: true,
      sanitize: false,  // Desactivar sanitización para obtener todos los campos
      mergeOutput: true, // Combinar todas las salidas para facilitar acceso
      pick: undefined    // No filtrar campos - obtener TODO
    };
    
    // Configuración específica adicional para archivos RAW
    if(esRAW) {
      configuracion.chunked = false;
      configuracion.firstChunkSize = 131072;  // 128KB primer chunk (más grande)
      configuracion.chunkSize = 65536;
      
      // Agregar campos específicos RAW
      configuracion.iptc = true;
      configuracion.icc = true;
      configuracion.jfif = false;
      configuracion.ihdr = false;
      configuracion.makerNote = true;  // Importante para datos específicos del fabricante
    }
    
    console.log('🔧 DEBUG - Iniciando extracción EXIFR mejorada:', {
      nombre: file.name,
      formato: formatoRAW,
      esRAW: esRAW,
      configuracion: configuracion
    });
    
    return exifr.parse(file, configuracion).then(data => {
      console.log('🔧 DEBUG - Resultado EXIFR completo:', {
        nombre: file.name,
        tieneData: !!data,
        totalCampos: data ? Object.keys(data).length : 0,
        camposPrincipales: data ? Object.keys(data).slice(0, 20) : []
      });
      
      if(data) {
        // Log detallado de campos críticos y alternativos
        console.log('📋 Campos EXIF extraídos:', {
          'Modelo': data.Model || data.CameraModelName || data.UniqueCameraModel || 'No encontrado',
          'Fabricante': data.Make || data.Manufacturer || 'No encontrado',
          'Focal': data.FocalLength || data.FocalLengthIn35mmFormat || 'No encontrado',
          'Apertura': data.FNumber || data.ApertureValue || data.MaxApertureValue || 'No encontrado',
          'Lente': data.LensModel || data.LensMake || 'No encontrado',
          'ISO': data.ISO || data.ISOSpeedRatings || 'No encontrado',
          'Dimensiones': `${data.ImageWidth || '?'}x${data.ImageHeight || '?'}`
        });
      }
      
      if(!data) {
        const tipoArchivo = esRAW ? formatoRAW.toUpperCase() : 'JPG';
        console.error('❌ EXIFR no pudo extraer metadatos de:', file.name);
        throw new Error(`Archivo ${tipoArchivo} sin metadatos EXIF válidos`);
      }
      
      // Verificar si al menos tenemos ALGÚN dato útil
      const tieneDatosMinimos = data.Model || data.Make || data.FocalLength || data.ImageWidth;
      
      if(!tieneDatosMinimos) {
        console.warn('⚠️ Archivo con metadatos vacíos o corruptos');
        throw new Error(`Metadatos ${esRAW ? formatoRAW.toUpperCase() : 'JPG'} vacíos o no legibles`);
      }
      
      console.log(`✅ Metadatos ${esRAW ? formatoRAW.toUpperCase() : 'JPG'} extraídos exitosamente:`, {
        fabricante: data.Make || 'N/A',
        modelo: data.Model || 'N/A',
        focalLength: data.FocalLength || 'N/A',
        fNumber: data.FNumber || 'N/A',
        dimensiones: {
          width: data.ImageWidth || 'N/A',
          height: data.ImageHeight || 'N/A'
        }
      });
      
      return data;
    }).catch(error => {
      console.error(`❌ Error al procesar ${esRAW ? formatoRAW.toUpperCase() : 'JPG'}:`, error);
      throw error;
    });
  }

  function procesarMetadatos(exifData, esArchivoRAW = false) {
    if(!exifData) {
      const tipoArchivo = esArchivoRAW ? 'RAW' : 'JPG';
      UtilityHelpers.setStatus(`Error: No se pudieron procesar los metadatos del archivo ${tipoArchivo}`, true);
      return false;
    }
    
    // DEBUG: Mostrar todos los campos disponibles en los metadatos
    console.log('🔍 DEBUG - Todos los campos EXIF disponibles:', Object.keys(exifData));
    console.log('🔍 DEBUG - Valores de campos críticos:', {
      Model: exifData.Model,
      Make: exifData.Make,
      FocalLength: exifData.FocalLength,
      FNumber: exifData.FNumber,
      ApertureValue: exifData.ApertureValue,
      LensModel: exifData.LensModel
    });
    
    let metadatosCompletos = true;
    let mensajesAdvertencia = [];
    let camposEncontrados = 0;
    
    // Procesar modelo de cámara con búsqueda mejorada
    let modeloDetectado = null;
    const campoModelo = exifData.Model || exifData.CameraModelName || exifData.UniqueCameraModel;
    const campoFabricante = exifData.Make || exifData.Manufacturer;
    
    if(campoModelo) {
      modeloDetectado = campoModelo.toUpperCase().trim();
      
      if(campoFabricante && !modeloDetectado.includes(campoFabricante.toUpperCase())) {
        modeloDetectado = `${campoFabricante.toUpperCase()} ${modeloDetectado}`;
      }
      
      cameraModelInput.value = modeloDetectado;
      camposEncontrados++;
      console.log(`✓ Modelo de cámara detectado: ${modeloDetectado}`);
      
      // Buscar dimensiones del sensor en la base de datos
      const sensorData = sensorSizes[modeloDetectado];
      if(sensorData) {
        sensorWidthInput.value = sensorData.width;
        sensorHeightInput.value = sensorData.height;
        console.log(`✓ Sensor reconocido automáticamente: ${modeloDetectado}`);
        UtilityHelpers.setStatus(`Sensor reconocido: ${sensorData.width}x${sensorData.height}mm`, false);
      } else {
        console.warn(`⚠ Modelo ${modeloDetectado} no encontrado en base de datos`);
        
        // Valores por defecto según fabricante
        const fabricante = campoFabricante ? campoFabricante.toUpperCase().trim() : '';
        if(fabricante.includes('NIKON')) {
          sensorWidthInput.value = 23.5;
          sensorHeightInput.value = 15.6;
        } else if(fabricante.includes('CANON')) {
          sensorWidthInput.value = 22.3;
          sensorHeightInput.value = 14.9;
        } else if(fabricante.includes('SONY')) {
          sensorWidthInput.value = 23.5;
          sensorHeightInput.value = 15.6;
        } else {
          sensorWidthInput.value = 23.5;
          sensorHeightInput.value = 15.6;
        }
        
        mensajesAdvertencia.push(`Usando sensor por defecto para ${fabricante || 'cámara desconocida'}: ${sensorWidthInput.value}x${sensorHeightInput.value}mm`);
        sensorWidthInput.readOnly = false;
        sensorHeightInput.readOnly = false;
      }
    } else {
      const tipoArchivo = esArchivoRAW ? 'RAW' : 'JPG';
      mensajesAdvertencia.push(`Modelo de cámara no detectado en metadatos ${tipoArchivo}`);
      console.warn('⚠️ Campos intentados para modelo:', {
        Model: exifData.Model,
        CameraModelName: exifData.CameraModelName,
        UniqueCameraModel: exifData.UniqueCameraModel
      });
      // NO marcar como incompleto para RAW - permitir continuar
    }
    
    // Procesar distancia focal con búsqueda mejorada
    const focalLength = exifData.FocalLength || exifData.FocalLengthIn35mmFormat || exifData.FocalLengthIn35mmFilm;
    if(focalLength && focalLength >= 4 && focalLength <= 1200) {
      focalInput.value = focalLength;
      camposEncontrados++;
      console.log(`✓ Distancia focal detectada: ${focalLength}mm`);
    } else {
      if(focalLength) {
        mensajesAdvertencia.push(`Distancia focal sospechosa: ${focalLength}mm - verifique manualmente`);
        focalInput.value = focalLength;
        camposEncontrados++;
      } else {
        const tipoArchivo = esArchivoRAW ? 'RAW' : 'JPG';
        mensajesAdvertencia.push(`Distancia focal no encontrada en metadatos ${tipoArchivo}`);
        console.warn('⚠️ Campos intentados para focal:', {
          FocalLength: exifData.FocalLength,
          FocalLengthIn35mmFormat: exifData.FocalLengthIn35mmFormat,
          FocalLengthIn35mmFilm: exifData.FocalLengthIn35mmFilm
        });
        // NO marcar como incompleto - permitir entrada manual
      }
    }
    
    // Procesar apertura con búsqueda mejorada
    const apertura = exifData.FNumber || exifData.ApertureValue || exifData.MaxApertureValue;
    const aperturaMaxima = exifData.MaxApertureValue;
    
    if(apertura && apertura >= 1.0 && apertura <= 32) {
      apertureInput.value = apertura;
      camposEncontrados++;
      console.log(`✓ Apertura detectada: f/${apertura}`);
      
      // Mostrar info de apertura máxima si es diferente
      const apertureMaxInfo = document.getElementById('apertureMaxInfo');
      if(apertureMaxInfo) {
        if(aperturaMaxima && aperturaMaxima !== apertura && aperturaMaxima < apertura) {
          apertureMaxInfo.textContent = `(máx. f/${aperturaMaxima})`;
          apertureMaxInfo.title = `La apertura máxima del lente es f/${aperturaMaxima}, pero se capturó a f/${apertura}`;
          console.log(`ℹ️ Lente con apertura máxima f/${aperturaMaxima}, capturada a f/${apertura}`);
        } else {
          apertureMaxInfo.textContent = '';
        }
      }
    } else {
      if(apertura) {
        mensajesAdvertencia.push(`Apertura sospechosa: f/${apertura} - verifique manualmente`);
        apertureInput.value = apertura;
        camposEncontrados++;
      } else {
        const tipoArchivo = esArchivoRAW ? 'RAW' : 'JPG';
        mensajesAdvertencia.push(`Apertura no encontrada en metadatos ${tipoArchivo}`);
        console.warn('⚠️ Campos intentados para apertura:', {
          FNumber: exifData.FNumber,
          ApertureValue: exifData.ApertureValue,
          MaxApertureValue: exifData.MaxApertureValue
        });
        // NO marcar como incompleto - no es crítico
      }
    }
    
    // Resumen de campos encontrados
    console.log(`📊 Resumen de metadatos: ${camposEncontrados}/3 campos críticos detectados`);
    
    // Considerar metadatos completos si tenemos al menos modelo y focal
    // La apertura es menos crítica y puede estar en otros campos
    metadatosCompletos = camposEncontrados >= 2;
    
    // Mostrar resultados
    if(mensajesAdvertencia.length > 0) {
      const mensaje = mensajesAdvertencia.join('; ');
      // Cambiar criterio: solo es error si no tenemos NADA
      const esErrorCritico = camposEncontrados === 0;
      
      if(esErrorCritico) {
        UtilityHelpers.setStatus(`Error: ${mensaje}. Complete los datos manualmente.`, true);
        // Hacer campos editables para entrada manual
        cameraModelInput.readOnly = false;
        focalInput.readOnly = false;
        apertureInput.readOnly = false;
        sensorWidthInput.readOnly = false;
        sensorHeightInput.readOnly = false;
      } else {
        UtilityHelpers.setStatus(`Advertencias: ${mensaje}`, false);
      }
    }
    
    // Mostrar mensaje informativo - escala ahora es completamente manual
    setTimeout(() => {
      if(metadatosCompletos || camposEncontrados > 0) {
        const tipoArchivo = esArchivoRAW ? 'RAW' : 'JPG';
        const estadoCampos = camposEncontrados === 3 ? 'completos' : `parciales (${camposEncontrados}/3)`;
        UtilityHelpers.setStatus(`Metadatos ${tipoArchivo} ${estadoCampos}. Ingrese la distancia y use "Calcular Escala".`, false);
      } else {
        UtilityHelpers.setStatus(`Complete los datos de cámara manualmente para calcular la escala.`, false);
      }
    }, 100);
    
    return metadatosCompletos;
  }

  // === SISTEMA OPTIMIZADO DE CARGA DE IMÁGENES ===
  
  /**
   * Sistema de caché para imágenes y procesamientos
   */
  class ImageCache {
    constructor() {
      this.cache = new Map();
      this.thumbnailCache = new Map();
      this.maxCacheSize = 100 * 1024 * 1024; // 100MB máximo
      this.currentCacheSize = 0;
    }
    
    generateKey(file) {
      return `${file.name}_${file.size}_${file.lastModified}`;
    }
    
    has(key) {
      return this.cache.has(key);
    }
    
    get(key) {
      const entry = this.cache.get(key);
      if (entry) {
        entry.lastUsed = Date.now();
        return entry.data;
      }
      return null;
    }
    
    set(key, data, size) {
      // Limpiar caché si es necesario
      while (this.currentCacheSize + size > this.maxCacheSize && this.cache.size > 0) {
        this.evictLeastUsed();
      }
      
      this.cache.set(key, {
        data: data,
        size: size,
        lastUsed: Date.now()
      });
      this.currentCacheSize += size;
    }
    
    evictLeastUsed() {
      let oldestKey = null;
      let oldestTime = Date.now();
      
      for (const [key, entry] of this.cache) {
        if (entry.lastUsed < oldestTime) {
          oldestTime = entry.lastUsed;
          oldestKey = key;
        }
      }
      
      if (oldestKey) {
        const entry = this.cache.get(oldestKey);
        this.currentCacheSize -= entry.size;
        this.cache.delete(oldestKey);
        console.log(`🗑️ Evicted from cache: ${oldestKey}`);
      }
    }
    
    clear() {
      this.cache.clear();
      this.thumbnailCache.forEach(entry => { if (entry.url) URL.revokeObjectURL(entry.url); });
      this.thumbnailCache.clear();
      this.currentCacheSize = 0;
      console.log('🧹 Image cache cleared');
    }
  }
  
  const imageCache = new ImageCache();
  
  /**
   * Validación rápida de archivo de imagen antes de carga completa (ACTUALIZADA PARA RAW)
   */
  async function validarArchivoImagen(file) {
    const validTypes = [
      'image/jpeg', 'image/jpg', 'image/png',
      'image/x-nikon-nef', 'image/x-canon-cr2', 'image/x-sony-arw', 'image/x-adobe-dng',
      'application/octet-stream' // Muchos RAW se detectan como binary
    ];
    
    const validExtensions = [
      'jpg', 'jpeg', 'png', 'nef', 'cr2', 'cr3', 'arw', 'orf', 'raf', 'dng', 
      'rw2', 'pef', 'srw', '3fr', 'fff', 'erf', 'mef', 'mos', 'crw', 'x3f', 'rwl', 'iiq'
    ];
    
    const maxSize = 500 * 1024 * 1024; // 500MB máximo
    
    // Obtener extensión del archivo
    const extension = file.name.split('.').pop().toLowerCase();
    
    // DEBUG: Log de validación
    console.log('🔧 DEBUG - validarArchivoImagen:', {
      nombre: file.name,
      extension: extension,
      mimeType: file.type,
      size: file.size,
      esExtensionValida: validExtensions.includes(extension),
      esMimeTypeValido: validTypes.includes(file.type)
    });
    
    // Validar tipo MIME o extensión
    const isValidType = validTypes.includes(file.type) || validExtensions.includes(extension);
    if (!isValidType) {
      console.error('❌ Formato no soportado:', { type: file.type, extension: extension });
      throw new Error(`Formato no soportado: ${file.type || extension}. Formatos soportados: ${validExtensions.join(', ')}`);
    }
    
    // Validar tamaño
    if (file.size > maxSize) {
      throw new Error(`Archivo demasiado grande: ${(file.size / 1024 / 1024).toFixed(1)}MB > 500MB`);
    }
    
    // Leer primeros bytes para validar formato
    const headerBytes = await UtilityHelpers.readFileHeader(file, 16);
    
    // DEBUG: Log del header
    console.log('🔧 DEBUG - Header bytes:', {
      nombre: file.name,
      headerHex: Array.from(headerBytes).map(b => '0x' + b.toString(16).padStart(2, '0')).join(' '),
      headerString: Array.from(headerBytes).map(b => String.fromCharCode(b)).join('').replace(/[^\x20-\x7E]/g, '.')
    });
    
    const isValidImage = UtilityHelpers.validateImageHeader(headerBytes, file.type, file.name);
    
    console.log('🔧 DEBUG - Validación header:', {
      nombre: file.name,
      mimeType: file.type,
      esHeaderValido: isValidImage
    });
    
    if (!isValidImage) {
      console.error('❌ Header inválido para archivo:', file.name);
      throw new Error('Archivo corrupto o no es una imagen válida');
    }
    
    return true;
  }
  
  /**
   * Lee los primeros bytes del archivo para validación
   */
  function readFileHeader(file, bytesToRead) {
    return new Promise((resolve, reject) => {
      const slice = file.slice(0, bytesToRead);
      const reader = new FileReader();
      
      reader.onload = () => {
        const buffer = reader.result;
        resolve(new Uint8Array(buffer));
      };
      
      reader.onerror = reject;
      reader.readAsArrayBuffer(slice);
    });
  }
  
  /**
   * Valida el header de la imagen incluyendo formatos RAW
   */
  function validateImageHeader(bytes, mimeType, fileName = '') {
    const view = new DataView(bytes.buffer);
    const extension = fileName ? fileName.split('.').pop().toLowerCase() : '';
    
    switch (mimeType) {
      case 'image/jpeg':
      case 'image/jpg':
        // JPEG: FF D8 FF
        return bytes[0] === 0xFF && bytes[1] === 0xD8 && bytes[2] === 0xFF;
      
      case 'image/png':
        // PNG: 89 50 4E 47 0D 0A 1A 0A
        return bytes[0] === 0x89 && bytes[1] === 0x50 && 
               bytes[2] === 0x4E && bytes[3] === 0x47;
      
      case 'image/x-canon-cr2':
        // Validación específica para CR2
        return validateRAWHeader(bytes, mimeType, extension);
      
      case 'application/octet-stream':
        // Muchos archivos RAW se detectan como octet-stream
        // Usar extensión para determinar el formato
        if (extension === 'cr2') {
          return validateRAWHeader(bytes, 'image/x-canon-cr2', extension);
        }
        return validateRAWHeader(bytes, 'generic-raw', extension);
      
      default:
        // Para archivos RAW, validar por extensión y patrones de header
        return validateRAWHeader(bytes, mimeType, extension);
    }
  }
  
  /**
   * Validación específica para formatos RAW
   */
  function validateRAWHeader(bytes, mimeType, extension = '') {
    // Si no hay suficientes bytes, aceptar (se validará después)
    if (bytes.length < 16) return true;
    
    console.log('🔧 DEBUG - validateRAWHeader:', {
      mimeType: mimeType,
      extension: extension,
      bytesLength: bytes.length,
      firstBytes: Array.from(bytes.slice(0, 8)).map(b => '0x' + b.toString(16).padStart(2, '0')).join(' ')
    });
    
    const view = new DataView(bytes.buffer);
    
    // NEF (Nikon): Comienza con "II*" o "MM*"
    if (mimeType === 'image/x-nikon-nef' || checkBytePattern(bytes, 'nef')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) || // Little endian TIFF
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00); // Big endian TIFF
    }
    
    // CR2 (Canon): Validación más permisiva para compatibilidad
    if (mimeType === 'image/x-canon-cr2' || extension === 'cr2' || checkBytePattern(bytes, 'cr2')) {
      console.log('🔧 DEBUG - Validando CR2:', {
        mimeType: mimeType,
        extension: extension,
        firstBytes: Array.from(bytes.slice(0, 12)).map(b => '0x' + b.toString(16).padStart(2, '0')).join(' ')
      });
      
      // Verificar que sea un TIFF (la mayoría de archivos CR2 son TIFF-based)
      const isTIFF = (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) || // Little endian TIFF "II*"
                     (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00); // Big endian TIFF "MM*"
      
      // Si es TIFF, aceptar (validación más permisiva)
      if (isTIFF) {
        console.log('✅ CR2 validado como TIFF');
        return true;
      }
      
      // Verificación adicional: buscar signatura "CR" en los primeros 16 bytes
      for (let i = 0; i < bytes.length - 1; i++) {
        if (bytes[i] === 0x43 && bytes[i + 1] === 0x52) { // "CR"
          console.log('✅ CR2 validado por signatura CR');
          return true;
        }
      }
      
      // Si la extensión es .cr2, aceptar de todos modos (validación muy permisiva)
      if (extension === 'cr2' || mimeType === 'image/x-canon-cr2') {
        console.log('✅ CR2 validado por extensión/mimeType');
        return true;
      }
      
      console.log('❌ CR2 no pudo ser validado');
      return false;
    }
    
    // CR3 (Canon nuevo): Comienza con ftyp + crx
    if (checkBytePattern(bytes, 'cr3')) {
      return bytes[4] === 0x66 && bytes[5] === 0x74 && bytes[6] === 0x79 && bytes[7] === 0x70 && // "ftyp"
             bytes[8] === 0x63 && bytes[9] === 0x72 && bytes[10] === 0x78; // "crx"
    }
    
    // ARW (Sony): Similar a TIFF con marca específica
    if (mimeType === 'image/x-sony-arw' || checkBytePattern(bytes, 'arw')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) || // Little endian TIFF
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00); // Big endian TIFF
    }
    
    // DNG (Adobe): TIFF-based con magic number específico
    if (mimeType === 'image/x-adobe-dng' || checkBytePattern(bytes, 'dng')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) || 
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00);
    }
    
    // ORF (Olympus): TIFF-based
    if (checkBytePattern(bytes, 'orf')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) ||
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00);
    }
    
    // RAF (Fujifilm): Comienza con "FUJIFILM"
    if (checkBytePattern(bytes, 'raf')) {
      const fujiSignature = [0x46, 0x55, 0x4A, 0x49, 0x46, 0x49, 0x4C, 0x4D]; // "FUJIFILM"
      return fujiSignature.every((byte, index) => bytes[index] === byte);
    }
    
    // RW2 (Panasonic): TIFF-based
    if (checkBytePattern(bytes, 'rw2')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) ||
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00);
    }
    
    // PEF (Pentax): TIFF-based
    if (checkBytePattern(bytes, 'pef')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) ||
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00);
    }
    
    // SRW (Samsung): TIFF-based
    if (checkBytePattern(bytes, 'srw')) {
      return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) ||
             (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00);
    }
    
    // Para otros formatos, aceptar si parece TIFF (muchos RAW son TIFF-based)
    return (bytes[0] === 0x49 && bytes[1] === 0x49 && bytes[2] === 0x2A) ||
           (bytes[0] === 0x4D && bytes[1] === 0x4D && bytes[2] === 0x00) ||
           true; // Fallback: aceptar para validación posterior
  }
  
  /**
   * Helper para verificar patrones de bytes basado en extensión
   */
  function checkBytePattern(bytes, expectedFormat) {
    // Esta función puede expandirse para verificaciones más específicas
    // Por ahora, acepta todos los formatos conocidos
    const rawFormats = ['nef', 'cr2', 'cr3', 'arw', 'orf', 'raf', 'dng', 'rw2', 'pef', 'srw', 
                       '3fr', 'fff', 'erf', 'mef', 'mos', 'crw', 'x3f', 'rwl', 'iiq'];
    return rawFormats.includes(expectedFormat.toLowerCase());
  }
  
  /**
   * Crea un thumbnail rápido para vista previa
   */
  async function crearThumbnail(file, maxDimension = 300) {
    const cacheKey = `thumb_${imageCache.generateKey(file)}_${maxDimension}`;
    
    // Verificar caché
    if (imageCache.thumbnailCache.has(cacheKey)) {
      return imageCache.thumbnailCache.get(cacheKey);
    }
    
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      
      reader.onload = (e) => {
        const img = new Image();
        
        img.onload = () => {
          // Calcular dimensiones del thumbnail
          const { width, height } = calcularDimensionesThumbnail(
            img.naturalWidth, img.naturalHeight, maxDimension
          );
          
          // Crear canvas para thumbnail
          const canvas = document.createElement('canvas');
          const ctx = canvas.getContext('2d');
          canvas.width = width;
          canvas.height = height;
          
          // Renderizar thumbnail con alta calidad
          ctx.imageSmoothingEnabled = true;
          ctx.imageSmoothingQuality = 'high';
          ctx.drawImage(img, 0, 0, width, height);
          
          // Convertir a blob comprimido
          canvas.toBlob((blob) => {
            const thumbnailUrl = URL.createObjectURL(blob);
            
            // Guardar en caché
            imageCache.thumbnailCache.set(cacheKey, {
              url: thumbnailUrl,
              width: width,
              height: height,
              originalWidth: img.naturalWidth,
              originalHeight: img.naturalHeight
            });
            
            resolve(imageCache.thumbnailCache.get(cacheKey));
          }, 'image/jpeg', 0.8);
        };
        
        img.onerror = reject;
        img.src = e.target.result;
      };
      
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  }
  
  /**
   * Calcula dimensiones optimales para thumbnail
   */
  function calcularDimensionesThumbnail(originalWidth, originalHeight, maxDimension) {
    const aspectRatio = originalWidth / originalHeight;
    
    let width, height;
    
    if (originalWidth > originalHeight) {
      width = Math.min(maxDimension, originalWidth);
      height = width / aspectRatio;
    } else {
      height = Math.min(maxDimension, originalHeight);
      width = height * aspectRatio;
    }
    
    return {
      width: Math.round(width),
      height: Math.round(height)
    };
  }
  
  /**
   * Función principal optimizada para cargar imágenes
   */
  async function cargarImagen(file, options = {}) {
    const {
      createThumbnail = true,
      maxDimension = null,
      compressionQuality = 0.95,
      useCache = true,
      progressCallback = null
    } = options;
    
    // PASO 1: Limpiar caché anterior al cargar nueva imagen
    UtilityHelpers.clearContourCache();
    
    if (progressCallback) progressCallback(10, 'Validando archivo...');
    
    // PASO 2: Validación rápida
    await validarArchivoImagen(file);
    
    if (progressCallback) progressCallback(20, 'Verificando caché...');
    
    // PASO 3: Verificar caché
    const cacheKey = imageCache.generateKey(file);
    if (useCache && imageCache.has(cacheKey)) {
      console.log('✅ Imagen cargada desde caché:', file.name);
      if (progressCallback) progressCallback(100, 'Cargado desde caché');
      return imageCache.get(cacheKey);
    }
    
    if (progressCallback) progressCallback(30, 'Creando vista previa...');
    
    // PASO 4: Crear thumbnail primero para vista previa rápida
    if (createThumbnail) {
      try {
        const thumbnail = await crearThumbnail(file);
        console.log(`📸 Thumbnail creado: ${thumbnail.width}x${thumbnail.height}`);
        
        // Mostrar thumbnail inmediatamente si es muy pequeño
        if (thumbnail.originalWidth < 2000 && thumbnail.originalHeight < 2000) {
          if (progressCallback) progressCallback(60, 'Optimizando imagen pequeña...');
        }
      } catch (error) {
        console.warn('⚠️ Error creando thumbnail:', error);
      }
    }
    
    if (progressCallback) progressCallback(50, 'Cargando imagen completa...');
    
    // PASO 5: Cargar imagen completa
    const img = await new Promise((resolve, reject) => {
      const reader = new FileReader();
      
      reader.onload = (e) => {
        const image = new Image();
        
        image.onload = () => {
          if (progressCallback) progressCallback(80, 'Procesando imagen...');
          
          // Optimizar imagen si es muy grande
          if (maxDimension && (image.naturalWidth > maxDimension || image.naturalHeight > maxDimension)) {
            optimizarImagenGrande(image, maxDimension, compressionQuality)
              .then(optimizedImg => {
                console.log(`🔧 Imagen optimizada: ${image.naturalWidth}x${image.naturalHeight} → ${optimizedImg.naturalWidth}x${optimizedImg.naturalHeight}`);
                resolve(optimizedImg);
              })
              .catch(() => resolve(image)); // Fallback a imagen original
          } else {
            resolve(image);
          }
        };
        
        image.onerror = reject;
        image.src = e.target.result;
      };
      
      reader.onerror = reject;
      reader.onprogress = (e) => {
        if (e.lengthComputable && progressCallback) {
          const fileProgress = (e.loaded / e.total) * 30 + 50; // 50-80%
          progressCallback(fileProgress, `Leyendo archivo... ${(e.loaded / 1024 / 1024).toFixed(1)}MB`);
        }
      };
      
      reader.readAsDataURL(file);
    });
    
    if (progressCallback) progressCallback(90, 'Guardando en caché...');
    
    // PASO 6: Guardar en caché
    if (useCache) {
      const estimatedSize = img.naturalWidth * img.naturalHeight * 4; // Aproximado RGBA
      imageCache.set(cacheKey, img, estimatedSize);
      console.log(`💾 Imagen guardada en caché: ${file.name} (${(estimatedSize / 1024 / 1024).toFixed(1)}MB)`);
    }
    
    if (progressCallback) progressCallback(100, 'Carga completada');
    
    return img;
  }
  
  /**
   * Optimiza imágenes grandes redimensionándolas
   */
  async function optimizarImagenGrande(sourceImage, maxDimension, quality = 0.95) {
    return new Promise((resolve) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      
      // Calcular nuevas dimensiones
      const { width, height } = calcularDimensionesThumbnail(
        sourceImage.naturalWidth, 
        sourceImage.naturalHeight, 
        maxDimension
      );
      
      canvas.width = width;
      canvas.height = height;
      
      // Renderizar con alta calidad
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(sourceImage, 0, 0, width, height);
      
      // Convertir de vuelta a imagen
      canvas.toBlob((blob) => {
        const optimizedImg = new Image();
        optimizedImg.onload = () => {
          URL.revokeObjectURL(optimizedImg.src); // Limpiar blob URL
          resolve(optimizedImg);
        };
        optimizedImg.src = URL.createObjectURL(blob);
      }, 'image/jpeg', quality);
    });
  }
  
  function resetView() {
    zoom = 0.5;
    offsetX = 0;
    offsetY = 0;
    updateZoomDisplay();
  }

  function setZoomFromPercent(percent) {
    const newZoom = Math.max(0.1, Math.min(5.0, percent / 100));
    zoom = newZoom;
    updateZoomDisplay();
    requestAnimationFrame(() => redraw());
  }


  function updateZoomDisplay() {
    const zoomPercent = (zoom*100).toFixed(0);
    zoomLevelDisplay.textContent = `${zoomPercent}%`;
    zoomInput.value = zoomPercent;
  }

  let redrawTimeout;
  function debouncedRedraw() {
    clearTimeout(redrawTimeout);
    redrawTimeout = setTimeout(() => {
      requestAnimationFrame(() => redraw());
    }, 8);
  }

  // Alias para redrawCanvas usado en las funciones de selección manual
  function redrawCanvas() {
    redraw();
  }

  // Manejo de zoom, pan y selección manual
  canvas.addEventListener('mousedown', e => {
    const rect = canvas.getBoundingClientRect();
    const mouseX = e.offsetX;
    const mouseY = e.offsetY;
    
    if (modoVerificacionEscala) {
      // Modo verificación de escala: permitir pan con Shift+drag, clicks normales para marcar puntos
      if (e.shiftKey && puntosVerificacion.length < 2) {
        // Pan temporal con Shift presionado
        isPanning = true;
        startPan = { x: mouseX, y: mouseY };
        canvas.style.cursor = 'grabbing';
      }
      // Los clicks sin Shift se manejan en mouseup para marcar puntos
      return;
    } else if (geometrySelectionActive) {
      // Modo selección de objeto para Geometría Manual
      seleccionarObjetoGeometriaManual(mouseX, mouseY);
    } else if (isPerforationDetectionMode) {
      // Modo detección de perforaciones - trazado de polígono por clics
      // No hacer nada en mousedown, se maneja en click
    } else if (isManualSelectionMode) {
      // Modo selección manual: iniciar selección de área
      iniciarSeleccionArea(mouseX, mouseY);
    } else {
      // Modo normal: pan
      isPanning = true;
      startPan = { x: mouseX, y: mouseY };
      canvas.style.cursor = 'grabbing';
    }
  });
  
  let panTimeout;
  canvas.addEventListener('mousemove', e => {
    const mouseX = e.offsetX;
    const mouseY = e.offsetY;
    
    if (isPerforationDetectionMode && isDrawingPerforationPolygon) {
      // Mostrar línea temporal desde último punto hasta cursor
      UtilityHelpers.redrawCanvas();
    } else if (isManualSelectionMode && isSelectingArea) {
      // Modo selección manual: actualizar área de selección
      actualizarSeleccionArea(mouseX, mouseY);
    } else if (isPanning) {
      // Modo normal: pan
      offsetX += (mouseX - startPan.x) / zoom;
      offsetY += (mouseY - startPan.y) / zoom;
      startPan = { x: mouseX, y: mouseY };
      
      clearTimeout(panTimeout);
      panTimeout = setTimeout(() => {
        debouncedRedraw();
      }, 8);
    }
  });
  
  // =====================================================================================
  // LISTENERS ANTIGUOS DESACTIVADOS - EL TRAZADO AHORA SE HACE EN perforationCanvas MODAL
  // =====================================================================================
  // Event listener para clics (trazado de polígono) - DESACTIVADO
  // canvas.addEventListener('click', e => {
  //   if (isPerforationDetectionMode) {
  //     const mouseX = e.offsetX;
  //     const mouseY = e.offsetY;
  //     iniciarTrazadoPoligonoPerforacion(mouseX, mouseY);
  //   }
  // });
  
  // Event listener para doble clic (cerrar polígono) - DESACTIVADO
  // canvas.addEventListener('dblclick', e => {
  //   if (isPerforationDetectionMode && isDrawingPerforationPolygon) {
  //     e.preventDefault();
  //     cerrarPoligonoPerforacion();
  //   }
  // });
  
  canvas.addEventListener('mouseup', e => {
    const mouseX = e.offsetX;
    const mouseY = e.offsetY;
    
    // MODO VERIFICACIÓN DE ESCALA: Registrar puntos para medir distancia
    if (modoVerificacionEscala) {
      // Si estábamos haciendo pan (Shift+drag), solo restaurar cursor
      if (isPanning) {
        isPanning = false;
        canvas.style.cursor = 'crosshair';
        return;
      }
      
      // Si no hay Shift presionado y aún faltan puntos, marcar punto
      if (!e.shiftKey && puntosVerificacion.length < 2) {
        // Convertir coordenadas del canvas a coordenadas de la imagen considerando zoom y offset
        const imgX = (mouseX / zoom) - offsetX;
        const imgY = (mouseY / zoom) - offsetY;
        
        procesarClickVerificacion(imgX, imgY);
      }
      return;
    }
    
    if (isComponentSelectionMode && detectedComponents) {
      // MODO SELECCIÓN DE COMPONENTE: Usuario hizo clic para seleccionar un objeto
      manejarSeleccionComponente(mouseX, mouseY);
    } else if (isManualSelectionMode && isSelectingArea) {
      // Finalizar selección de área
      finalizarSeleccionArea();
    } else {
      // Finalizar pan
      isPanning = false;
      canvas.style.cursor = isManualSelectionMode ? 'crosshair' : 'grab';
    }
  });
  
  canvas.addEventListener('mouseleave', e => {
    if (isSelectingArea) {
      // Cancelar selección si el mouse sale del canvas
      isSelectingArea = false;
      UtilityHelpers.redrawCanvas();
    }
    isPanning = false;
    canvas.style.cursor = isManualSelectionMode ? 'crosshair' : 'grab';
  });
  
