          const mn = metricas[`${k}_rango_min`];
          const mx = metricas[`${k}_rango_max`];
          if (v !== undefined && e !== undefined)
            opticaRows.push(`Incertidumbre_Propagada,${k},${v},${u},"±${e} ${u} | rango [${mn} – ${mx}] ${u}"`);
