        curvaturaMedia: ['curvaturaMedia', 'curvatura_media'],
        curvaturaAlta: ['curvaturaAlta', 'curvatura_alta'],
        presionFlake: ['presionFlake'],
        direccionGolpe: ['direccionGolpe'],
