  /**
   * 📄 Generar y descargar archivo CSV (SIN DEPENDENCIAS)
   * Ventajas: No requiere bibliotecas externas, Excel lo abre perfectamente
   */
  async function generarArchivoCSV() {
    try {
      console.log('📄 Iniciando generación de archivo CSV...');
      
      // Mostrar mensaje de inicio
      toast.show('Generando archivo CSV...', 'info', 2000);
      
      // 1. Recolectar datos
      const datos = recolectarDatosParaExportacion();
      
      if (datos.error) {
        toast.show(datos.mensaje, 'error');
        return;
      }
      
      // 2. Formatear para Excel (reutilizamos la misma función)
      const workbook = formatearParaExcel(datos);
      
      // 3. Convertir cada hoja a CSV
      let csvContent = '';
      
      workbook.hojas.forEach((hoja, index) => {
        // Separador visual entre hojas
        if (index > 0) {
          csvContent += '\n\n';
        }
        
        // Nombre de la hoja como encabezado
        csvContent += `"=== ${hoja.nombre} ==="\n\n`;
        
        // Convertir filas a CSV
        hoja.datos.forEach(row => {
          const csvRow = row.map(cell => {
            // Escapar comillas y valores con comas
            const cellStr = String(cell ?? '');
            if (cellStr.includes(',') || cellStr.includes('"') || cellStr.includes('\n')) {
              return `"${cellStr.replace(/"/g, '""')}"`;
            }
            return cellStr;
          }).join(',');
          
          csvContent += csvRow + '\n';
        });
      });
      
      // 4. Crear Blob y descargar
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const nombreArchivo = `${datos.sesion.id}_analisis.csv`;
      
      // Crear enlace de descarga
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = nombreArchivo;
      link.style.display = 'none';
      
      // Agregar al DOM, hacer click y remover
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      
      // Limpiar URL del blob
      setTimeout(() => URL.revokeObjectURL(link.href), 100);
      
      console.log(`✅ Archivo CSV generado: ${nombreArchivo}`);
      toast.show(`CSV descargado: ${nombreArchivo}\n(Abre con Excel, Google Sheets o Numbers)`, 'success', 5000);
      
    } catch (error) {
      console.error('❌ Error al generar CSV:', error);
      toast.show(`Error: ${error.message}`, 'error');
    }
  }
  
