  // ============================================================================
  // FUNCIONES DE VISUALIZACIÓN BIFACIAL
  // ============================================================================
  
  /**
   * Dibujar imagen en canvas de una cara específica (modo bifacial)
   * @param {string} cara - 'A' o 'B'
   */
  function redrawCanvasBifacial(cara) {
    const canvasElement = document.getElementById(`canvasCara${cara}`);
    const statusElement = document.getElementById(`statusCanvas${cara}`);
    const dimElement = document.getElementById(`dimCara${cara}`);
    
    if (!canvasElement) {
      console.error(`❌ Canvas para Cara ${cara} no encontrado`);
      return;
    }
    
    const ctx = canvasElement.getContext('2d');
    const imagen = cara === 'A' ? imageCaraA : imageCaraB;
    const imgWidth = cara === 'A' ? imageWidthCaraA : imageWidthCaraB;
    const imgHeight = cara === 'A' ? imageHeightCaraA : imageHeightCaraB;
    
    // Limpiar canvas
    ctx.clearRect(0, 0, canvasElement.width, canvasElement.height);
    
    if (!imagen) {
      // Sin imagen
      if (statusElement) statusElement.textContent = 'Sin imagen';
      if (dimElement) dimElement.textContent = '-';
      
      // Dibujar placeholder
      ctx.fillStyle = '#f8f9fa';
      ctx.fillRect(0, 0, canvasElement.width, canvasElement.height);
      ctx.strokeStyle = '#dee2e6';
      ctx.lineWidth = 2;
      ctx.strokeRect(0, 0, canvasElement.width, canvasElement.height);
      
      ctx.fillStyle = '#6c757d';
      ctx.font = '14px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(`Cara ${cara} - Sin imagen cargada`, canvasElement.width / 2, canvasElement.height / 2);
      
      return;
    }
    
    // Calcular escala para ajustar al canvas manteniendo proporción, aplicando zoom
    const zoomFactor = cara === 'A' ? zoomFactorCaraA : zoomFactorCaraB;
    const scaleX = canvasElement.width / imgWidth;
    const scaleY = canvasElement.height / imgHeight;
    const scale = Math.min(scaleX, scaleY) * zoomFactor;
    
    const scaledWidth = imgWidth * scale;
    const scaledHeight = imgHeight * scale;
    const offsetX = (canvasElement.width - scaledWidth) / 2;
    const offsetY = (canvasElement.height - scaledHeight) / 2;
    
    // Dibujar imagen centrada
    ctx.drawImage(imagen, offsetX, offsetY, scaledWidth, scaledHeight);
    
    // 🆕 Dibujar área de selección si está activa para esta cara
    if (isManualSelectionMode && window.deteccionBifacialActiva && window.deteccionBifacialActiva.cara === cara) {
      dibujarAreaSeleccionBifacial(ctx, cara, scale, offsetX, offsetY);
    }
    
    // Actualizar status e información
    if (statusElement) {
      statusElement.innerHTML = `<span style="color: #28a745;">Cargada</span>`;
    }
    if (dimElement) {
      dimElement.textContent = `${imgWidth} × ${imgHeight} px`;
    }
    
    console.log(`✅ Canvas Cara ${cara} dibujado:`, {
      imagenOriginal: `${imgWidth}×${imgHeight}`,
      canvasSize: `${canvasElement.width}×${canvasElement.height}`,
      escala: scale.toFixed(3),
      posición: `(${offsetX.toFixed(1)}, ${offsetY.toFixed(1)})`,
      seleccionActiva: isSelectingArea
    });
  }
  
  /**
   * 🆕 Dibujar área de selección en canvas bifacial
   * @param {CanvasRenderingContext2D} ctx - Contexto del canvas
   * @param {string} cara - 'A' o 'B'
   * @param {number} scale - Escala de la imagen en el canvas
   * @param {number} offsetX - Desplazamiento horizontal de la imagen
   * @param {number} offsetY - Desplazamiento vertical de la imagen
   */
  function dibujarAreaSeleccionBifacial(ctx, cara, scale, offsetX, offsetY) {
    if (!isSelectingArea && !manualSelectedArea) return;
    
    let area;
    if (isSelectingArea) {
      // Área en proceso de selección - convertir coordenadas de imagen a canvas
      const canvasStartX = selectionStartX * scale + offsetX;
      const canvasStartY = selectionStartY * scale + offsetY;
      const canvasEndX = selectionEndX * scale + offsetX;
      const canvasEndY = selectionEndY * scale + offsetY;
      
      area = {
        x: Math.min(canvasStartX, canvasEndX),
        y: Math.min(canvasStartY, canvasEndY),
        width: Math.abs(canvasEndX - canvasStartX),
        height: Math.abs(canvasEndY - canvasStartY)
      };
      
      console.log(`🎨 Dibujando selección activa en Cara ${cara}:`, {
        imagenCoords: `(${selectionStartX}, ${selectionStartY}) → (${selectionEndX}, ${selectionEndY})`,
        canvasCoords: `(${area.x.toFixed(1)}, ${area.y.toFixed(1)}) ${area.width.toFixed(1)}×${area.height.toFixed(1)}`,
        scale: scale.toFixed(3)
      });
    } else if (manualSelectedArea) {
      // Área ya seleccionada - convertir a coordenadas canvas
      const canvasStartX = manualSelectedArea.x * scale + offsetX;
      const canvasStartY = manualSelectedArea.y * scale + offsetY;
      const canvasWidth = manualSelectedArea.width * scale;
      const canvasHeight = manualSelectedArea.height * scale;
      
      area = {
        x: canvasStartX,
        y: canvasStartY,
        width: canvasWidth,
        height: canvasHeight
      };
    }
    
    if (area && area.width > 0 && area.height > 0) {
      // Determinar color según la cara
      const colorCara = cara === 'A' ? '#17a2b8' : '#28a745'; // Azul para A, Verde para B
      const colorRGB = cara === 'A' ? '23, 162, 184' : '40, 167, 69';
      
      // Guardar estado del contexto
      ctx.save();
      
      // Dibujar borde del área de selección
      ctx.strokeStyle = colorCara;
      ctx.lineWidth = 3; // Borde más grueso para mejor visibilidad
      ctx.setLineDash([8, 4]); // Línea discontinua más visible
      ctx.strokeRect(area.x, area.y, area.width, area.height);
      
      // Dibujar relleno semi-transparente
      ctx.fillStyle = `rgba(${colorRGB}, 0.15)`; // Más opaco para mejor visibilidad
      ctx.fillRect(area.x, area.y, area.width, area.height);
      
      // Dibujar esquinas para mejor referencia visual
      ctx.setLineDash([]); // Línea sólida para esquinas
      const cornerSize = 12;
      ctx.lineWidth = 3;
      
      // Esquina superior izquierda
      ctx.beginPath();
      ctx.moveTo(area.x, area.y + cornerSize);
      ctx.lineTo(area.x, area.y);
      ctx.lineTo(area.x + cornerSize, area.y);
      ctx.stroke();
      
      // Esquina superior derecha
      ctx.beginPath();
      ctx.moveTo(area.x + area.width - cornerSize, area.y);
      ctx.lineTo(area.x + area.width, area.y);
      ctx.lineTo(area.x + area.width, area.y + cornerSize);
      ctx.stroke();
      
      // Esquina inferior izquierda
      ctx.beginPath();
      ctx.moveTo(area.x, area.y + area.height - cornerSize);
      ctx.lineTo(area.x, area.y + area.height);
      ctx.lineTo(area.x + cornerSize, area.y + area.height);
      ctx.stroke();
      
      // Esquina inferior derecha
      ctx.beginPath();
      ctx.moveTo(area.x + area.width - cornerSize, area.y + area.height);
      ctx.lineTo(area.x + area.width, area.y + area.height);
      ctx.lineTo(area.x + area.width, area.y + area.height - cornerSize);
      ctx.stroke();
      
      // Dibujar etiqueta con dimensiones
      if (isSelectingArea) {
        const labelText = `${Math.round(area.width / scale)} × ${Math.round(area.height / scale)} px`;
        const labelPadding = 6;
        const fontSize = 12;
        
        ctx.font = `bold ${fontSize}px Arial`;
        const textWidth = ctx.measureText(labelText).width;
        
        // Posicionar etiqueta arriba del área
        const labelX = area.x + area.width / 2 - (textWidth + labelPadding * 2) / 2;
        const labelY = area.y - 8;
        
        // Fondo de la etiqueta
        ctx.fillStyle = colorCara;
        ctx.fillRect(labelX, labelY - fontSize - labelPadding, textWidth + labelPadding * 2, fontSize + labelPadding * 2);
        
        // Texto de la etiqueta
        ctx.fillStyle = 'white';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';
        ctx.fillText(labelText, labelX + labelPadding, labelY - fontSize - labelPadding / 2);
      }
      
      // Restaurar estado del contexto
      ctx.restore();
      
      console.log(`✅ Área de selección dibujada en Cara ${cara}`);
    }
  }
  
  /**
   * Redibujar ambos canvas bifaciales
   */
  function redrawBifacial() {
    console.log('🎨 Redibujando canvas bifaciales...');
    redrawCanvasBifacial('A');
    redrawCanvasBifacial('B');
  }
  
  /**
   * 🆕 Obtener parámetros de escalado y offset para canvas bifacial
   * Esta función calcula cómo se dibuja la imagen en el canvas (centrada y escalada)
   */
  function obtenerParametrosCanvasBifacial(cara) {
    const canvasElement = document.getElementById(`canvasCara${cara}`);
    const imgWidth = cara === 'A' ? imageWidthCaraA : imageWidthCaraB;
    const imgHeight = cara === 'A' ? imageHeightCaraA : imageHeightCaraB;
    
    if (!canvasElement || !imgWidth || !imgHeight) {
      return null;
    }
    
    // Calcular escala para ajustar al canvas manteniendo proporción
    const scaleX = canvasElement.width / imgWidth;
    const scaleY = canvasElement.height / imgHeight;
    const scale = Math.min(scaleX, scaleY);
    
    const scaledWidth = imgWidth * scale;
    const scaledHeight = imgHeight * scale;
    const offsetX = (canvasElement.width - scaledWidth) / 2;
    const offsetY = (canvasElement.height - scaledHeight) / 2;
    
    return {
      canvasElement,
      imgWidth,
      imgHeight,
      scale,
      scaledWidth,
      scaledHeight,
      offsetX,
      offsetY
    };
  }
  
  /**
   * 🆕 Convertir coordenadas de canvas a coordenadas de imagen (bifacial)
   */
  function canvasToImageCoordsBifacial(canvasX, canvasY, cara) {
    const params = obtenerParametrosCanvasBifacial(cara);
    if (!params) return { x: 0, y: 0 };
    
    // Restar el offset y dividir por la escala
    const imgX = (canvasX - params.offsetX) / params.scale;
    const imgY = (canvasY - params.offsetY) / params.scale;
    
    // Asegurar que esté dentro de los límites de la imagen
    return {
      x: Math.max(0, Math.min(params.imgWidth, imgX)),
      y: Math.max(0, Math.min(params.imgHeight, imgY))
    };
  }
  
  /**
   * 🆕 Convertir coordenadas de imagen a coordenadas de canvas (bifacial)
   */
  function imageToCanvasCoordsBifacial(imgX, imgY, cara) {
    const params = obtenerParametrosCanvasBifacial(cara);
    if (!params) return { x: 0, y: 0 };
    
    // Multiplicar por la escala y sumar el offset
    return {
      x: (imgX * params.scale) + params.offsetX,
      y: (imgY * params.scale) + params.offsetY
    };
  }
  
  /**
   * Inicializar canvas bifaciales (llamar al inicio o al cambiar a modo bifacial)
   */
  function inicializarCanvasBifaciales() {
    console.log('🎨 Inicializando canvas bifaciales...');
    
    const canvasA = document.getElementById('canvasCaraA');
    const canvasB = document.getElementById('canvasCaraB');
    
    if (canvasA && canvasB) {
      // Dibujar placeholders iniciales
      redrawCanvasBifacial('A');
      redrawCanvasBifacial('B');
      
      console.log('✅ Canvas bifaciales inicializados');
    } else {
      console.error('❌ No se encontraron los canvas bifaciales');
    }
  }
  
  /**
   * Función unificada para cargar imágenes en modo bifacial
   * @param {File} file - Archivo de imagen
   * @param {string} cara - 'A' o 'B'
   * @param {string} tipo - 'jpg' o 'raw'
   */
  async function cargarImagenBifacial(file, cara, tipo) {
    console.log(`📷 Cargando ${tipo.toUpperCase()} para Cara ${cara}...`);
    
    const statusElement = document.getElementById(`statusCara${cara}`);
    const progressContainer = crearIndicadorProgreso();
    progressContainer.title.textContent = `Cargando Cara ${cara} (${tipo.toUpperCase()})`;
    
    try {
      let metadatos = null;
      let imagenCargada = null;
      
      if (tipo === 'jpg') {
        // Cargar imagen JPG
        actualizarProgreso(progressContainer, 20, `Cargando JPG Cara ${cara}...`);
        
        imagenCargada = await cargarImagen(file, {
          createThumbnail: true,
          maxDimension: 8000,
          compressionQuality: 0.95,
          useCache: true,
          progressCallback: (percent, message) => {
            actualizarProgreso(progressContainer, 20 + (percent * 0.5), `JPG Cara ${cara}: ${message}`);
          }
        });
        
        // Extraer metadatos
        actualizarProgreso(progressContainer, 70, `Extrayendo metadatos JPG Cara ${cara}...`);
        metadatos = await cargarMetadatos(file);
        
        // Guardar datos según la cara
        if (cara === 'A') {
          imageCaraA = imagenCargada;
          imageWidthCaraA = imagenCargada.naturalWidth;
          imageHeightCaraA = imagenCargada.naturalHeight;
          archivosComplementariosCaraA.jpg = file;
          archivosComplementariosCaraA.metadatosJPG = metadatos;
          archivosComplementariosCaraA.nombreFotografia = file.name || '';
        } else {
          imageCaraB = imagenCargada;
          imageWidthCaraB = imagenCargada.naturalWidth;
          imageHeightCaraB = imagenCargada.naturalHeight;
          archivosComplementariosCaraB.jpg = file;
          archivosComplementariosCaraB.metadatosJPG = metadatos;
          archivosComplementariosCaraB.nombreFotografia = file.name || '';
        }

        // Actualizar preview si el modo de identificación es 'fotografia'
        actualizarPreviewFotografia();

        if (statusElement) {
          statusElement.innerHTML = `<span style="color: #28a745;">JPG cargado (${imagenCargada.naturalWidth}×${imagenCargada.naturalHeight})</span>`;
        }
        
      } else if (tipo === 'raw') {
        // Cargar archivo RAW (solo metadatos)
        const rawFormat = detectarFormatoRAW(file);
        actualizarProgreso(progressContainer, 30, `Validando ${rawFormat.toUpperCase()} Cara ${cara}...`);
        
        await validarArchivoImagen(file);
        
        actualizarProgreso(progressContainer, 60, `Extrayendo metadatos ${rawFormat.toUpperCase()} Cara ${cara}...`);
        try {
          metadatos = await cargarMetadatos(file);
        } catch (metaError) {
          const esFormatoNoSoportado = metaError.message.includes('Unknown file format') ||
                                       metaError.message.includes('sin metadatos EXIF') ||
                                       metaError.message.includes('vacíos o no legibles');
          if (esFormatoNoSoportado) {
            console.warn(`⚠ Metadatos ${rawFormat.toUpperCase()} Cara ${cara} no legibles. Ingrese parámetros manualmente.`);
          } else {
            throw metaError;
          }
        }

        // Guardar datos según la cara
        if (cara === 'A') {
          archivosComplementariosCaraA.raw = file;
          archivosComplementariosCaraA.metadatosRAW = metadatos;
        } else {
          archivosComplementariosCaraB.raw = file;
          archivosComplementariosCaraB.metadatosRAW = metadatos;
        }

        if (statusElement) {
          statusElement.innerHTML = `<span style="color: #17a2b8;">RAW cargado (${rawFormat.toUpperCase()})</span>`;
        }
      }

      // Procesar metadatos (solo completar campos, sin cálculos)
      if (metadatos) {
        procesarMetadatos(metadatos, tipo === 'raw');
      }
      
      actualizarProgreso(progressContainer, 90, 'Verificando coherencia entre caras...');
      
      // Verificar coherencia de metadatos entre ambas caras
      await verificarCoherenciaMetadatosBifacial();
      
      // 🆕 DIBUJAR EN CANVAS BIFACIAL
      if (tipo === 'jpg') {
        actualizarProgreso(progressContainer, 95, `Dibujando en canvas Cara ${cara}...`);
        redrawCanvasBifacial(cara);
      }
      
      // 🆕 ACTUALIZAR ESTADO DE BOTONES
      actualizarEstadoProcesamiento();
      
      actualizarProgreso(progressContainer, 100, `Cara ${cara} cargada exitosamente`);
      setTimeout(() => removerIndicadorProgreso(progressContainer), 1000);
      
      console.log(`✅ Cara ${cara} (${tipo.toUpperCase()}) cargada:`, {
        cara,
        tipo,
        width: cara === 'A' ? imageWidthCaraA : imageWidthCaraB,
        height: cara === 'A' ? imageHeightCaraA : imageHeightCaraB,
        modelo: metadatos?.Model || 'N/A'
      });
      
    } catch (error) {
      console.error(`❌ Error cargando Cara ${cara}:`, error);
      actualizarProgreso(progressContainer, 0, `Error: ${error.message}`, true);
      setTimeout(() => removerIndicadorProgreso(progressContainer), 3000);
      
      if (statusElement) {
        statusElement.innerHTML = `<span style="color: #dc3545;">Error: ${error.message}</span>`;
      }
    }
  }
  
  /**
   * Verificar coherencia de metadatos entre Cara A y Cara B
   * Asume que ambas imágenes deben tener los mismos parámetros de cámara
   */
  async function verificarCoherenciaMetadatosBifacial() {
    console.log('🔍 Verificando coherencia de metadatos entre caras...');
    
    // Obtener metadatos de ambas caras (priorizar RAW > JPG)
    const metadatosA = archivosComplementariosCaraA.metadatosRAW || archivosComplementariosCaraA.metadatosJPG;
    const metadatosB = archivosComplementariosCaraB.metadatosRAW || archivosComplementariosCaraB.metadatosJPG;
    
    // Si no hay metadatos en ambas caras, no hay nada que verificar
    if (!metadatosA && !metadatosB) {
      console.log('⚠️ No hay metadatos en ninguna cara para verificar');
      return;
    }
    
    // Si solo hay metadatos en una cara, usar esos
    if (!metadatosA && metadatosB) {
      console.log('ℹ️ Solo Cara B tiene metadatos, usando esos');
      return;
    }
    
    if (metadatosA && !metadatosB) {
      console.log('ℹ️ Solo Cara A tiene metadatos, usando esos');
      return;
    }
    
    // Si ambas caras tienen metadatos, verificar coherencia
    const camposAVerificar = [
      { campo: 'Make', nombre: 'Fabricante' },
      { campo: 'Model', nombre: 'Modelo de cámara' },
      { campo: 'FocalLength', nombre: 'Distancia focal' },
      { campo: 'FNumber', nombre: 'Apertura (f/)' }
    ];
    
    const incoherencias = [];
    
    camposAVerificar.forEach(({ campo, nombre }) => {
      const valorA = metadatosA[campo];
      const valorB = metadatosB[campo];
      
      if (valorA && valorB && valorA !== valorB) {
        incoherencias.push({
          campo: nombre,
          valorA,
          valorB
        });
        console.warn(`⚠️ Incoherencia en ${nombre}:`, {
          CaraA: valorA,
          CaraB: valorB
        });
      }
    });
    
    // Mostrar advertencia si hay incoherencias
    if (incoherencias.length > 0) {
      let mensaje = 'ADVERTENCIA: Se detectaron diferencias en los metadatos entre ambas caras:\n\n';
      
      incoherencias.forEach(inc => {
        mensaje += `• ${inc.campo}:\n`;
        mensaje += `  Cara A: ${inc.valorA}\n`;
        mensaje += `  Cara B: ${inc.valorB}\n\n`;
      });
      
      mensaje += 'Esto puede indicar que las imágenes fueron tomadas con diferentes configuraciones.\n';
      mensaje += '¿Desea continuar de todas formas?';
      
      const continuar = confirm(mensaje);
      
      if (!continuar) {
        throw new Error('Verificación de coherencia cancelada por el usuario');
      }
      
      console.log('✅ Usuario confirmó continuar a pesar de incoherencias');
    } else {
      console.log('✅ Metadatos coherentes entre ambas caras');
      
      // Mostrar mensaje de confirmación
      UtilityHelpers.setStatus('Metadatos verificados: Ambas caras tienen parámetros coherentes', false);
    }
  }
  
  // ============================================================================
  
  // Event listeners para campos críticos de escala
  if (distanciaInput) {
    distanciaInput.addEventListener('input', function() {
      console.log('🔄 Distancia lente-objeto modificada:', this.value);
      // ✅ Ya no se calcula automáticamente - el usuario debe usar el botón "Calcular Escala"
      actualizarEstadoProcesamiento();
    });
    
    distanciaInput.addEventListener('blur', function() {
      // Solo validar entrada - cálculo ahora es manual
      if (this.value && parseFloat(this.value) > 0) {
        UtilityHelpers.setStatus('Distancia ingresada. Use "Calcular Escala" para proceder.', false);
      }
    });
  }
  
  if (focalInput && !focalInput.readOnly) {
    focalInput.addEventListener('input', function() {
      console.log('🔄 Distancia focal modificada:', this.value);
      // ✅ Ya no se calcula automáticamente - el usuario debe usar el botón "Calcular Escala"
      actualizarEstadoProcesamiento();
    });
  }
  
  if (sensorWidthInput && !sensorWidthInput.readOnly) {
    sensorWidthInput.addEventListener('input', function() {
      console.log('🔄 Ancho sensor modificado:', this.value);
      // Actualización automática eliminada - ahora completamente manual
    });
  }
  
  if (sensorHeightInput && !sensorHeightInput.readOnly) {
    sensorHeightInput.addEventListener('input', function() {
      console.log('🔄 Alto sensor modificado:', this.value);
      // Aunque no afecte el cálculo directo, puede ser útil para validación futura
    });
  }

  guardarConfigBtn.addEventListener('click', () => {
    if(!validarEntradas()) return;
    localStorage.setItem('cameraModel', cameraModelInput.value);
    localStorage.setItem('focalLength', focalInput.value);
    localStorage.setItem('aperture', apertureInput.value);
    localStorage.setItem('sensorWidth', sensorWidthInput.value);
    localStorage.setItem('sensorHeight', sensorHeightInput.value);
    localStorage.setItem('distancia', distanciaInput.value);
    UtilityHelpers.setStatus('Configuración guardada. Use "Calcular Escala"para aplicar cambios.', false);
    // Cálculo automático eliminado - ahora completamente manual
  });

  limpiarMetadatosBtn.addEventListener('click', () => {
    if (confirm('¿Está seguro de que desea limpiar los metadatos automáticos?\n\nEsto eliminará los datos de cámara, focal, apertura y sensor, pero preservará la distancia lente-objeto.')) {
      // Limpiar metadatos automáticos
      cameraModelInput.value = '';
      focalInput.value = '';
      apertureInput.value = '';
      sensorWidthInput.value = '';
      sensorHeightInput.value = '';
      
      // Restaurar campos como readonly
      cameraModelInput.readOnly = true;
      focalInput.readOnly = true;
      apertureInput.readOnly = true;
      sensorWidthInput.readOnly = true;
      sensorHeightInput.readOnly = true;
      
      // Limpiar localStorage de metadatos automáticos
      localStorage.removeItem('cameraModel');
      localStorage.removeItem('focalLength');
      localStorage.removeItem('aperture');
      localStorage.removeItem('sensorWidth');
      localStorage.removeItem('sensorHeight');
      
      // Resetear escala
      scale = null;
      scaleDisplay.textContent = '-';
      
      UtilityHelpers.setStatus('Metadatos automáticos limpiados. Cargue una nueva imagen para obtener datos frescos.', false);
    }
  });

  // =====================================================================================
  // EVENT LISTENERS PARA PROCESAMIENTO INDEPENDIENTE
  // =====================================================================================
  
  // Event listener para cálculo de escala independiente
  if (calcularEscalaBtn) {
    calcularEscalaBtn.addEventListener('click', async () => {
      if (estadoProcesamiento.calculandoEscala) return;
      
      console.log('📏 Iniciando cálculo de escala...');
      console.log(`   Modo: ${modoAnalisis}`);
      
      try {
        estadoProcesamiento.calculandoEscala = true;
        actualizarEstadoProcesamiento();
        
        // ============================================================================
        // MODO BIFACIAL: Calcular escala UNA VEZ y aplicar a AMBAS caras
        // ============================================================================
        if (modoAnalisis === 'bifacial') {
          console.log('🔄 Modo bifacial: Calculando escala única para ambas caras...');
          
          // Verificar que al menos una cara tenga imagen cargada
          if (!imageCaraA && !imageCaraB) {
            throw new Error('Debe cargar al menos una imagen (Cara A o Cara B) antes de calcular escala');
          }
          
          // Obtener metadatos (prioridad: RAW > JPG, A > B)
          const metadatosA = archivosComplementariosCaraA.metadatosRAW || archivosComplementariosCaraA.metadatosJPG;
          const metadatosB = archivosComplementariosCaraB.metadatosRAW || archivosComplementariosCaraB.metadatosJPG;
          
          // Usar los metadatos disponibles (preferir A si ambos existen)
          const metadatosAUsar = metadatosA || metadatosB;
          const caraUsada = metadatosA ? 'A' : 'B';
          
          if (!metadatosAUsar) {
            throw new Error('No se encontraron metadatos en ninguna de las caras. Verifique que las imágenes tengan datos EXIF.');
          }
          
          console.log(`   ✅ Usando metadatos de Cara ${caraUsada}`);
          console.log('   📷 Cámara:', metadatosAUsar.Model || 'Desconocida');
          console.log('   🔍 Focal:', metadatosAUsar.FocalLength || 'N/A');
          console.log('   ℹ️ Coherencia previamente verificada - la misma escala aplica a ambas caras');
          
          // Ejecutar cálculo de escala
          // IMPORTANTE: Como las imágenes tienen metadatos coherentes (misma cámara, focal, etc.)
          // la escala calculada será IDÉNTICA para ambas caras.
          // Solo calculamos UNA VEZ y la aplicamos a ambas.
          await ejecutarCalculoEscala();
          
          console.log(`   📐 Escala calculada: ${scale.toFixed(6)} mm/píxel`);
          console.log('   ✅ Esta escala se aplicará automáticamente a AMBAS caras');
          console.log('   💡 Justificación: Metadatos coherentes verificados al cargar imágenes');
          
          UtilityHelpers.setStatus(`Escala bifacial calculada: ${scale.toFixed(6)} mm/píxel. Se aplica a ambas caras (metadatos coherentes).`, false);
          
        } else {
          // ============================================================================
          // MODO MONOFACIAL: Cálculo estándar
          // ============================================================================
          await ejecutarCalculoEscala();
        }
        
        estadoProcesamiento.calculandoEscala = false;
        estadoProcesamiento.escalaCalculada = true;
        estadoProcesamiento.ultimaEscala = new Date();
        actualizarEstadoProcesamiento();
        
      } catch (error) {
        console.error('❌ Error calculando escala:', error);
        UtilityHelpers.setStatus(`Error calculando escala: ${error.message}`, true);
        
        estadoProcesamiento.calculandoEscala = false;
        actualizarEstadoProcesamiento();
      }
    });
  }
  
  // =====================================================================================
  // VERIFICACIÓN DE ESCALA - Medir distancia entre 2 puntos
  // =====================================================================================
  
  let modoVerificacionEscala = false;
  let puntosVerificacion = [];
  
  if (verificarEscalaBtn) {
    verificarEscalaBtn.addEventListener('click', () => {
      if (!scale) {
        toast.warning('Calcula la escala primero antes de verificarla.');
        return;
      }
      
      modoVerificacionEscala = true;
      puntosVerificacion = [];
      panelVerificacionEscala.style.display = 'block';
      resultadosVerificacion.style.display = 'none';
      errorCalculo.style.display = 'none';
      medidaRealInput.value = '';
      
      // Cambiar cursor del canvas
      canvas.style.cursor = 'crosshair';
      UtilityHelpers.setStatus('Modo verificación activo. Use botones +/- para zoom, Shift+Drag para mover imagen', false);
      console.log('📐 Modo verificación de escala activado - Zoom y Pan habilitados');
    });
  }
  
  if (cancelarVerificacionBtn) {
    cancelarVerificacionBtn.addEventListener('click', () => {
      cancelarModoVerificacion();
    });
  }
  
  // Los event listeners de nuevaMedicionBtn se configuran más abajo junto con aplicarCorreccionBtn
  
  if (calcularErrorBtn) {
    calcularErrorBtn.addEventListener('click', () => {
      const medidaRealMm = parseFloat(medidaRealInput.value);
      if (!medidaRealMm || medidaRealMm <= 0) {
        toast.warning('Ingresa una medida real válida en milímetros.');
        return;
      }
      
      const distanciaPx = window.distanciaVerificacionPx;
      if (!distanciaPx) {
        toast.error('No se pudo obtener la distancia en píxeles.');
        return;
      }
      
      // Calcular escala manual basada en la medición del usuario
      const escalaManual = medidaRealMm / distanciaPx;  // mm/px
      
      // Comparar con la escala automática calculada
      const escalaAutomatica = scale;  // mm/px
      
      // Calcular diferencia absoluta y porcentual
      const diferenciaEscala = Math.abs(escalaManual - escalaAutomatica);
      const errorPorcentaje = (diferenciaEscala / escalaManual) * 100;
      
      // Calcular factor de corrección
      const factorCorreccion = escalaManual / escalaAutomatica;
      
      // Guardar datos de verificación para aplicar corrección
      window.datosVerificacion = {
        escalaManual,
        escalaAutomatica,
        factorCorreccion,
        errorPorcentaje,
        distanciaPx,
        medidaRealMm
      };
      
      // Verificar posición de puntos respecto al centro
      // Usar dimensiones disponibles (pueden ser bifaciales o monofaciales)
      const anchoActual = anchoImagen || imageWidth || imageWidthCaraA || 0;
      const altoActual = altoImagen || imageHeight || imageHeightCaraA || 0;
      
      let maxDistanciaCentro = 0;  // Declarar fuera del bloque para acceso posterior
      
      if (!anchoActual || !altoActual) {
        console.warn('⚠️ No se pueden verificar posiciones: dimensiones de imagen no disponibles');
        window.datosVerificacion.maxDistanciaCentro = 0;
      } else {
        const centroX = anchoActual / 2;
        const centroY = altoActual / 2;
        const radioMaximo = Math.sqrt(centroX * centroX + centroY * centroY);
        
        puntosVerificacion.forEach(punto => {
          const dx = punto.x - centroX;
          const dy = punto.y - centroY;
          const distanciaCentro = Math.sqrt(dx * dx + dy * dy);
          const porcentajeRadio = (distanciaCentro / radioMaximo) * 100;
          if (porcentajeRadio > maxDistanciaCentro) maxDistanciaCentro = porcentajeRadio;
        });
        
        window.datosVerificacion.maxDistanciaCentro = maxDistanciaCentro;
      }
      
      // Actualizar display de distancia en mm usando escala MANUAL
      document.getElementById('distanciaMm').textContent = `${medidaRealMm.toFixed(3)} mm (real)`;
      
      errorCalculo.style.display = 'block';
      
      // Mostrar advertencia según posición de puntos
      const advertenciaZona = document.getElementById('advertenciaZona');
      if (maxDistanciaCentro > 40) {
        advertenciaZona.style.display = 'block';
        advertenciaZona.innerHTML = `Medición a ${maxDistanciaCentro.toFixed(0)}% del radio. Para mejor precisión, mida en zona central (< 40%).`;
      } else {
        advertenciaZona.style.display = 'none';
      }
      
      // Mostrar resultados con recomendación según error
      const botonesCorreccion = document.getElementById('botonesCorreccion');
      const botonNuevaMedicionSolo = document.getElementById('botonNuevaMedicionSolo');
      
      if (errorPorcentaje < 1) {
        errorCalculo.style.background = '#d4edda';
        errorCalculo.style.color = '#155724';
        errorCalculo.innerHTML = `<strong>Excelente precisión</strong><br>
          Escala automática: ${escalaAutomatica.toFixed(6)} mm/px<br>
          Escala manual: ${escalaManual.toFixed(6)} mm/px<br>
          Error: ${errorPorcentaje.toFixed(2)}% - No requiere corrección`;
        botonesCorreccion.style.display = 'none';
        botonNuevaMedicionSolo.style.display = 'block';
      } else if (errorPorcentaje < 5) {
        errorCalculo.style.background = '#fff3cd';
        errorCalculo.style.color = '#856404';
        errorCalculo.innerHTML = `<strong>Error moderado</strong><br>
          Escala automática: ${escalaAutomatica.toFixed(6)} mm/px<br>
          Escala manual: ${escalaManual.toFixed(6)} mm/px<br>
          Error: ${errorPorcentaje.toFixed(2)}%<br>
          Factor de corrección: ${factorCorreccion.toFixed(4)}`;
        botonesCorreccion.style.display = 'flex';
        botonNuevaMedicionSolo.style.display = 'none';
      } else {
        errorCalculo.style.background = '#f8d7da';
        errorCalculo.style.color = '#721c24';
        errorCalculo.innerHTML = `<strong>Error significativo</strong><br>
          Escala automática: ${escalaAutomatica.toFixed(6)} mm/px<br>
          Escala manual: ${escalaManual.toFixed(6)} mm/px<br>
          Error: ${errorPorcentaje.toFixed(2)}%<br>
          Factor de corrección: ${factorCorreccion.toFixed(4)}<br>
          <small>Recomendado: Aplicar corrección o verificar metadatos de cámara</small>`;
        botonesCorreccion.style.display = 'flex';
        botonNuevaMedicionSolo.style.display = 'none';
      }
      
      console.log(`📊 Verificación de escala:
  • Distancia en píxeles: ${distanciaPx.toFixed(2)}px
  • Medida real ingresada: ${medidaRealMm.toFixed(3)}mm
  • Escala automática: ${escalaAutomatica.toFixed(6)} mm/px
  • Escala manual calculada: ${escalaManual.toFixed(6)} mm/px
  • Diferencia absoluta: ${diferenciaEscala.toFixed(6)} mm/px
  • Error relativo: ${errorPorcentaje.toFixed(2)}%`);
    });
  }
  
  // Event listener para aplicar corrección de escala
  const aplicarCorreccionBtn = document.getElementById('aplicarCorreccionBtn');
  if (aplicarCorreccionBtn) {
    aplicarCorreccionBtn.addEventListener('click', () => {
      const datos = window.datosVerificacion;
      if (!datos) {
        toast.error('No hay datos de verificación.');
        return;
      }
      
      const confirmar = confirm(
        `¿Aplicar factor de corrección ${datos.factorCorreccion.toFixed(4)}?\n\n` +
        `Esto actualizará:\n` +
        `• Escala: ${datos.escalaAutomatica.toFixed(6)} → ${datos.escalaManual.toFixed(6)} mm/px\n` +
        `• Todas las mediciones existentes serán recalculadas\n\n` +
        `Nota: La corrección es efectiva en zona central (< 40% radio).\n` +
        `Cerca de bordes puede haber error residual por distorsión de lente.`
      );
      
      if (!confirmar) return;
      
      // Aplicar factor de corrección a la escala global
      const escalaAnterior = scale;
      scale = datos.escalaManual;
      
      // Marcar que se está usando escala corregida
      window.escalaCorregida = {
        activa: true,
        factorCorreccion: datos.factorCorreccion,
        escalaOriginal: escalaAnterior,
        escalaCorregida: scale,
        errorOriginal: datos.errorPorcentaje,
        fecha: new Date().toISOString(),
        zonaVerificacion: datos.maxDistanciaCentro
      };
      
      // Actualizar display de escala
      scaleDisplay.textContent = `${scale.toFixed(6)}`;
      scaleDisplay.style.color = '#28a745';
      scaleDisplay.style.fontWeight = 'bold';
      
      // Mostrar indicador de corrección
      const scaleCorrectedIndicator = document.getElementById('scaleCorrectedIndicator');
      if (scaleCorrectedIndicator) {
        scaleCorrectedIndicator.style.display = 'inline-block';
        scaleCorrectedIndicator.title = `Factor: ${datos.factorCorreccion.toFixed(4)} | Error original: ${datos.errorPorcentaje.toFixed(2)}% | Zona: ${datos.maxDistanciaCentro.toFixed(0)}% del radio`;
      }
      
      console.log(`✅ Corrección de escala aplicada:
  • Factor de corrección: ${datos.factorCorreccion.toFixed(6)}
  • Escala anterior: ${escalaAnterior.toFixed(6)} mm/px
  • Escala corregida: ${scale.toFixed(6)} mm/px
  • Error original: ${datos.errorPorcentaje.toFixed(2)}%
  • Zona de verificación: ${datos.maxDistanciaCentro.toFixed(1)}% del radio
  • IMPORTANTE: Las nuevas mediciones usarán la escala corregida automáticamente`);
      
      // Invalidar cachés de análisis morfológicos (escala cambió)
      invalidarCachePorCambioEscala();
      
      // Redibujar canvas con mediciones actualizadas
      redraw();
      
      // Salir del modo verificación
      cancelarModoVerificacion();
      
      UtilityHelpers.setStatus(`Escala corregida aplicada (factor: ${datos.factorCorreccion.toFixed(4)}). Nuevas mediciones usarán escala corregida.`, false);
    });
  }
  
  // Event listeners para nueva medición (ambos botones)
  const nuevaMedicionBtn2 = document.getElementById('nuevaMedicionBtn2');
  [nuevaMedicionBtn, nuevaMedicionBtn2].forEach(btn => {
    if (btn) {
      btn.addEventListener('click', () => {
        puntosVerificacion = [];
        window.distanciaVerificacionPx = null;
        window.datosVerificacion = null;
        resultadosVerificacion.style.display = 'none';
        errorCalculo.style.display = 'none';
        document.getElementById('advertenciaZona').style.display = 'none';
        document.getElementById('botonesCorreccion').style.display = 'none';
        document.getElementById('botonNuevaMedicionSolo').style.display = 'none';
        medidaRealInput.value = '';
        redraw();
        UtilityHelpers.setStatus('Nueva medición: Haga clic en 2 puntos', false);
      });
    }
  });
  
  function cancelarModoVerificacion() {
    modoVerificacionEscala = false;
    puntosVerificacion = [];
    window.distanciaVerificacionPx = null;
    window.datosVerificacion = null;
    panelVerificacionEscala.style.display = 'none';
    canvas.style.cursor = 'default';
    redraw();
    UtilityHelpers.setStatus('Modo verificación cancelado', false);
  }
  
  function procesarClickVerificacion(x, y) {
    puntosVerificacion.push({ x, y });
    
    if (puntosVerificacion.length === 1) {
      UtilityHelpers.setStatus('Punto 1 marcado. Haga clic en el segundo punto', false);
      redraw();
    } else if (puntosVerificacion.length === 2) {
      calcularDistanciaVerificacion();
    }
  }
  
  function calcularDistanciaVerificacion() {
    const p1 = puntosVerificacion[0];
    const p2 = puntosVerificacion[1];
    
    // Calcular distancia euclidiana en píxeles
    const dx = p2.x - p1.x;
    const dy = p2.y - p1.y;
    const distanciaPx = Math.sqrt(dx * dx + dy * dy);
    
    // Guardar distancia en píxeles para cálculo posterior
    window.distanciaVerificacionPx = distanciaPx;
    
    // Mostrar solo píxeles - NO convertir con escala automática
    document.getElementById('distanciaPx').textContent = `${distanciaPx.toFixed(2)} píxeles`;
    document.getElementById('distanciaMm').textContent = `Ingrese medida real →`;
    resultadosVerificacion.style.display = 'block';
    
    UtilityHelpers.setStatus(`Distancia medida: ${distanciaPx.toFixed(2)} píxeles. Ingrese la medida real en mm`, false);
    
    console.log(`📏 Medición completada:
  • Punto 1: (${p1.x.toFixed(1)}, ${p1.y.toFixed(1)})
  • Punto 2: (${p2.x.toFixed(1)}, ${p2.y.toFixed(1)})
  • Distancia: ${distanciaPx.toFixed(2)} píxeles
  • Esperando medida real del usuario para calcular escala manual`);
    
    redraw();
  }
  
  // Event listener para detección automática de objetos
  if (detectarObjetosBtn) {
    detectarObjetosBtn.addEventListener('click', async () => {
      if (estadoProcesamiento.detectandoObjetos) return;
      
      console.log('🎯 Iniciando detección automática de objetos...');
      
      try {
        estadoProcesamiento.detectandoObjetos = true;
        actualizarEstadoProcesamiento();
        
        await ejecutarDeteccionAutomatica();
        
        estadoProcesamiento.detectandoObjetos = false;
        estadoProcesamiento.objetosDetectados = true;
        estadoProcesamiento.ultimaDeteccion = new Date();
        actualizarEstadoProcesamiento();
        
      } catch (error) {
        console.error('❌ Error detectando objetos:', error);
        UtilityHelpers.setStatus(`Error detectando objetos: ${error.message}`, true);
        
        estadoProcesamiento.detectandoObjetos = false;
        actualizarEstadoProcesamiento();
      }
    });
  }
  
  // Event listener para detección manual por área (integrado con selección manual)
  if (deteccionManualBtn) {
    deteccionManualBtn.addEventListener('click', () => {
      if (estadoProcesamiento.modoDeteccionManual) {
        // Cancelar según el modo
        if (modoAnalisis === 'bifacial') {
          cancelarDeteccionManualBifacial();
        } else {
          cancelarSeleccionManual();
        }
        estadoProcesamiento.modoDeteccionManual = false;
      } else {
        // ============================================================================
        // MODO BIFACIAL: Activar detección en AMBOS canvas simultáneamente
        // ============================================================================
        if (modoAnalisis === 'bifacial') {
          const tieneCaraA = imageCaraA !== null;
          const tieneCaraB = imageCaraB !== null;
          
          if (!tieneCaraA && !tieneCaraB) {
            toast.warning('Carga al menos una imagen (Cara A o Cara B) antes de usar detección manual.');
            return;
          }
          
          // 🆕 SIMPLIFICADO: Activar detección en ambos canvas
          // El usuario hace clic directamente en el canvas que desea usar
          activarDeteccionManualBifacialSimultanea();
          estadoProcesamiento.modoDeteccionManual = true;
          
        } else {
          // ============================================================================
          // MODO MONOFACIAL: Verificación estándar
          // ============================================================================
          if (!image) {
            toast.warning('Carga una imagen antes de usar detección manual.');
            return;
          }
          
          // Activar usando el sistema integrado
          iniciarSeleccionManual();
          estadoProcesamiento.modoDeteccionManual = true;
        }
      }
      actualizarEstadoProcesamiento();
    });
  }
  
  /**
   * 🆕 Activar detección manual en modo bifacial (SIMPLIFICADO)
   * Activa event listeners en AMBOS canvas simultáneamente
   * El usuario hace clic directamente en el canvas que desea usar
   */
  function activarDeteccionManualBifacialSimultanea() {
    console.log('🎯 Activando detección manual bifacial simultánea');
    
    // Guardar objetos actuales como backup
    originalObjects = [...objects];
    
    // Activar modo selección manual
    isManualSelectionMode = true;
    isSelectingArea = false;
    manualSelectedArea = null;
    
    // Actualizar interfaz
    manualSelectionStatus.style.display = 'block';
    manualSelectionInstructions.textContent = 'Haga clic y arrastre directamente en Cara A (azul) o Cara B (verde) para seleccionar objetos';
    
    // Actualizar botón principal
    if (deteccionManualBtn) {
      deteccionManualBtn.style.background = '#dc3545';
      deteccionManualBtn.style.color = 'white';
      deteccionManualBtn.textContent = 'Cancelar Manual';
    }
    
    // Obtener referencias a ambos canvas
    const canvasA = document.getElementById('canvasCaraA');
    const canvasB = document.getElementById('canvasCaraB');
    
    // Configurar cursor crosshair en ambos canvas (si existen imágenes)
    if (imageCaraA && canvasA) {
      canvasA.style.cursor = 'crosshair';
    }
    if (imageCaraB && canvasB) {
      canvasB.style.cursor = 'crosshair';
    }
    
    // 🆕 AGREGAR EVENT LISTENERS A CANVAS A
    if (imageCaraA && canvasA) {
      // Crear handlers para Cara A
      const mouseDownHandlerA = function(e) {
        if (!isManualSelectionMode) return;
        
        // Configurar variables globales para Cara A
        configurarCanvasParaDeteccion('A');
        
        const rect = canvasA.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        
        console.log(`🖱️ Mouse down en Cara A:`, mouseX, mouseY);
        iniciarSeleccionArea(mouseX, mouseY);
      };
      
      const mouseMoveHandlerA = function(e) {
        if (!isManualSelectionMode || !isSelectingArea) return;
        if (!window.deteccionBifacialActiva || window.deteccionBifacialActiva.cara !== 'A') return;
        
        const rect = canvasA.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        
        actualizarSeleccionArea(mouseX, mouseY);
      };
      
      const mouseUpHandlerA = function(e) {
        if (!isManualSelectionMode || !isSelectingArea) return;
        if (!window.deteccionBifacialActiva || window.deteccionBifacialActiva.cara !== 'A') return;
        
        console.log(`🖱️ Mouse up en Cara A`);
        finalizarSeleccionArea();
      };
      
      // Guardar handlers para poder eliminarlos después
      window.bifacialHandlersA = {
        mouseDown: mouseDownHandlerA,
        mouseMove: mouseMoveHandlerA,
        mouseUp: mouseUpHandlerA
      };
      
      canvasA.addEventListener('mousedown', mouseDownHandlerA);
      canvasA.addEventListener('mousemove', mouseMoveHandlerA);
      canvasA.addEventListener('mouseup', mouseUpHandlerA);
      
      console.log('✅ Event listeners agregados a Cara A');
    }
    
    // 🆕 AGREGAR EVENT LISTENERS A CANVAS B
    if (imageCaraB && canvasB) {
      // Crear handlers para Cara B
      const mouseDownHandlerB = function(e) {
        if (!isManualSelectionMode) return;
        
        // Configurar variables globales para Cara B
        configurarCanvasParaDeteccion('B');
        
        const rect = canvasB.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        
        console.log(`🖱️ Mouse down en Cara B:`, mouseX, mouseY);
        iniciarSeleccionArea(mouseX, mouseY);
      };
      
      const mouseMoveHandlerB = function(e) {
        if (!isManualSelectionMode || !isSelectingArea) return;
        if (!window.deteccionBifacialActiva || window.deteccionBifacialActiva.cara !== 'B') return;
        
        const rect = canvasB.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        
        actualizarSeleccionArea(mouseX, mouseY);
      };
      
      const mouseUpHandlerB = function(e) {
        if (!isManualSelectionMode || !isSelectingArea) return;
        if (!window.deteccionBifacialActiva || window.deteccionBifacialActiva.cara !== 'B') return;
        
        console.log(`🖱️ Mouse up en Cara B`);
        finalizarSeleccionArea();
      };
      
      // Guardar handlers para poder eliminarlos después
      window.bifacialHandlersB = {
        mouseDown: mouseDownHandlerB,
        mouseMove: mouseMoveHandlerB,
        mouseUp: mouseUpHandlerB
      };
      
      canvasB.addEventListener('mousedown', mouseDownHandlerB);
      canvasB.addEventListener('mousemove', mouseMoveHandlerB);
      canvasB.addEventListener('mouseup', mouseUpHandlerB);
      
      console.log('✅ Event listeners agregados a Cara B');
    }
    
    // Limpiar objetos automáticos (preservar objetos de AIA)
    objects = objects.filter(o => o._fromIA);
    
    // Redibujar ambos canvas
    if (imageCaraA) redrawCanvasBifacial('A');
    if (imageCaraB) redrawCanvasBifacial('B');
    
    UtilityHelpers.setStatus('Modo detección manual bifacial activado. Haga clic en cualquier canvas (A o B) para seleccionar objetos. ESC para cancelar.', false);
    console.log('✅ Detección manual bifacial simultánea activada');
  }
  
  /**
   * 🆕 Configurar variables globales para detección en una cara específica
   */
  function configurarCanvasParaDeteccion(cara) {
    console.log(`🔧 Configurando canvas para Cara ${cara}`);
    
    // Guardar backup si es la primera vez
    if (!window.canvasBackup) {
      window.canvasBackup = canvas;
      window.ctxBackup = ctx;
      window.imagenMonofacialBackup = image;
      window.imageWidthMonofacialBackup = imageWidth;
      window.imageHeightMonofacialBackup = imageHeight;
    }
    
    // Remover indicador visual del canvas anterior
    const canvasA = document.getElementById('canvasCaraA');
    const canvasB = document.getElementById('canvasCaraB');
    if (canvasA) canvasA.style.boxShadow = '';
    if (canvasB) canvasB.style.boxShadow = '';
    
    if (cara === 'A') {
      // 🔧 ASIGNAR a variables globales directamente (sin window.)
      canvas = document.getElementById('canvasCaraA');
      ctx = canvas.getContext('2d');
      image = imageCaraA;
      imageWidth = imageWidthCaraA;
      imageHeight = imageHeightCaraA;
      
      // 🎨 Indicador visual: borde brillante en canvas activo
      if (canvas) {
        canvas.style.boxShadow = '0 0 0 4px #17a2b8, 0 0 20px rgba(23, 162, 184, 0.5)';
      }
      
      // 🆕 CONFIGURAR manualModeScale con parámetros del canvas bifacial
      const params = obtenerParametrosCanvasBifacial('A');
      if (params) {
        window.manualModeScale = {
          scale: params.scale,
          offsetX: params.offsetX,
          offsetY: params.offsetY,
          canvasWidth: params.canvasElement.width,
          canvasHeight: params.canvasElement.height
        };
        console.log('   🔧 manualModeScale configurado:', window.manualModeScale);
      }
      
      window.deteccionBifacialActiva = {
        cara: 'A',
        canvasOriginal: window.canvasBackup,
        ctxOriginal: window.ctxBackup
      };
      if (typeof actualizarBloqueExportacion === 'function') actualizarBloqueExportacion();
      
      console.log('   📷 Canvas configurado: Cara A (Anverso)');
      console.log('   📐 Dimensiones imagen:', imageWidthCaraA, 'x', imageHeightCaraA);
      console.log('   📏 Escala:', params ? params.scale.toFixed(4) : 'N/A');
      console.log('   🖼️ image:', image);
      console.log('   📦 image.naturalWidth:', image ? image.naturalWidth : 'N/A');
      
    } else if (cara === 'B') {
      // 🔧 ASIGNAR a variables globales directamente (sin window.)
      canvas = document.getElementById('canvasCaraB');
      ctx = canvas.getContext('2d');
      image = imageCaraB;
      imageWidth = imageWidthCaraB;
      imageHeight = imageHeightCaraB;
      
      // � Indicador visual: borde brillante en canvas activo
      if (canvas) {
        canvas.style.boxShadow = '0 0 0 4px #28a745, 0 0 20px rgba(40, 167, 69, 0.5)';
      }
      
      // �🆕 CONFIGURAR manualModeScale con parámetros del canvas bifacial
      const params = obtenerParametrosCanvasBifacial('B');
      if (params) {
        window.manualModeScale = {
          scale: params.scale,
          offsetX: params.offsetX,
          offsetY: params.offsetY,
          canvasWidth: params.canvasElement.width,
          canvasHeight: params.canvasElement.height
        };
        console.log('   🔧 manualModeScale configurado:', window.manualModeScale);
      }
      
      window.deteccionBifacialActiva = {
        cara: 'B',
        canvasOriginal: window.canvasBackup,
        ctxOriginal: window.ctxBackup
      };
      if (typeof actualizarBloqueExportacion === 'function') actualizarBloqueExportacion();
      
      console.log('   📷 Canvas configurado: Cara B (Reverso)');
      console.log('   📐 Dimensiones imagen:', imageWidthCaraB, 'x', imageHeightCaraB);
      console.log('   📏 Escala:', params ? params.scale.toFixed(4) : 'N/A');
      console.log('   🖼️ image:', image);
      console.log('   📦 image.naturalWidth:', image ? image.naturalWidth : 'N/A');
    }
  }
  
  /**
   * 🆕 Iniciar detección manual para modo bifacial
   * REUTILIZA el sistema de detección manual monofacial
   * Solo configura las variables globales y canvas apropiados
   */
  function iniciarDeteccionManualBifacial(cara) {
    console.log(`🎯 Iniciando detección manual bifacial para Cara ${cara}`);
    
    if (cara === 'A') {
      // Verificar que existe imagen en Cara A
      if (!imageCaraA) {
        UtilityHelpers.setStatus('Error: Primero cargue una imagen en Cara A', true);
        return;
      }
      
      // 🔄 GUARDAR variables monofaciales originales (si existen)
      window.imagenMonofacialBackup = image;
      window.imageWidthMonofacialBackup = imageWidth;
      window.imageHeightMonofacialBackup = imageHeight;
      
      // 🔄 CONFIGURAR VARIABLES GLOBALES para usar sistema monofacial
      image = imageCaraA;
      imageWidth = imageWidthCaraA;
      imageHeight = imageHeightCaraA;
      
      // 🔄 REASIGNAR CANVAS: usar canvasCaraA como si fuera el canvas principal
      const canvasOriginal = canvas;
      const ctxOriginal = ctx;
      
      window.canvasBackup = canvasOriginal;  // Guardar referencia original
      window.ctxBackup = ctxOriginal;
      
      // Reasignar variables globales al canvas bifacial
      window.canvas = document.getElementById('canvasCaraA');
      window.ctx = window.canvas.getContext('2d');
      
      // Marcar que estamos en modo bifacial
      window.deteccionBifacialActiva = {
        cara: 'A',
        canvasOriginal: canvasOriginal,
        ctxOriginal: ctxOriginal
      };
      if (typeof actualizarBloqueExportacion === 'function') actualizarBloqueExportacion();
      
      UtilityHelpers.setStatus('CARA A (Anverso): Haga clic y arrastre en el canvas azul para seleccionar objetos. ESC para cancelar.', false);
      console.log('   📷 Canvas reasignado: Cara A (Anverso)');
      console.log('   📐 Dimensiones:', imageWidthCaraA, 'x', imageHeightCaraA);
      
      // 🔄 USAR FUNCIÓN MONOFACIAL EXISTENTE
      iniciarSeleccionManual();
      
    } else if (cara === 'B') {
      // Verificar que existe imagen en Cara B
      if (!imageCaraB) {
        UtilityHelpers.setStatus('Error: Primero cargue una imagen en Cara B', true);
        return;
      }
      
      // 🔄 GUARDAR variables monofaciales originales (si existen)
      window.imagenMonofacialBackup = image;
      window.imageWidthMonofacialBackup = imageWidth;
      window.imageHeightMonofacialBackup = imageHeight;
      
      // 🔄 CONFIGURAR VARIABLES GLOBALES para usar sistema monofacial
      image = imageCaraB;
      imageWidth = imageWidthCaraB;
      imageHeight = imageHeightCaraB;
      
      // 🔄 REASIGNAR CANVAS: usar canvasCaraB como si fuera el canvas principal
      const canvasOriginal = canvas;
      const ctxOriginal = ctx;
      
      window.canvasBackup = canvasOriginal;  // Guardar referencia original
      window.ctxBackup = ctxOriginal;
      
      // Reasignar variables globales al canvas bifacial
      window.canvas = document.getElementById('canvasCaraB');
      window.ctx = window.canvas.getContext('2d');
      
      // Marcar que estamos en modo bifacial
      window.deteccionBifacialActiva = {
        cara: 'B',
        canvasOriginal: canvasOriginal,
        ctxOriginal: ctxOriginal
      };
      if (typeof actualizarBloqueExportacion === 'function') actualizarBloqueExportacion();
      
      UtilityHelpers.setStatus('CARA B (Reverso): Haga clic y arrastre en el canvas verde para seleccionar objetos. ESC para cancelar.', false);
      console.log('   📷 Canvas reasignado: Cara B (Reverso)');
      console.log('   📐 Dimensiones:', imageWidthCaraB, 'x', imageHeightCaraB);
      
      // 🔄 USAR FUNCIÓN MONOFACIAL EXISTENTE
      iniciarSeleccionManual();
      
    } else if (cara === 'AMBAS') {
      // Modo secuencial: primero Cara A, luego Cara B
      if (!imageCaraA && !imageCaraB) {
        UtilityHelpers.setStatus('Error: Debe cargar al menos una imagen en Cara A o B', true);
        return;
      }
      
      UtilityHelpers.setStatus('MODO SECUENCIAL: Primero detecte objetos en Cara A. Al finalizar, continuará con Cara B.', false);
      console.log('   📷 Modo secuencial activado: Cara A → Cara B');
      
      // Guardar flag para continuar con Cara B después
      window.deteccionBifacialSecuencial = {
        activo: true,
        caraActual: 'A',
        objetosCaraA: [],
        objetosCaraB: []
      };
      
      // Iniciar con Cara A (si existe)
      if (imageCaraA) {
        iniciarDeteccionManualBifacial('A');
      } else {
        iniciarDeteccionManualBifacial('B');
      }
    }
  }
  
  /**
   * 🆕 Cancelar detección manual bifacial
   * REUTILIZA la función monofacial y restaura canvas original
   */
  function cancelarDeteccionManualBifacial() {
    console.log('🚫 Cancelando detección manual bifacial');
    
    // Remover event listeners de ambos canvas
    const canvasA = document.getElementById('canvasCaraA');
    const canvasB = document.getElementById('canvasCaraB');
    
    if (canvasA && window.bifacialHandlersA) {
      canvasA.removeEventListener('mousedown', window.bifacialHandlersA.mouseDown);
      canvasA.removeEventListener('mousemove', window.bifacialHandlersA.mouseMove);
      canvasA.removeEventListener('mouseup', window.bifacialHandlersA.mouseUp);
      canvasA.style.cursor = 'default';
      canvasA.style.boxShadow = ''; // Remover borde brillante
      window.bifacialHandlersA = null;
      console.log('   ✅ Event listeners removidos de Cara A');
    }
    
    if (canvasB && window.bifacialHandlersB) {
      canvasB.removeEventListener('mousedown', window.bifacialHandlersB.mouseDown);
      canvasB.removeEventListener('mousemove', window.bifacialHandlersB.mouseMove);
      canvasB.removeEventListener('mouseup', window.bifacialHandlersB.mouseUp);
      canvasB.style.cursor = 'default';
      canvasB.style.boxShadow = ''; // Remover borde brillante
      window.bifacialHandlersB = null;
      console.log('   ✅ Event listeners removidos de Cara B');
    }
    
    // Desactivar modo selección
    isManualSelectionMode = false;
    isSelectingArea = false;
    manualSelectedArea = null;
    
    // Restaurar objetos automáticos
    objects = [...originalObjects];
    originalObjects = [];
    
    // Restaurar interfaz
    manualSelectionStatus.style.display = 'none';
    
    if (deteccionManualBtn) {
      deteccionManualBtn.style.background = '#ffc107';
      deteccionManualBtn.style.color = '#212529';
      deteccionManualBtn.textContent = 'Detección Manual';
    }
    
    // Restaurar canvas original si estábamos en modo bifacial
    if (window.canvasBackup) {
      // 🔧 Restaurar variables globales directamente (sin window.)
      canvas = window.canvasBackup;
      ctx = window.ctxBackup;
      
      if (window.imagenMonofacialBackup) {
        image = window.imagenMonofacialBackup;
        imageWidth = window.imageWidthMonofacialBackup;
        imageHeight = window.imageHeightMonofacialBackup;
      }
      
      console.log('   ✅ Canvas y variables restauradas');
      
      // Limpiar flags
      window.deteccionBifacialActiva = null;
      window.canvasBackup = null;
      window.ctxBackup = null;
      window.imagenMonofacialBackup = null;
      window.imageWidthMonofacialBackup = null;
      window.imageHeightMonofacialBackup = null;
    }
    
    // Redibujar ambos canvas bifaciales
    if (imageCaraA) redrawCanvasBifacial('A');
    if (imageCaraB) redrawCanvasBifacial('B');
    
    // Actualizar estado
    estadoProcesamiento.modoDeteccionManual = false;
    actualizarEstadoProcesamiento();
    
    UtilityHelpers.setStatus('Detección manual bifacial cancelada', false);
    console.log('✅ Detección manual bifacial cancelada completamente');
  }

  // Event listeners para botones de prueba virtual
  const generateVirtualTestBtn = document.getElementById('generateVirtualTestBtn');
  const validateResultsBtn = document.getElementById('validateResultsBtn');
  const testProgressIndicatorBtn = document.getElementById('testProgressIndicatorBtn');

  if (generateVirtualTestBtn) {
    generateVirtualTestBtn.addEventListener('click', () => {
      console.log('🧪 Iniciando generación de imagen de prueba virtual...');
      generateVirtualTestBtn.disabled = true;
      generateVirtualTestBtn.textContent = 'Generando...';
      
      setTimeout(() => {
        generarImagenVirtualPrueba();
        generateVirtualTestBtn.disabled = false;
        generateVirtualTestBtn.textContent = 'Generar Imagen de Prueba Virtual';
        validateResultsBtn.disabled = false;
      }, 100);
    });
  }

  if (validateResultsBtn) {
    validateResultsBtn.addEventListener('click', () => {
      console.log('📊 Validando resultados de la prueba virtual...');
      validateResultsBtn.disabled = true;
      validateResultsBtn.textContent = 'Validando...';
      
      setTimeout(() => {
        validarResultadosPrueba();
        validateResultsBtn.disabled = false;
        validateResultsBtn.textContent = 'Validar Resultados';
      }, 100);
    });
  }
  
  // === BOTÓN DE PRUEBA: INDICADOR DE PROGRESO DETALLADO ===
  if (testProgressIndicatorBtn) {
    testProgressIndicatorBtn.addEventListener('click', () => {
      console.log('🔄 Probando sistema de indicadores de progreso...');
      
      // Definir pasos de ejemplo para la demostración
      const demoSteps = [
        { id: 'prepare', title: 'Preparando imagen', detail: 'Validando dimensiones y memoria...' },
        { id: 'analyze', title: 'Analizando fondo', detail: 'Detectando color y homogeneidad...' },
        { id: 'strategy', title: 'Seleccionando estrategia', detail: 'Optimizando algoritmos de detección...' },
        { id: 'detect', title: 'Detectando objetos', detail: 'Ejecutando detección híbrida...' },
        { id: 'extract', title: 'Extrayendo contornos', detail: 'Procesando límites de objetos...' },
        { id: 'calculate', title: 'Calculando métricas', detail: 'Analizando características morfológicas...' },
        { id: 'finalize', title: 'Finalizando', detail: 'Preparando visualización y resultados...' }
      ];
      
      // Iniciar indicador de progreso con tiempo estimado de 20 segundos
      startDetailedProgress('Demo: Análisis Morfométrico Completo', demoSteps, 20);
      
      // Simular procesamiento paso a paso
      let currentStepIndex = 0;
      
      const processNextStep = () => {
        if (currentStepIndex >= demoSteps.length) {
          // Todos los pasos completados
          setTimeout(() => {
            endDetailedProgress(true, `Demo completada: ${demoSteps.length} pasos ejecutados exitosamente`);
          }, 1000);
          return;
        }
        
        // Verificar si fue cancelado
        if (isProgressCancelled()) {
          console.log('Demo cancelada por el usuario');
          return;
        }
        
        const currentStep = demoSteps[currentStepIndex];
        
        // Actualizar al paso actual
        updateDetailedProgress(currentStep.id);
        
        // Simular trabajo con detalles dinámicos
        setTimeout(() => {
          // Actualizar detalle con información simulada
          const detalles = [
            'Imagen: 4000×3000 píxeles (~45MB)',
            'Fondo: Blanco uniforme detectado',
            'Estrategia: RÁPIDA (Fondo blanco uniforme)',
            '12 objetos encontrados',
            '148 puntos de contorno extraídos',
            'Calculando objeto 12/12...',
            '¡Proceso completado!'
          ];
          
          if (currentStepIndex < detalles.length) {
            updateDetailedProgress(currentStep.id, detalles[currentStepIndex]);
          }
          
          // Marcar como completado y avanzar
          completeCurrentStep();
          currentStepIndex++;
          
          // Tiempo variable por paso (2-4 segundos)
          const randomDelay = 2000 + Math.random() * 2000;
          setTimeout(processNextStep, randomDelay);
          
        }, 500);
      };
      
      // Iniciar simulación
      setTimeout(processNextStep, 500);
    });
  }
  
  // Función de debounce para optimizar rendimiento
  function debounce(func, wait) {
    let timeout;
    return function executedFunction(...args) {
      const later = () => {
        clearTimeout(timeout);
        func(...args);
      };
      clearTimeout(timeout);
      timeout = setTimeout(later, wait);
    };
  }

