  // FIN GEOMETRÍA MANUAL
  // ============================================================================

  /**
   * Calcular centroide de un polígono (para colocar etiquetas)
   */
  function calcularCentroidePoligono(puntos) {
    if (!puntos || puntos.length === 0) return { x: 0, y: 0 };
    if (puntos.length < 3) {
      let sx = 0, sy = 0;
      puntos.forEach(p => { sx += (p.x || 0); sy += (p.y || 0); });
      return { x: sx / puntos.length, y: sy / puntos.length };
    }
    // Shoelace área-ponderado (geométricamente exacto)
    const n = puntos.length;
    let cx = 0, cy = 0, sa = 0;
    for (let i = 0; i < n; i++) {
      const j = (i + 1) % n;
      const cross = (puntos[i].x || 0) * (puntos[j].y || 0) - (puntos[j].x || 0) * (puntos[i].y || 0);
      sa += cross;
      cx += ((puntos[i].x || 0) + (puntos[j].x || 0)) * cross;
      cy += ((puntos[i].y || 0) + (puntos[j].y || 0)) * cross;
    }
    sa /= 2;
    if (Math.abs(sa) > 1e-10) {
      return { x: cx / (6 * sa), y: cy / (6 * sa) };
    }
    // Fallback aritmético si el polígono es degenerado
    let sumX = 0, sumY = 0;
    puntos.forEach(p => { sumX += (p.x || 0); sumY += (p.y || 0); });
    return { x: sumX / n, y: sumY / n };
  }

  /**
   * Redibujar polígono en el canvas ampliado (MEJORADO: múltiples trazados)
   */
  function redibujarPoligonoEnCanvasAmpliado() {
    if (!selectedObjectForPerforation || !perforationCanvas || !perforationCanvasCtx) return;

    // Mantener etiquetas sincronizadas entre canvas y listado en cada redibujo.
    recalcularEtiquetasTrazadosPH();
    
    const obj = selectedObjectForPerforation;
    
    // Re-renderizar el objeto base
    const canvasWidth = perforationCanvas.width;
    const canvasHeight = perforationCanvas.height;
    
    // Limpiar
    perforationCanvasCtx.clearRect(0, 0, canvasWidth, canvasHeight);
    
    // Fondo blanco
    perforationCanvasCtx.fillStyle = '#ffffff';
    perforationCanvasCtx.fillRect(0, 0, canvasWidth, canvasHeight);
    
    // Redibujar objeto usando la imagen correcta según la cara
    const imagenAUsar = obj._imagenCara || 
                        (obj.cara === 'A' ? imageCaraA : (obj.cara === 'B' ? imageCaraB : null)) ||
                        image;
    
    if (imagenAUsar && imagenAUsar.complete && imagenAUsar.naturalWidth > 0) {
      perforationCanvasCtx.drawImage(
        imagenAUsar,
        obj.minX, obj.minY, obj.width, obj.height,  // Región de la imagen
        0, 0, canvasWidth, canvasHeight              // Destino en canvas (1:1)
      );
    }
    
    // Borde
    perforationCanvasCtx.strokeStyle = '#dee2e6';
    perforationCanvasCtx.lineWidth = 1;
    perforationCanvasCtx.strokeRect(0, 0, canvasWidth, canvasHeight);
    
    // Contorno del objeto (si existe) - SIMPLIFICADO PARA ESCALA 1:1
    if (obj.metricas?._contour_data?.points) {
      const contorno = obj.metricas._contour_data.points;
      perforationCanvasCtx.strokeStyle = 'rgba(0, 255, 0, 0.3)';
      perforationCanvasCtx.lineWidth = 1;
      perforationCanvasCtx.beginPath();
      
      const getX = (p) => p.x !== undefined ? p.x : p[0];
      const getY = (p) => p.y !== undefined ? p.y : p[1];
      
      if (contorno.length > 0) {
        // Escala 1:1: solo restar offset, sin multiplicar por zoom
        const x0 = getX(contorno[0]) - obj.minX;
        const y0 = getY(contorno[0]) - obj.minY;
        perforationCanvasCtx.moveTo(x0, y0);
        
        for (let i = 1; i < contorno.length; i++) {
          const xi = getX(contorno[i]) - obj.minX;
          const yi = getY(contorno[i]) - obj.minY;
          perforationCanvasCtx.lineTo(xi, yi);
        }
        perforationCanvasCtx.closePath();
      }
      perforationCanvasCtx.stroke();
    }
    
    // ============================================================================
    // NUEVO: Dibujar TODOS los trazados completados
    // ============================================================================
    trazadosPerforaciones.forEach((trazado, index) => {
      // ADR-009: candidatos auto-detectados se distinguen (ámbar, discontinuo).
      const esCandidato = trazado.tipo === 'candidato';
      const color = esCandidato ? '#e69500'
                  : (trazado.tipo === 'perforacion' ? '#0066cc' : '#28a745');

      // Convertir puntos
      const canvasPoints = trazado.puntos.map(pt =>
        UtilityHelpers.imageToPerforationCanvasCoords(pt.x, pt.y)
      );

      if (canvasPoints.length < 3) return;

      // NO dibujar relleno - solo borde (sólido para P/H confirmados, discontinuo
      // para candidatos sin confirmar).
      perforationCanvasCtx.strokeStyle = color;
      perforationCanvasCtx.lineWidth = 2;
      perforationCanvasCtx.setLineDash(esCandidato ? [5, 4] : []);
      perforationCanvasCtx.beginPath();
      perforationCanvasCtx.moveTo(canvasPoints[0].x, canvasPoints[0].y);
      for (let i = 1; i < canvasPoints.length; i++) {
        perforationCanvasCtx.lineTo(canvasPoints[i].x, canvasPoints[i].y);
      }
      perforationCanvasCtx.closePath();
      perforationCanvasCtx.stroke();
      perforationCanvasCtx.setLineDash([]);

      // Etiqueta semi-transparente en una esquina externa (valores fijos 1:1)
      const centroide = calcularCentroidePoligono(canvasPoints);
      const etiqueta = trazado._displayLabel || (esCandidato ? `?${index + 1}`
                       : (trazado.tipo === 'perforacion' ? `P${index + 1}` : `H${index + 1}`));
      const fontSize = 10;
      
      // Encontrar punto más alejado del centro (para poner etiqueta afuera)
      let maxDist = 0;
      let farPoint = canvasPoints[0];
      canvasPoints.forEach(pt => {
        const dist = Math.sqrt((pt.x - centroide.x)**2 + (pt.y - centroide.y)**2);
        if (dist > maxDist) {
          maxDist = dist;
          farPoint = pt;
        }
      });
      
      // Posicionar etiqueta 5 píxeles afuera del punto más alejado (valores fijos 1:1)
      const dx = farPoint.x - centroide.x;
      const dy = farPoint.y - centroide.y;
      const dist = Math.sqrt(dx*dx + dy*dy);
      const offset = 8; // 8 píxeles hacia afuera
      
      const labelX = dist > 0 ? farPoint.x + (dx/dist) * offset : farPoint.x;
      const labelY = dist > 0 ? farPoint.y + (dy/dist) * offset : farPoint.y - offset;
      
      perforationCanvasCtx.font = `bold ${fontSize}px Arial`;
      const textWidth = perforationCanvasCtx.measureText(etiqueta).width;
      const padding = 2;
      
      // Fondo blanco semi-transparente (70% opacidad)
      perforationCanvasCtx.fillStyle = 'rgba(255, 255, 255, 0.7)';
      perforationCanvasCtx.fillRect(
        labelX - textWidth / 2 - padding,
        labelY - fontSize / 2 - padding,
        textWidth + padding * 2,
        fontSize + padding * 2
      );
      
      // Texto
      perforationCanvasCtx.fillStyle = color;
      perforationCanvasCtx.textAlign = 'center';
      perforationCanvasCtx.textBaseline = 'middle';
      perforationCanvasCtx.fillText(etiqueta, labelX, labelY);
    });
    
    // ============================================================================
    // NUEVO: Dibujar polígono TEMPORAL esperando clasificación (amarillo)
    // ============================================================================
    if (poligonoTemporal && poligonoTemporal.puntos.length > 0) {
      const canvasPoints = poligonoTemporal.puntos.map(pt => 
        UtilityHelpers.imageToPerforationCanvasCoords(pt.x, pt.y)
      );
      
      if (canvasPoints.length >= 3) {
        // Solo borde amarillo grueso (sin relleno) - valores fijos 1:1
        perforationCanvasCtx.strokeStyle = '#ffc107';
        perforationCanvasCtx.lineWidth = 3;
        perforationCanvasCtx.beginPath();
        perforationCanvasCtx.moveTo(canvasPoints[0].x, canvasPoints[0].y);
        for (let i = 1; i < canvasPoints.length; i++) {
          perforationCanvasCtx.lineTo(canvasPoints[i].x, canvasPoints[i].y);
        }
        perforationCanvasCtx.closePath();
        perforationCanvasCtx.stroke();
        
        // Etiqueta "?" semi-transparente en esquina (valores fijos 1:1)
        const centroide = calcularCentroidePoligono(canvasPoints);
        const fontSize = 11;
        
        // Posicionar 8px arriba del punto más alto
        const minY = Math.min(...canvasPoints.map(p => p.y));
        const labelY = minY - 8;
        
        perforationCanvasCtx.font = `bold ${fontSize}px Arial`;
        const textWidth = perforationCanvasCtx.measureText('?').width;
        const padding = 2;
        
        // Fondo blanco semi-transparente (70% opacidad)
        perforationCanvasCtx.fillStyle = 'rgba(255, 255, 255, 0.7)';
        perforationCanvasCtx.fillRect(
          centroide.x - textWidth / 2 - padding,
          labelY - fontSize / 2 - padding,
          textWidth + padding * 2,
          fontSize + padding * 2
        );
        
        // Texto "?"
        perforationCanvasCtx.fillStyle = '#ffc107';
        perforationCanvasCtx.textAlign = 'center';
        perforationCanvasCtx.textBaseline = 'middle';
        perforationCanvasCtx.fillText('?', centroide.x, labelY);
        
        console.log(`✨ Polígono temporal dibujado (${canvasPoints.length} puntos) - Esperando clasificación`);
      }
    }
    
    // ============================================================================
    // Dibujar polígono ACTUAL siendo trazado (en progreso)
    // ============================================================================
    if (perforationPolygonPoints.length > 0) {
      const color = '#6c757d'; // Gris neutro - no sabemos el tipo todavía
      
      // Convertir puntos de imagen a canvas ampliado
      const canvasPoints = perforationPolygonPoints.map(pt => 
        UtilityHelpers.imageToPerforationCanvasCoords(pt.x, pt.y)
      );
      
      // Dibujar líneas punteadas MÁS DELGADAS (valores fijos para escala 1:1)
      perforationCanvasCtx.strokeStyle = '#ff0000'; // Rojo
      perforationCanvasCtx.lineWidth = 1.5; // Más delgado (era 2)
      perforationCanvasCtx.setLineDash([6, 4]);
      perforationCanvasCtx.beginPath();
      
      if (canvasPoints.length > 0) {
        perforationCanvasCtx.moveTo(canvasPoints[0].x, canvasPoints[0].y);
        for (let i = 1; i < canvasPoints.length; i++) {
          perforationCanvasCtx.lineTo(canvasPoints[i].x, canvasPoints[i].y);
        }
      }
      perforationCanvasCtx.stroke();
      perforationCanvasCtx.setLineDash([]);
      
      // Dibujar puntos MÁS PEQUEÑOS con etiquetas más alejadas y transparentes
      const pointRadius = 3; // 3px (OK)
      const fontSize = 9; // Más pequeño (era 10)
      const labelOffset = 14; // Más alejado (era 8)
      
      canvasPoints.forEach((pt, i) => {
        // Círculo del punto - ROJO SIN CONTORNO ✅
        perforationCanvasCtx.fillStyle = '#ff0000'; // Rojo (era color gris)
        perforationCanvasCtx.beginPath();
        perforationCanvasCtx.arc(pt.x, pt.y, pointRadius, 0, Math.PI * 2);
        perforationCanvasCtx.fill();
        // ✅ SIN BORDE (eliminado strokeStyle y stroke)
        
        // Calcular posición EXTERNA para la etiqueta
        const centroide = calcularCentroidePoligono(canvasPoints);
        const dx = pt.x - centroide.x;
        const dy = pt.y - centroide.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        
        // Normalizar y escalar hacia afuera
        let labelX = pt.x;
        let labelY = pt.y;
        if (dist > 0) {
          labelX = pt.x + (dx / dist) * labelOffset;
          labelY = pt.y + (dy / dist) * labelOffset;
        } else {
          labelY = pt.y - labelOffset; // Si está en el centro, poner arriba
        }
        
        // Etiqueta MÁS PEQUEÑA Y MÁS TRANSPARENTE ✅
        const label = (i + 1).toString();
        perforationCanvasCtx.font = `bold ${fontSize}px Arial`;
        perforationCanvasCtx.textAlign = 'center';
        perforationCanvasCtx.textBaseline = 'middle';
        const metrics = perforationCanvasCtx.measureText(label);
        const padding = 2;
        
        // Fondo MÁS TRANSPARENTE ✅ (era 0.7, ahora 0.5)
        perforationCanvasCtx.fillStyle = 'rgba(255, 255, 255, 0.5)';
        perforationCanvasCtx.fillRect(
          labelX - metrics.width/2 - padding,
          labelY - fontSize/2 - padding,
          metrics.width + padding * 2,
          fontSize + padding * 2
        );
        
        // Texto de la etiqueta - MÁS TRANSPARENTE ✅
        perforationCanvasCtx.fillStyle = 'rgba(255, 0, 0, 0.7)'; // Rojo con 70% opacidad (era color gris opaco)
        perforationCanvasCtx.fillText(label, labelX, labelY);
      });
    }
    
    // B: Línea guía en vivo desde el último punto hasta el cursor
    if (isDrawingPerforationPolygon && perforationPolygonPoints.length > 0 && perforationMousePos) {
      const lastPt = perforationPolygonPoints[perforationPolygonPoints.length - 1];
      const lastCanvas = UtilityHelpers.imageToPerforationCanvasCoords(lastPt.x, lastPt.y);
      perforationCanvasCtx.save();
      perforationCanvasCtx.strokeStyle = 'rgba(255, 60, 60, 0.55)';
      perforationCanvasCtx.lineWidth = 1.5;
      perforationCanvasCtx.setLineDash([5, 4]);
      perforationCanvasCtx.beginPath();
      perforationCanvasCtx.moveTo(lastCanvas.x, lastCanvas.y);
      perforationCanvasCtx.lineTo(perforationMousePos.x, perforationMousePos.y);
      perforationCanvasCtx.stroke();
      perforationCanvasCtx.setLineDash([]);
      // Retículo en el cursor
      perforationCanvasCtx.strokeStyle = 'rgba(255, 60, 60, 0.7)';
      perforationCanvasCtx.lineWidth = 1;
      const r = 5;
      perforationCanvasCtx.beginPath();
      perforationCanvasCtx.arc(perforationMousePos.x, perforationMousePos.y, r, 0, Math.PI * 2);
      perforationCanvasCtx.stroke();
      perforationCanvasCtx.restore();
    }

    // Actualizar contador
    const pointCountSpan = document.getElementById('perforationPointCount');
    if (pointCountSpan) {
      pointCountSpan.textContent = perforationPolygonPoints.length.toString();
    }
  }


  /**
   * Iniciar trazado de polígono de perforación
   */
  /**
   * Activa o desactiva el modo "detección por punto".
   * Cuando está activo, el siguiente clic en el perforationCanvas lanza
   * detectarPhDesdeUnPunto() en lugar de agregar un vértice al polígono.
   */
  function togglePhPointDetectMode() {
    phPointDetectMode = !phPointDetectMode;
    const btn = document.getElementById('phDetectarPorPuntoBtn');
    if (btn) {
      btn.style.background = phPointDetectMode ? '#e65100' : 'transparent';
      btn.style.color      = phPointDetectMode ? 'white'   : '#e65100';
    }
    if (perforationCanvas) {
      perforationCanvas.style.cursor = phPointDetectMode ? 'cell' : 'crosshair';
    }
    UtilityHelpers.setStatus(
      phPointDetectMode
        ? 'Modo detección por punto activo — haga clic dentro de la P/H para detectar su contorno automáticamente.'
        : 'Modo polígono activo — haga clic para agregar puntos al contorno.',
      false
    );
  }

  /**
   * Detecta el contorno de una P/H a partir del punto (canvasX, canvasY) en
   * coordenadas internas del perforationCanvas (ya corregidas por CSS scale).
   * Usa el endpoint Python /api/ph/detect-at-point (flood fill + OpenCV).
   * El contorno resultante se convierte a coordenadas de imagen (suma el offset
   * del objeto al canvas) y se añade a trazadosPerforaciones para ser procesado
   * por el flujo normal de métricas.
   */
  async function detectarPhDesdeUnPunto(canvasX, canvasY) {
    if (!selectedObjectForPerforation || !perforationCanvas) return;
    if (phPointDetectActive) return;
    if (!window.PythonBridge?.isAvailable()) {
      toast.warning('El servidor Python no está disponible. Use el modo polígono manual.');
      return;
    }

    phPointDetectActive = true;
    UtilityHelpers.setStatus('🔍 Detectando contorno automáticamente...', false);

    try {
      const imageDataURL = perforationCanvas.toDataURL('image/png');
      const result = await window.PythonBridge.ph.detectAtPoint(
        imageDataURL,
        Math.round(canvasX),
        Math.round(canvasY),
        30
      );

      if (!result || result.status !== 'ok' ||
          !Array.isArray(result.points) || result.points.length < 3) {
        toast.warning(
          result?.message ||
          'No se detectó contorno en ese punto. Haga clic más al centro de la P/H.'
        );
        UtilityHelpers.setStatus('Haga clic en el interior de la P/H para detectar su contorno.', false);
        return;
      }

      // Convertir puntos [canvas] → [imagen] sumando el offset del objeto
      const puntos = result.points.map(([cx, cy]) => ({
        x: cx + perforationCanvasOffsetX,
        y: cy + perforationCanvasOffsetY,
      }));

      // Registrar como nuevo trazado (mismo flujo que polígono manual)
      contadorTrazados++;
      trazadosPerforaciones.push({
        id:        contadorTrazados,
        tipo:      perforationSelectionType,
        puntos,
        timestamp: Date.now(),
        metodo:    'auto_punto',
      });

      actualizarListaTrazados();
      redibujarPoligonoEnCanvasAmpliado();

      const tipoTexto = perforationSelectionType === 'perforacion' ? 'Perforación' : 'Horadación';
      UtilityHelpers.setStatus(
        `${tipoTexto} detectada (${puntos.length} puntos). ` +
        'Puede seguir marcando o pulsar "Finalizar y Aplicar".',
        false
      );

    } catch (err) {
      console.error('[detectarPhDesdeUnPunto]', err);
      toast.warning('Error al detectar contorno. Verifique que el servidor Python esté activo.');
      UtilityHelpers.setStatus('Error en detección automática.', true);
    } finally {
      phPointDetectActive = false;
    }
  }

  /**
   * Detección IA automática de P/H (multi-semilla) sobre el objeto activo.
   * Recorre una malla de puntos internos y usa /api/ph/detect-at-point para
   * proponer contornos. Los candidatos se deduplican por centro/área.
   */
  async function detectarPhAutomatico() {
    if (!selectedObjectForPerforation || !perforationCanvas) return;
    if (phPointDetectActive) return;
    if (!window.PythonBridge?.isAvailable()) {
      toast.warning('El servidor Python no está disponible.');
      return;
    }

    phPointDetectMode = false;
    phPointDetectActive = true;

    const pointBtn = document.getElementById('phDetectarPorPuntoBtn');
    if (pointBtn) {
      pointBtn.style.background = 'transparent';
      pointBtn.style.color = '#e65100';
    }

    try {
      const obj = selectedObjectForPerforation;
      const imageDataURL = perforationCanvas.toDataURL('image/png');
      const canvasW = perforationCanvas.width;
      const canvasH = perforationCanvas.height;
      const areaObjPx = parseFloat(obj.metricas?.area_real || obj.metricas?.area || 0) || (canvasW * canvasH);

      const profileResolved = phAutoProfileMode === 'auto'
        ? getPhAutoDetectProfile(areaObjPx)
        : {
            key: phAutoProfileMode,
            cfg: PH_AUTO_DETECT_PROFILES[phAutoProfileMode] || getPhAutoDetectProfile(areaObjPx).cfg,
          };
      const phAutoProfile = profileResolved.key;
      const phCfg = profileResolved.cfg;

      const sensitivity = Math.max(0.7, Math.min(1.6, Number(phAutoSensitivity) || 1.0));
      const gridDivisor = Math.max(4, phCfg.gridDivisor * sensitivity);
      const autoTolerance = Math.max(14, Math.min(38, Math.round(phCfg.tolerance + (sensitivity - 1.0) * 4)));
      const autoMinAreaPx = Math.max(6, Math.round(phCfg.minAreaPx / sensitivity));
      const autoMaxAreaRatio = Math.max(0.15, Math.min(0.55, phCfg.maxAreaRatio + (sensitivity - 1.0) * 0.08));
      const autoMaxCandidates = Math.max(8, Math.round(phCfg.maxCandidates * sensitivity));
      const profileLabel = phAutoProfileMode === 'auto' ? `${phAutoProfile}/auto` : `${phAutoProfile}/manual`;

      const contour = obj.metricas?._contour_data?.points || [];
      const getX = (p) => p?.x !== undefined ? p.x : p?.[0];
      const getY = (p) => p?.y !== undefined ? p.y : p?.[1];

      const pointInPolygon = (x, y, poly) => {
        if (!Array.isArray(poly) || poly.length < 3) return true;
        let inside = false;
        for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
          const xi = getX(poly[i]);
          const yi = getY(poly[i]);
          const xj = getX(poly[j]);
          const yj = getY(poly[j]);
          if (!Number.isFinite(xi) || !Number.isFinite(yi) || !Number.isFinite(xj) || !Number.isFinite(yj)) continue;
          const intersects = ((yi > y) !== (yj > y)) &&
            (x < ((xj - xi) * (y - yi)) / ((yj - yi) || 1e-9) + xi);
          if (intersects) inside = !inside;
        }
        return inside;
      };

      const step = Math.max(18, Math.min(72, Math.round(Math.min(canvasW, canvasH) / gridDivisor)));
      const margin = Math.max(10, Math.round(step * 0.6));
      const seeds = [];
      for (let y = margin; y < canvasH - margin; y += step) {
        for (let x = margin; x < canvasW - margin; x += step) {
          const imgX = x + perforationCanvasOffsetX;
          const imgY = y + perforationCanvasOffsetY;
          if (pointInPolygon(imgX, imgY, contour)) {
            seeds.push({ x, y });
          }
        }
      }

      if (!seeds.length) {
        toast.warning('No se generaron semillas internas para detección automática.');
        UtilityHelpers.setStatus('No fue posible iniciar detección IA automática.', true);
        return;
      }

      UtilityHelpers.setStatus(
        `✦ Detección IA Auto (${profileLabel}, sens ${sensitivity.toFixed(2)}x): evaluando hasta ${Math.min(autoMaxCandidates * 3, seeds.length)} semillas...`,
        false
      );

      let candidatos = [];
      let autoResp = null;
      try {
        autoResp = await window.PythonBridge.ph.detectAuto(imageDataURL, seeds, {
          tolerance: autoTolerance,
          minAreaPx: autoMinAreaPx,
          maxAreaRatio: autoMaxAreaRatio,
          maxCandidates: autoMaxCandidates,
        });
      } catch (errAuto) {
        // Compatibilidad: backend antiguo sin endpoint batch => usar fallback por semilla.
        if (errAuto?.status === 404) {
          console.warn('[detectarPhAutomatico] /ph/detect-auto no disponible, activando fallback por semilla.');
          UtilityHelpers.setStatus('Detección IA batch no disponible en backend actual. Usando fallback por semilla...', false);
        } else {
          throw errAuto;
        }
      }

      if (autoResp && autoResp.status === 'ok' && Array.isArray(autoResp.candidates)) {
        candidatos = autoResp.candidates
          .filter(c => Array.isArray(c.points) && c.points.length >= 4)
          .map(c => ({
            puntos: c.points.map(([cx, cy]) => ({
              x: cx + perforationCanvasOffsetX,
              y: cy + perforationCanvasOffsetY,
            })),
            areaPx: parseFloat(c.area_px || 0) || 0,
            tipo: (c.auto_tipo === 'perforacion' || c.auto_tipo === 'horadacion')
              ? c.auto_tipo
              : 'horadacion',
          }));
      }

      // Fallback de compatibilidad: si detectAuto no responde candidatos, usar método previo por semilla.
      if (!candidatos.length) {
        const vistos = [];
        const maxCalls = Math.min(Math.max(18, autoMaxCandidates * 2), seeds.length);
        for (let i = 0; i < maxCalls; i++) {
          const seed = seeds[i];
          const result = await window.PythonBridge.ph.detectAtPoint(
            imageDataURL,
            Math.round(seed.x),
            Math.round(seed.y),
            autoTolerance
          );
          if (!result || result.status !== 'ok' || !Array.isArray(result.points) || result.points.length < 4) {
            continue;
          }
          const areaPx = parseFloat(result.area_px || 0);
          if (!Number.isFinite(areaPx) || areaPx < autoMinAreaPx || areaPx > areaObjPx * autoMaxAreaRatio) {
            continue;
          }
          const centroid = Array.isArray(result.centroid) ? result.centroid : [seed.x, seed.y];
          const already = vistos.some(v => {
            const d = Math.hypot(v.cx - centroid[0], v.cy - centroid[1]);
            const ar = areaPx > 0 ? Math.abs(v.area - areaPx) / areaPx : 1;
            return d < 14 && ar < 0.35;
          });
          if (already) continue;

          const puntos = result.points.map(([cx, cy]) => ({
            x: cx + perforationCanvasOffsetX,
            y: cy + perforationCanvasOffsetY,
          }));
          const circularity = parseFloat(result.circularity || 0);
          const tipoAuto = (areaPx < areaObjPx * 0.06 && circularity > 0.55) ? 'perforacion' : 'horadacion';

          vistos.push({ cx: centroid[0], cy: centroid[1], area: areaPx });
          candidatos.push({ puntos, areaPx, tipo: tipoAuto });
        }
      }

      if (!candidatos.length) {
        toast.warning('No se detectaron candidatos IA. Puede usar trazado manual o detección por punto.');
        UtilityHelpers.setStatus('Detección IA Auto finalizada sin candidatos.', false);
        return;
      }

      for (const cand of candidatos) {
        contadorTrazados++;
        trazadosPerforaciones.push({
          id: contadorTrazados,
          tipo: cand.tipo,
          puntos: cand.puntos,
          timestamp: Date.now(),
          metodo: 'auto_malla_ia',
          area_px: cand.areaPx,
        });
      }

      actualizarListaTrazados();
      redibujarPoligonoEnCanvasAmpliado();

      const nPerf = candidatos.filter(c => c.tipo === 'perforacion').length;
      const nHor = candidatos.length - nPerf;
      toast.success(`Detección IA Auto: ${candidatos.length} candidatos (${nPerf} P, ${nHor} H).`);
      UtilityHelpers.setStatus(
        `Detección IA Auto completada: ${candidatos.length} candidatos añadidos. Revise/edite y pulse "Finalizar y Aplicar".`,
        false
      );
    } catch (err) {
      console.error('[detectarPhAutomatico]', err);
      toast.warning('Error en detección IA automática. Intente detección por punto o trazado manual.');
      UtilityHelpers.setStatus('Error en detección IA automática.', true);
    } finally {
      phPointDetectActive = false;
    }
  }

  function iniciarTrazadoPoligonoPerforacion(mouseX, mouseY) {
    if (!selectedObjectForPerforation) {
      // Intentar seleccionar objeto primero
      const obj = seleccionarObjetoParaPerforation(mouseX, mouseY);
      if (!obj) return;
      
      // Inicializar trazado después de seleccionar objeto
      UtilityHelpers.setStatus(`Objeto seleccionado. Haga clic para trazar puntos del polígono. Doble clic para cerrar.`, false);
      return;
    }
    
    const imgCoords = UtilityHelpers.canvasToImageCoords(mouseX, mouseY);
    
    // Verificar que el punto está dentro del objeto seleccionado
    if (imgCoords.x < selectedObjectForPerforation.minX || 
        imgCoords.x > selectedObjectForPerforation.maxX ||
        imgCoords.y < selectedObjectForPerforation.minY || 
        imgCoords.y > selectedObjectForPerforation.maxY) {
      
      UtilityHelpers.setStatus('El polígono debe estar dentro del objeto seleccionado.', true);
      return;
    }
    
    // Añadir punto al polígono
    perforationPolygonPoints.push({ x: imgCoords.x, y: imgCoords.y });
    isDrawingPerforationPolygon = true;
    
    const numPuntos = perforationPolygonPoints.length;
    const tipoTexto = perforationSelectionType === 'perforacion' ? 'perforación' : 'horadación';
    
    if (numPuntos === 1) {
      UtilityHelpers.setStatus(`Punto 1 marcado. Continue trazando el polígono de ${tipoTexto}. Doble clic para cerrar.`, false);
    } else {
      UtilityHelpers.setStatus(`${numPuntos} puntos. Doble clic o presione Enter para cerrar el polígono.`, false);
    }
    
    UtilityHelpers.redrawCanvas();
  }

  /**
   * Cerrar polígono actual y MOSTRAR DIÁLOGO de clasificación (MEJORADO)
   */
  function cerrarPoligonoPerforacion() {
    if (!isDrawingPerforationPolygon || perforationPolygonPoints.length < 3) {
      if (perforationPolygonPoints.length > 0 && perforationPolygonPoints.length < 3) {
        toast.warning('El polígono debe tener al menos 3 puntos.');
      }
      return;
    }
    
    console.log('✅ Polígono cerrado con', perforationPolygonPoints.length, 'puntos - Esperando clasificación');
    
    // Guardar polígono temporalmente
    poligonoTemporal = {
      puntos: [...perforationPolygonPoints] // Copia del array
    };
    
    // Resetear estado de dibujo
    perforationPolygonPoints = [];
    isDrawingPerforationPolygon = false;
    perforationPolygonClosed = false;
    
    // Actualizar contador de puntos
    const pointCountSpan = document.getElementById('perforationPointCount');
    if (pointCountSpan) pointCountSpan.textContent = '0';
    
    // A: Auto-clasificar si hay tipo pre-seleccionado (modo por defecto)
    if (phAutoClassify) {
      if (perforationSelectionType === 'perforacion') {
        clasificarComoPerforacion();
      } else {
        clasificarComoHoradacion();
      }
      return;
    }

    // Fallback: mostrar diálogo de clasificación manual
    const dialog = document.getElementById('clasificarPoligonoDialog');
    if (dialog) {
      dialog.style.display = 'block';
      UtilityHelpers.setStatus(`Polígono trazado. Seleccione si es PERFORACIÓN o HORADACIÓN.`, false);
    }
    
    // Redibujar canvas para mostrar polígono temporal
    redibujarPoligonoEnCanvasAmpliado();
  }

  /**
   * Clasificar polígono temporal como PERFORACIÓN
   */
  function clasificarComoPerforacion() {
    if (!poligonoTemporal) return;
    
    contadorTrazados++;
    const nuevoTrazado = {
      id: contadorTrazados,
      tipo: 'perforacion',
      puntos: [...poligonoTemporal.puntos],
      timestamp: Date.now()
    };
    
    trazadosPerforaciones.push(nuevoTrazado);
    console.log(`✅ Trazado #${contadorTrazados} clasificado como PERFORACIÓN`);
    
    // Limpiar temporal
    poligonoTemporal = null;
    
    // Ocultar diálogo
    const dialog = document.getElementById('clasificarPoligonoDialog');
    if (dialog) dialog.style.display = 'none';
    
    // Actualizar UI
    actualizarListaTrazados();
    redibujarPoligonoEnCanvasAmpliado();
    
    UtilityHelpers.setStatus(`Perforación agregada. Total: ${trazadosPerforaciones.length}. Puede trazar otro polígono.`, false);
  }

  /**
   * Clasificar polígono temporal como HORADACIÓN
   */
  function clasificarComoHoradacion() {
    if (!poligonoTemporal) return;
    
    contadorTrazados++;
    const nuevoTrazado = {
      id: contadorTrazados,
      tipo: 'horadacion',
      puntos: [...poligonoTemporal.puntos],
      timestamp: Date.now()
    };
    
    trazadosPerforaciones.push(nuevoTrazado);
    console.log(`✅ Trazado #${contadorTrazados} clasificado como HORADACIÓN`);
    
    // Limpiar temporal
    poligonoTemporal = null;
    
    // Ocultar diálogo
    const dialog = document.getElementById('clasificarPoligonoDialog');
    if (dialog) dialog.style.display = 'none';
    
    // Actualizar UI
    actualizarListaTrazados();
    redibujarPoligonoEnCanvasAmpliado();
    
    UtilityHelpers.setStatus(`Horadación agregada. Total: ${trazadosPerforaciones.length}. Puede trazar otro polígono.`, false);
  }

  /**
   * Cancelar clasificación del polígono temporal
   */
  function cancelarClasificacion() {
    console.log(`❌ Clasificación cancelada - polígono descartado`);
    
    // Descartar polígono temporal
    poligonoTemporal = null;
    
    // Ocultar diálogo
    const dialog = document.getElementById('clasificarPoligonoDialog');
    if (dialog) dialog.style.display = 'none';
    
    // Redibujar para eliminar visualización del polígono temporal
    redibujarPoligonoEnCanvasAmpliado();
    
    UtilityHelpers.setStatus(`Polígono descartado. Trace un nuevo polígono.`, false);
  }

  /**
   * Actualizar lista visual de trazados completados
   */
  function recalcularEtiquetasTrazadosPH() {
    let nPerf = 0;
    let nHor = 0;
    let nCand = 0;
    trazadosPerforaciones.forEach(t => {
      if (t.tipo === 'perforacion') {
        nPerf += 1;
        t._displayLabel = `P${nPerf}`;
      } else if (t.tipo === 'candidato') {   // ADR-009: candidato sin tipo aún
        nCand += 1;
        t._displayLabel = `?${nCand}`;
      } else {
        nHor += 1;
        t._displayLabel = `H${nHor}`;
      }
    });
  }

  function actualizarListaTrazados() {
    const panel = document.getElementById('trazadosCompletadosPanel');
    const lista = document.getElementById('listaTrazados');
    const totalSpan = document.getElementById('totalTrazadosCount');
    
    if (!panel || !lista) return;
    
    // Mostrar/ocultar panel según si hay trazados
    if (trazadosPerforaciones.length > 0) {
      recalcularEtiquetasTrazadosPH();
      panel.style.display = 'block';
      
      // Generar HTML de la lista
      lista.innerHTML = trazadosPerforaciones.map(t => {
        // ADR-009: candidatos auto-detectados → controles para confirmar/tipar/descartar.
        if (t.tipo === 'candidato') {
          const conf = (typeof t._confidence === 'number')
            ? ` · conf. ${(t._confidence * 100).toFixed(0)}%${t._confidenceLvl ? ' (' + t._confidenceLvl + ')' : ''}`
            : '';
          return `
            <div style="margin: 3px 0;">
              <div style="display: flex; justify-content: space-between; align-items: center; padding: 5px; background: #fff8ec; border-left: 4px solid #e69500; border-radius: 3px; gap: 6px; flex-wrap: wrap;">
                <span style="font-size: 11px; font-weight: bold; color: #b36b00;">
                  CANDIDATO ${t._displayLabel || ('?' )} <span style="color: #6c757d; font-weight: normal;">(${t.puntos.length} pts${conf})</span>
                </span>
                <span style="display:flex;gap:4px;align-items:center;">
                  <button onclick="confirmarCandidatoPH(${t.id}, 'perforacion')" title="Confirmar como perforación" style="padding: 2px 8px; background: #0066cc; color: white; border: none; border-radius: 3px; cursor: pointer; font-size: 10px;">Perforación</button>
                  <button onclick="confirmarCandidatoPH(${t.id}, 'horadacion')" title="Confirmar como horadación" style="padding: 2px 8px; background: #28a745; color: white; border: none; border-radius: 3px; cursor: pointer; font-size: 10px;">Horadación</button>
                  <button onclick="descartarCandidatoPH(${t.id})" title="Descartar candidato" style="padding: 2px 8px; background: #6c757d; color: white; border: none; border-radius: 3px; cursor: pointer; font-size: 10px;">Descartar</button>
                </span>
              </div>
            </div>
          `;
        }
        const color = t.tipo === 'perforacion' ? '#0066cc' : '#28a745';
        const icono = t.tipo === 'perforacion' ? '' : '';
        const nombre = t.tipo === 'perforacion' ? 'PERFORACIÓN' : 'HORADACIÓN';
        const etiqueta = t._displayLabel || (t.tipo === 'perforacion' ? 'P?' : 'H?');

        return `
          <div style="margin: 3px 0;">
            <div style="display: flex; justify-content: space-between; align-items: center; padding: 5px; background: white; border-left: 4px solid ${color}; border-radius: 3px;">
              <span style="font-size: 11px; font-weight: bold; color: ${color};">
                ${icono} ${nombre} ${etiqueta} <span style="color: #6c757d;">(${t.puntos.length} pts)</span>
              </span>
              <span style="display:flex;gap:4px;align-items:center;">
                <button onclick="eliminarTrazado(${t.id})" style="padding: 2px 8px; background: #dc3545; color: white; border: none; border-radius: 3px; cursor: pointer; font-size: 10px;"></button>
              </span>
            </div>
          </div>
        `;
      }).join('');
      
      // Actualizar contador total
      if (totalSpan) totalSpan.textContent = trazadosPerforaciones.length.toString();
      
    } else {
      panel.style.display = 'none';
      if (totalSpan) totalSpan.textContent = '0';
    }
  }

  /**
   * Eliminar un trazado específico
   */
  function eliminarTrazado(id) {
    const index = trazadosPerforaciones.findIndex(t => t.id === id);
    if (index !== -1) {
      const trazado = trazadosPerforaciones[index];
      trazadosPerforaciones.splice(index, 1);
      recalcularEtiquetasTrazadosPH();
      
      console.log(`🗑️ Trazado #${id} eliminado`);
      
      // Actualizar UI
      actualizarListaTrazados();
      redibujarPoligonoEnCanvasAmpliado();
      
      const tipoNombre = trazado.tipo === 'perforacion' ? 'Perforación' : 'Horadación';
      const etiqueta = trazado._displayLabel || (trazado.tipo === 'perforacion' ? 'P?' : 'H?');
      UtilityHelpers.setStatus(`${tipoNombre} ${etiqueta} eliminada. Total: ${trazadosPerforaciones.length}`, false);
    }
  }
  // C: Exponer a scope global para los onclick inlineados en actualizarListaTrazados()
  window.eliminarTrazado = eliminarTrazado;

  /**
   * ADR-009 — Confirmar un candidato P/H auto-detectado, asignándole tipo.
   * El candidato pasa a 'perforacion'|'horadacion' y, al finalizar los trazados,
   * se guarda como P/H (recalcula área neta). Sólo entonces afecta métricas.
   */
  function confirmarCandidatoPH(id, tipo) {
    const t = trazadosPerforaciones.find(x => x.id === id);
    if (!t || t.tipo !== 'candidato') return;
    if (tipo !== 'perforacion' && tipo !== 'horadacion') return;
    t.tipo = tipo;
    t.metodo = 'auto-confirmado';
    recalcularEtiquetasTrazadosPH();
    actualizarListaTrazados();
    redibujarPoligonoEnCanvasAmpliado();
    sincronizarCandidatosPHEnObjeto();
    const nombre = tipo === 'perforacion' ? 'Perforación' : 'Horadación';
    UtilityHelpers.setStatus(`Candidato confirmado como ${nombre}. Finalice los trazados para aplicarlo al objeto.`, false);
  }
  window.confirmarCandidatoPH = confirmarCandidatoPH;

  /**
   * ADR-009 — Descartar un candidato P/H (no es una P/H real). Se elimina del
   * trazado y del objeto para que el chip deje de contarlo.
   */
  function descartarCandidatoPH(id) {
    const index = trazadosPerforaciones.findIndex(x => x.id === id);
    if (index === -1 || trazadosPerforaciones[index].tipo !== 'candidato') return;
    trazadosPerforaciones.splice(index, 1);
    recalcularEtiquetasTrazadosPH();
    actualizarListaTrazados();
    redibujarPoligonoEnCanvasAmpliado();
    sincronizarCandidatosPHEnObjeto();
    const rest = trazadosPerforaciones.filter(t => t.tipo === 'candidato').length;
    UtilityHelpers.setStatus(`Candidato descartado. Candidatos restantes: ${rest}.`, false);
  }
  window.descartarCandidatoPH = descartarCandidatoPH;

  /**
   * ADR-009 — Resincroniza obj.phCandidatos con los candidatos AÚN sin confirmar
   * en el trazado actual, para que el chip §2 refleje confirmaciones/descartes
   * aunque el usuario cierre sin finalizar.
   */
  function sincronizarCandidatosPHEnObjeto() {
    const restantes = trazadosPerforaciones
      .filter(t => t.tipo === 'candidato')
      .map(t => ({
        tipo: 'candidato',
        points: t.puntos.map(p => [p.x, p.y]),
        detection_confidence: t._confidence,
        confidence_level: t._confidenceLvl,
      }));
    if (selectedObjectForPerforation) selectedObjectForPerforation.phCandidatos = restantes;
    if (currentAnalyzedObject && currentAnalyzedObject.obj) {
      currentAnalyzedObject.obj.phCandidatos = restantes;
    }
  }

  /**
   * ADR-009 — Fallback de detección de candidatos P/H para análisis que NO pasaron
   * por el bloque /contour (cacheados, objetos IA/SAM). Si `obj.phCandidatos` ya existe
   * no hace nada. Detecta huecos seedless sobre la imagen cargada y refresca el chip.
   * Fire-and-forget (no bloquea el render). Reversible: si no hay imagen o falla, no-op.
   */
  async function detectarCandidatosPHSiFaltan(obj) {
    if (!obj || Array.isArray(obj.phCandidatos)) return;          // ya resuelto
    if (obj._canonicalRaster) { obj.phCandidatos = []; return; }  // raster 3D: sin P/H reales
    if (!(window.PythonBridge && PythonBridge.isModuleActive('contour'))) return;

    // Resolver la imagen fuente (misma prioridad que el bloque /contour).
    const img = obj._imagenCara ||
      (obj.cara === 'A' ? imageCaraA : (obj.cara === 'B' ? imageCaraB : null)) ||
      image;
    if (!img) return;

    let dataURL = null;
    try {
      if (typeof img.src === 'string' && img.src.startsWith('data:')) {
        dataURL = img.src;
      } else if (img instanceof HTMLImageElement && img.complete && img.naturalWidth > 0) {
        const c = document.createElement('canvas');
        c.width = img.naturalWidth; c.height = img.naturalHeight;
        c.getContext('2d').drawImage(img, 0, 0);
        dataURL = c.toDataURL('image/png');
      } else if (img instanceof HTMLCanvasElement) {
        dataURL = img.toDataURL('image/png');
      }
    } catch (_e) { return; }
    if (!dataURL) return;

    try {
      const r = await PythonBridge.contour.extract(
        dataURL,
        { x: obj.minX || 0, y: obj.minY || 0, w: obj.width || 1, h: obj.height || 1 },
        { subpixel: false, simplify: 2.0 }
      );
      const cands = (r && Array.isArray(r.ph_candidates)) ? r.ph_candidates : [];
      obj.phCandidatos = cands;
      if (currentAnalyzedObject && currentAnalyzedObject.obj === obj) {
        currentAnalyzedObject.obj.phCandidatos = cands;
      }
      // Persistir en la caché para no re-detectar en aperturas futuras.
      if (obj.analisisCached && obj.analisisCached.metricas) {
        obj.analisisCached.metricas.phCandidatos = cands;
      }
      if (cands.length) {
        console.log(`[Python] P/H candidatos seedless (fallback caché/IA): ${cands.length} hueco(s)`);
      }
      // Nudge al organizador (observa #morphologicalMetrics) para reconstruir el chip §2.
      const mm = document.getElementById('morphologicalMetrics');
      if (mm) { const t = document.createComment('adr009-ph-refresh'); mm.appendChild(t); mm.removeChild(t); }
    } catch (_e) {
      console.warn('[Python] detección P/H fallback falló:', _e.message);
    }
  }

  /**
   * Calcular métricas morfológicas completas para una perforación/horadación
   * Similar a calcularMetricasMorfologicas pero optimizado para polígonos trazados manualmente
   * @param {Array} puntos - Puntos del polígono
   * @param {string} tipo - 'perforacion' o 'horadacion'
   * @param {number} id - ID del trazado
   * @param {number} scale - Escala en mm/px para convertir a milímetros
   */
  function calcularMetricasPerforacion(puntos, tipo, id, scale = 1) {
    console.log(`📊 Calculando métricas completas para ${tipo} #${id} (escala: ${scale} mm/px)...`);
    
    if (!puntos || puntos.length < 3) {
      console.warn(`⚠️ Insuficientes puntos para calcular métricas: ${puntos?.length || 0}`);
      return null;
    }
    
    const getX = (p) => p.x !== undefined ? p.x : p[0];
    const getY = (p) => p.y !== undefined ? p.y : p[1];
    
    // 1. MÉTRICAS BÁSICAS (Área, Perímetro, Centroide) - EN PÍXELES PRIMERO
    const areaPx = GeometryPrimitives.calcularAreaShoelace(puntos);
    const area = areaPx * scale * scale; // Convertir a mm²
    
    let perimeterPx = 0;
    for (let i = 0; i < puntos.length; i++) {
      const j = (i + 1) % puntos.length;
      const dx = getX(puntos[j]) - getX(puntos[i]);
      const dy = getY(puntos[j]) - getY(puntos[i]);
      perimeterPx += Math.sqrt(dx * dx + dy * dy);
    }
    const perimeter = perimeterPx * scale; // Convertir a mm
    
    // Centroide área-ponderado (Shoelace)
    let centroid;
    {
      const np = puntos.length;
      let cx = 0, cy = 0, sa = 0;
      for (let i = 0; i < np; i++) {
        const j = (i + 1) % np;
        const cross = getX(puntos[i]) * getY(puntos[j]) - getX(puntos[j]) * getY(puntos[i]);
        sa += cross;
        cx += (getX(puntos[i]) + getX(puntos[j])) * cross;
        cy += (getY(puntos[i]) + getY(puntos[j])) * cross;
      }
      sa /= 2;
      if (Math.abs(sa) > 1e-10) {
        centroid = [cx / (6 * sa), cy / (6 * sa)];
      } else {
        let sumX = 0, sumY = 0;
        for (const p of puntos) { sumX += getX(p); sumY += getY(p); }
        centroid = [sumX / puntos.length, sumY / puntos.length];
      }
    }
    
    // 2. BOUNDING BOX
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const p of puntos) {
      const x = getX(p);
      const y = getY(p);
      if (x < minX) minX = x;
      if (x > maxX) maxX = x;
      if (y < minY) minY = y;
      if (y > maxY) maxY = y;
    }
    const widthPx = maxX - minX;
    const heightPx = maxY - minY;
    const width = widthPx * scale; // Convertir a mm
    const height = heightPx * scale; // Convertir a mm
    
    // 3. ANÁLISIS RADIAL (desde centroide Shoelace) — sobre puntos del polígono
    // radio_maximo y radio_minimo: calcula sobre el Convex Hull para que sean geométricamente exactos.
    // estadísticas (medio, desviación, CV): sobre los puntos del polígono (muestreo uniforme).
    const hullForRadios = GeometryPrimitives.calcularConvexHull(puntos);
    const radiosData = MorphometricMetrics.calcularRadiosExtremos(hullForRadios, centroid, puntos);
    const radioMaximoPx = radiosData.radio_maximo;
    const radioMinimoPx = radiosData.radio_minimo;
    const radioMedioPx  = radiosData.radio_medio;
    const puntoRadioMaximo = radiosData.punto_radio_maximo
      ? [radiosData.punto_radio_maximo[0] ?? radiosData.punto_radio_maximo.x ?? 0,
         radiosData.punto_radio_maximo[1] ?? radiosData.punto_radio_maximo.y ?? 0]
      : [centroid[0], centroid[1]];
    const puntoRadioMinimo = Array.isArray(radiosData.punto_radio_minimo)
      ? radiosData.punto_radio_minimo
      : [centroid[0], centroid[1]];

    // Convertir radios a mm
    const radioMaximo = radioMaximoPx * scale;
    const radioMinimo = radioMinimoPx * scale;
    const radioMedio  = radioMedioPx  * scale;
    const ratioRadios = radiosData.ratio_radios;

    // Desviación estándar de radios (en mm)
    const desviacionRadialPx = radiosData.desviacion_radial;
    const desviacionRadial   = desviacionRadialPx * scale;
    const coeficienteVariacion = radiosData.coeficiente_variacion_radial;
    const regularidadRadial    = radiosData.regularidad_radial;

    // 4. CONVEX HULL (ya calculado arriba para radios)
    const convexHullAreaPx = GeometryPrimitives.calcularAreaShoelace(hullForRadios);
    const convexHullArea = convexHullAreaPx * scale * scale; // Convertir a mm²
    const hullPoints = hullForRadios; // alias para compatibilidad con código posterior
    
    // 5. MÉTRICAS DE FORMA (independientes de escala)
    const circularity = (4 * Math.PI * areaPx) / (perimeterPx * perimeterPx);
    const compactness = (perimeterPx * perimeterPx) / areaPx;
    const solidity = areaPx / convexHullAreaPx;
    const aspectRatio = Math.max(widthPx, heightPx) / Math.min(widthPx, heightPx);
    const convexity = perimeterPx / calcularPerimetroPoligono(hullPoints);
    
    // 6. EJES PRINCIPALES — momentos de inercia de área (PCA real, no bounding box)
    // El bounding box alineado con los ejes de imagen da resultados erróneos para objetos rotados.
    // Se usan los mismos momentos de Green's theorem que calcularEjePrincipal.
    const ejePerfData = MorphometricMetrics.calcularExcentricidad(puntos, centroid);
    const ejeMayor = ejePerfData.eje_mayor * scale; // caliper sobre eje principal (mm)
    const ejeMenor = ejePerfData.eje_menor * scale; // caliper sobre eje secundario (mm)
    const excentricidad = ejePerfData.excentricidad;

    // 7. SHAPE FACTOR, RECTANGULARIDAD, ELONGACIÓN (adimensionales, calculadas en px)
    const shapeFactor    = (perimeterPx * perimeterPx) / (4 * Math.PI * areaPx);
    const rectangularity = areaPx / (widthPx * heightPx);
    const elongation     = Math.abs(1 - (Math.min(widthPx, heightPx) / Math.max(widthPx, heightPx)));

    // 8. DIÁMETROS DE FERET (sobre Convex Hull en px → convertir a mm)
    const feretData      = MorphometricMetrics.calcularDiametroFeret(hullPoints);
    const feretMax       = feretData.feret_max  * scale;
    const feretMin       = feretData.feret_min  * scale;
    const feretRatio     = feretData.feret_ratio;
    const feretAnguloMax = feretData.angulo_feret_max;
    const feretAnguloMin = feretData.angulo_feret_min;

    // 9. CLASIFICACIÓN DE FORMA (simplificada basada en métricas)
    let formaDetectada = 'Irregular';
    let confianza = 0;
    
    if (circularity > 0.85 && regularidadRadial > 80) {
      formaDetectada = 'Circular';
      confianza = Math.min(circularity, regularidadRadial / 100);
    } else if (aspectRatio < 1.3 && regularidadRadial > 70) {
      formaDetectada = 'Subcircular';
      confianza = 0.7;
    } else if (aspectRatio > 1.5 && aspectRatio < 2.5) {
      formaDetectada = 'Ovalada';
      confianza = 0.65;
    } else if (hullPoints.length <= 5 && solidity > 0.9) {
      formaDetectada = 'Poligonal';
      confianza = 0.6;
    }
    
    // 8. RETORNAR MÉTRICAS COMPLETAS
    const metricas = {
      // Básicas (en MM)
      area: parseFloat(area.toFixed(2)),
      perimeter: parseFloat(perimeter.toFixed(2)),
      perimetro: parseFloat(perimeter.toFixed(2)), // Alias para compatibilidad
      centroid: centroid,
      // Campos de centroide como valores escalares independientes para
      // compatibilidad con tablas bifaciales y análisis morfológico que
      // buscan centroide_hull_x/y y centroide_x/y directamente.
      centroide_hull_x: parseFloat(centroid[0].toFixed(2)),
      centroide_hull_y: parseFloat(centroid[1].toFixed(2)),
      centroide_x: parseFloat(centroid[0].toFixed(2)),
      centroide_y: parseFloat(centroid[1].toFixed(2)),
      
      // ✅ VALORES EN PÍXELES (para leyenda del canvas)
      area_real: parseFloat(areaPx.toFixed(2)),
      perimetro_real: parseFloat(perimeterPx.toFixed(2)),
      
      // Dimensiones
      width: parseFloat(width.toFixed(2)),
      height: parseFloat(height.toFixed(2)),
      minX: parseFloat(minX.toFixed(2)),
      maxX: parseFloat(maxX.toFixed(2)),
      minY: parseFloat(minY.toFixed(2)),
      maxY: parseFloat(maxY.toFixed(2)),
      
      // Radios
      radio_maximo: parseFloat(radioMaximo.toFixed(2)),
      radio_minimo: parseFloat(radioMinimo.toFixed(2)),
      radio_medio: parseFloat(radioMedio.toFixed(2)),
      ratio_radios: parseFloat(ratioRadios.toFixed(4)),
      regularidad_radial: parseFloat(regularidadRadial.toFixed(1)),
      desviacion_radial: parseFloat(desviacionRadial.toFixed(2)),
      coeficiente_variacion_radial: parseFloat(coeficienteVariacion.toFixed(1)),
      punto_radio_maximo: puntoRadioMaximo,
      punto_radio_minimo: puntoRadioMinimo,
      
      // Ejes
      eje_mayor: parseFloat(ejeMayor.toFixed(2)),
      eje_menor: parseFloat(ejeMenor.toFixed(2)),
      excentricidad: parseFloat(excentricidad.toFixed(4)),
      
      // Convex Hull
      convexHullArea: parseFloat(convexHullArea.toFixed(2)),
      convexHullPoints: hullPoints,
      
      // Forma
      circularity: parseFloat(circularity.toFixed(4)),
      compactness: parseFloat(compactness.toFixed(2)),
      solidity: parseFloat(solidity.toFixed(4)),
      aspect_ratio: parseFloat(aspectRatio.toFixed(2)),
      convexity: parseFloat(convexity.toFixed(4)),
      shape_factor: parseFloat(shapeFactor.toFixed(4)),
      rectangularity: parseFloat(rectangularity.toFixed(4)),
      elongation: parseFloat(elongation.toFixed(4)),

      // Feret (en mm)
      feret_max: parseFloat(feretMax.toFixed(2)),
      feret_min: parseFloat(feretMin.toFixed(2)),
      feret_ratio: parseFloat(feretRatio.toFixed(4)),
      feret_angulo_max: parseFloat(feretAnguloMax.toFixed(1)),
      feret_angulo_min: parseFloat(feretAnguloMin.toFixed(1)),

      // Clasificación
      forma_detectada: formaDetectada,
      forma_confianza: parseFloat(confianza.toFixed(2)),
      
      // Contorno
      contour_points: puntos.length,
      vertices_aproximados: hullPoints.length
    };
    
    console.log(`✅ Métricas calculadas para ${tipo} #${id}:`, {
      area: metricas.area,
      forma: metricas.forma_detectada,
      circularity: metricas.circularity,
      regularidad: metricas.regularidad_radial
    });
    
    return metricas;
  }

  /**
   * Calcular perímetro de un polígono
   */
  function calcularPerimetroPoligono(puntos) {
    const getX = (p) => p.x !== undefined ? p.x : p[0];
    const getY = (p) => p.y !== undefined ? p.y : p[1];
    
    let perimeter = 0;
    for (let i = 0; i < puntos.length; i++) {
      const j = (i + 1) % puntos.length;
      const dx = getX(puntos[j]) - getX(puntos[i]);
      const dy = getY(puntos[j]) - getY(puntos[i]);
      perimeter += Math.sqrt(dx * dx + dy * dy);
    }
    return perimeter;
  }

  /**
   * Calcula las áreas efectivas de P/H con deduplicación por contención.
   * Caso arquetípico: orificio cónico — la perforación (canal) está inscrita
   * dentro de la horadación (depresión exterior). Sumar ambas áreas sería
   * double-counting de la misma pérdida de masa.
   *
   * Criterio de contención: área(P) < área(H)  AND  centroide de P dentro del polígono H.
   *
   * @param {Array} perforaciones   Array de objetos perforación    {puntos, metricas?, area?, id?}
   * @param {Array} horadaciones    Array de objetos horadación     {puntos, metricas?, area?, id?}
   * @returns {{
   *   areaTotalPerforaciones: number,   // suma excluyendo perforaciones contenidas
   *   areaTotalHoradaciones:  number,
   *   areaTotalPH:            number,   // sin double-counting
   *   numContenidas:          number,
   *   relaciones:             Array<{perforacion_id, horadacion_id}>,
   *   idxContenidas:          Set<number>
   * }}
   */
  function calcularAreaEfectivaPH(perforaciones, horadaciones) {
    // Factor de conversión px²→mm² (usa la escala global del sistema)
    const _scaleSq = (typeof scale !== 'undefined' && scale > 0) ? scale * scale : 1;

    const _getA = (ph) => {
      // Prioridad 1: metricas.area ya en mm² (path finalizarTodosTrazados con calcularMetricasPerforacion)
      if (ph.metricas?.area) return parseFloat(ph.metricas.area) || 0;
      // Prioridad 2: metricas.area_real en px² (path procesarPerforacionConPoligono / procesarPerforacion)
      //             → convertir a mm² con la escala del sistema
      if (ph.metricas?.area_real) return (parseFloat(ph.metricas.area_real) || 0) * _scaleSq;
      // Prioridad 3: campo .area numérico explícito (distinto del objeto rectángulo de selección)
      if (ph.area !== undefined && typeof ph.area !== 'object' && !isNaN(parseFloat(ph.area)))
        return parseFloat(ph.area) || 0;
      // Prioridad 4: calcular Shoelace desde puntos del polígono (px²) → convertir a mm²
      const pts = ph.puntos || ph.contorno || ph.poligonoTrazado;
      return (pts && pts.length > 2) ? GeometryPrimitives.calcularAreaShoelace(pts) * _scaleSq : 0;
    };

    const _enPoligono = (px, py, poly) => {
      let inside = false;
      for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
        const xi = poly[i].x, yi = poly[i].y, xj = poly[j].x, yj = poly[j].y;
        if ((yi > py) !== (yj > py) && px < (xj - xi) * (py - yi) / (yj - yi) + xi)
          inside = !inside;
      }
      return inside;
    };

    const idxContenidas = new Set();
    const relaciones     = [];

    if (perforaciones.length > 0 && horadaciones.length > 0) {
      perforaciones.forEach((p, pi) => {
        const ptsP = p.puntos || p.contorno || p.poligonoTrazado;
        if (!ptsP || ptsP.length < 3) return;
        const cx = ptsP.reduce((s, pt) => s + pt.x, 0) / ptsP.length;
        const cy = ptsP.reduce((s, pt) => s + pt.y, 0) / ptsP.length;
        const areaP = _getA(p);
        horadaciones.forEach(h => {
          const ptsH = h.puntos || h.contorno || h.poligonoTrazado;
          if (!ptsH || ptsH.length < 3) return;
          if (areaP >= _getA(h)) return;          // contenido < contenedor
          if (_enPoligono(cx, cy, ptsH)) {
            idxContenidas.add(pi);
            relaciones.push({ perforacion_id: p.id ?? pi, horadacion_id: h.id ?? undefined });
          }
        });
      });
      if (relaciones.length > 0)
        console.log(`🔺 P/H contenidas (p.ej. orificio cónico): ${relaciones.length}`, relaciones);
    }

    let areaTotalPerforaciones = 0;
    perforaciones.forEach((p, i) => { if (!idxContenidas.has(i)) areaTotalPerforaciones += _getA(p); });

    // Área bruta: suma TODAS las P/H incluyendo las contenidas → para display al usuario
    // (evita mostrar 0 cuando P está inscrita en H; la lógica de área neta sigue usando los valores efectivos)
    let areaBrutaPerforaciones = 0;
    perforaciones.forEach(p => { areaBrutaPerforaciones += _getA(p); });

    let areaTotalHoradaciones = 0;
    horadaciones.forEach(h => { areaTotalHoradaciones += _getA(h); });

    const areaBrutaHoradaciones = areaTotalHoradaciones; // H no se deducan entre sí

    return {
      areaTotalPerforaciones,    // efectiva (excluye P inscritas en H) — para cálculo de área neta
      areaTotalHoradaciones,
      areaTotalPH: areaTotalPerforaciones + areaTotalHoradaciones,
      areaBrutaPerforaciones,    // medida (todas las P) — para display informativo al usuario
      areaBrutaHoradaciones,
      numContenidas: idxContenidas.size,
      relaciones,
      idxContenidas
    };
  }

  /**
   * ANÁLISIS COMPARATIVO AVANZADO: Objeto vs Perforaciones/Horadaciones
   * Calcula ratios, simetría, distribución espacial y clasificación funcional
   */
  function calcularAnalisisComparativo(obj, metricas) {
    console.log(`🔬 Iniciando análisis comparativo avanzado para objeto ${obj.id}...`);
    
    const tienePerforaciones = obj.perforaciones && obj.perforaciones.length > 0;
    const tieneHoradaciones = obj.horadaciones && obj.horadaciones.length > 0;
    
    if (!tienePerforaciones && !tieneHoradaciones) {
      console.log(`⚠️ No hay perforaciones/horadaciones para analizar`);
      return null;
    }
    
    // 🆕 Helpers para obtener métricas de forma flexible
    const getArea = (ph) => {
      // Prioridad 1: metricas.area en mm² (Ruta A: polygon trace)
      if (ph.metricas?.area) return parseFloat(ph.metricas.area);
      // Prioridad 2: metricas.area_real en px² (Ruta B: procesarPerforacion) → convertir a mm²
      if (ph.metricas?.area_real) {
        const _scSq = (typeof scale !== 'undefined' && scale > 0) ? scale * scale : 1;
        return (parseFloat(ph.metricas.area_real) || 0) * _scSq;
      }
      // Prioridad 3: ph.area numérico explícito (no el rectángulo de selección)
      if (ph.area !== undefined && typeof ph.area !== 'object' && !isNaN(parseFloat(ph.area)))
        return parseFloat(ph.area);
      // Prioridad 4: calcular desde puntos (ph.puntos o ph.contorno según ruta)
      const pts = ph.puntos || ph.contorno || ph.poligonoTrazado;
      if (pts && pts.length > 2) return GeometryPrimitives.calcularAreaShoelace(pts);
      return 0;
    };
    
    const getCentroide = (ph) => {
      if (ph.metricas && ph.metricas.centroid) return ph.metricas.centroid;
      if (ph.metricas && ph.metricas.centroide) return ph.metricas.centroide;
      if (ph.centroide) return ph.centroide;
      if (ph.puntos && ph.puntos.length > 2) return calcularCentroidePoligono(ph.puntos);
      return [0, 0];
    };
    
    const getMetrica = (ph, metricaKey, defaultValue = 0) => {
      if (ph.metricas && ph.metricas[metricaKey] !== undefined) return parseFloat(ph.metricas[metricaKey]);
      if (ph[metricaKey] !== undefined) return parseFloat(ph[metricaKey]);
      return defaultValue;
    };

    // ── Detección de contención via función global reutilizable ──────────────
    const _phEfectivo = calcularAreaEfectivaPH(
      obj.perforaciones || [],
      obj.horadaciones  || []
    );
    const _idxPerforacionesContenidas = _phEfectivo.idxContenidas;
    const _relacionesContencion       = _phEfectivo.relaciones;

    const analisis = {
      objeto_id: obj.id,
      timestamp: new Date().toISOString(),
      
      // Contadores
      num_perforaciones: obj.perforaciones?.length || 0,
      num_horadaciones: obj.horadaciones?.length || 0,
      total_perforaciones_horadaciones: (obj.perforaciones?.length || 0) + (obj.horadaciones?.length || 0),
      
      // Análisis de ratios y proporciones
      ratios: {},
      
      // Análisis de simetría y distribución espacial
      distribucionEspacial: {},
      
      // Análisis de clustering
      clustering: {},
      
      // Distribución angular
      distribucionAngular: {}
    };
    
    // Obtener centroide del objeto — parseFloat inmediato + guard isFinite.
    // NOTA: centroide_hull_x/y se almacena como string via safeToFixed (puede ser 'N/A').
    // El check anterior (=== undefined || === null) NO capturaba 'N/A' (truthy).
    // Ahora se verifica con isFinite tras parseFloat para cualquier valor inválido.
    let centroidObjX = parseFloat(metricas.centroide_hull_x ?? metricas.centroide_x);
    let centroidObjY = parseFloat(metricas.centroide_hull_y ?? metricas.centroide_y);
    
    if (!isFinite(centroidObjX) || !isFinite(centroidObjY)) {
      if (metricas._contour_data?.metrics?.centroid_hull?.length >= 2) {
        centroidObjX = metricas._contour_data.metrics.centroid_hull[0];
        centroidObjY = metricas._contour_data.metrics.centroid_hull[1];
      } else if (metricas._contour_data?.metrics?.centroid?.length >= 2) {
        centroidObjX = metricas._contour_data.metrics.centroid[0];
        centroidObjY = metricas._contour_data.metrics.centroid[1];
      } else {
        centroidObjX = obj.minX + obj.width / 2;
        centroidObjY = obj.minY + obj.height / 2;
      }
    }
    
    console.log(`   📍 Centroide objeto: (${centroidObjX.toFixed(2)}, ${centroidObjY.toFixed(2)})`);
    
    // ============================================================================
    // 1. ANÁLISIS DE RATIOS Y PROPORCIONES
    // ============================================================================

    // Validar que las métricas del objeto sean números válidos
    const areaObjeto = parseFloat(metricas.area) || 0;
    const perimetroObjeto = parseFloat(metricas.perimeter) || parseFloat(metricas.perimetro) || 0;

    // Áreas efectivas ya calculadas por calcularAreaEfectivaPH (sin double-counting)
    const areaTotalPerforaciones = _phEfectivo.areaTotalPerforaciones;
    const areaTotalHoradaciones  = _phEfectivo.areaTotalHoradaciones;
    const areaTotalPH            = _phEfectivo.areaTotalPH;

    // Arrays individuales para estadísticas descriptivas (exluye contenidas → 0 filtrado)
    const areasPerforaciones = tienePerforaciones
      ? obj.perforaciones.map((p, i) => _idxPerforacionesContenidas.has(i) ? 0 : getArea(p))
      : [];
    const areasHoradaciones = tieneHoradaciones
      ? obj.horadaciones.map(h => getArea(h))
      : [];
    const todasLasAreas = [...areasPerforaciones, ...areasHoradaciones].filter(a => a > 0);

    // Calcular estadísticas de áreas
    const mediaAreas = todasLasAreas.length > 0 ? todasLasAreas.reduce((a, b) => a + b, 0) / todasLasAreas.length : 0;
    let desviacionAreas = 0;
    let coefVariacionAreas = 0;

    if (todasLasAreas.length > 1 && mediaAreas > 0) {
      const varianza = todasLasAreas.reduce((sum, a) => sum + Math.pow(a - mediaAreas, 2), 0) / todasLasAreas.length;
      desviacionAreas = Math.sqrt(varianza);
      coefVariacionAreas = desviacionAreas / mediaAreas;
    }

    analisis.ratios = {
      // Ratio principal: Área objeto vs total P/H efectivo
      areaObjeto_vs_totalHoradaciones: areaObjeto > 0 && areaTotalPH > 0 ? (areaObjeto / areaTotalPH) : 0,

      // Porcentajes de área para DISPLAY (usando bruta: todas las P incluyendo contenidas)
      porcentaje_perforaciones: areaObjeto > 0 ? ((_phEfectivo.areaBrutaPerforaciones / areaObjeto) * 100) : 0,
      porcentaje_horadaciones: areaObjeto > 0 ? ((areaTotalHoradaciones / areaObjeto) * 100) : 0,
      porcentaje_total: areaObjeto > 0 ? ((areaTotalPH / areaObjeto) * 100) : 0,

      // Áreas absolutas — bruta (display) y efectiva (cálculo de área neta)
      area_total_perforaciones:         _phEfectivo.areaBrutaPerforaciones,   // DISPLAY: todas las P
      area_total_perforaciones_efectiva: areaTotalPerforaciones,               // CÁLCULO: excluye P contenidas en H
      area_total_horadaciones:           areaTotalHoradaciones,
      area_promedio: mediaAreas,

      // Variabilidad
      desviacion_estandar_areas: desviacionAreas,
      coeficienteVariacion_areas: coefVariacionAreas,

      // Contención P ⊂ H (p.ej. orificio cónico)
      perforaciones_contenidas_en_horadaciones: _relacionesContencion.length,
      relaciones_contencion: _relacionesContencion
    };
    
    console.log(`   📊 Ratios calculados:`, analisis.ratios);
    
    // ============================================================================
    // 2. ANÁLISIS DE DISTRIBUCIÓN ESPACIAL
    // ============================================================================

    // Factor de conversión px→mm para distancias
    const _scaleD = (typeof scale !== 'undefined' && scale > 0) ? scale : 1;

    // Radio máximo del objeto en mm (fallback de normalización cuando no hay hull)
    const _radioMaxObjMM = parseFloat(metricas.radio_maximo || metricas.radio_max || 0) || 1;

    // Puntos del convex hull del objeto (coordenadas px absolutas) para normalización direccional
    const _hullPtsDir = obj.convexHull || metricas._contour_data?.metrics?.convex_hull || [];

    const todasPH = [];
    if (tienePerforaciones) todasPH.push(...obj.perforaciones.map(p => ({ ...p, tipo: 'perforacion' })));
    if (tieneHoradaciones) todasPH.push(...obj.horadaciones.map(h => ({ ...h, tipo: 'horadacion' })));

    // Calcular distancias de cada P/H al centroide hull del objeto
    const distancias = todasPH.map(ph => {
      const centroidPH = getCentroide(ph);

      if (!centroidPH || !Array.isArray(centroidPH) || centroidPH.length < 2) {
        console.warn(`⚠️ Centroide inválido para P/H #${ph.id}:`, centroidPH);
        return {
          id: ph.id, tipo: ph.tipo,
          distancia_px: 0, distancia_mm: 0,
          distancia_normalizada: 0, posicion_relativa: 'indeterminada',
          dx: 0, dy: 0, angulo: 0
        };
      }

      const dx = centroidPH[0] - centroidObjX;
      const dy = centroidPH[1] - centroidObjY;
      const distancia_px = Math.sqrt(dx * dx + dy * dy);
      const distancia_mm = distancia_px * _scaleD;

      // Normalización DIRECCIONAL: radio del hull en la dirección centroide→P/H.
      // Para objetos elongados, circulares o irregulares esto da [0,1] correcto:
      // 0 = en el centroide, 1 = en el borde del hull en esa dirección.
      // Evita que objetos elongados clasifiquen posiciones laterales como 'intermedia'
      // cuando el P/H está realmente en la periferia del eje corto.
      let _hullRDirMM = _radioMaxObjMM; // fallback
      if (_hullPtsDir.length >= 3 && distancia_px > 0) {
        const _cosA = dx / distancia_px;
        const _sinA = dy / distancia_px;
        let _maxProj = 0;
        for (const _hpt of _hullPtsDir) {
          const _hx = (Array.isArray(_hpt) ? _hpt[0] : _hpt.x) - centroidObjX;
          const _hy = (Array.isArray(_hpt) ? _hpt[1] : _hpt.y) - centroidObjY;
          const _proj = _hx * _cosA + _hy * _sinA;
          if (_proj > _maxProj) _maxProj = _proj;
        }
        if (_maxProj > 0) _hullRDirMM = _maxProj * _scaleD;
      }
      const distancia_normalizada = _hullRDirMM > 0 ? Math.min(1.2, distancia_mm / _hullRDirMM) : 0;

      let posicion_relativa;
      if      (distancia_normalizada <= 0.20)  posicion_relativa = 'central';
      else if (distancia_normalizada <= 0.60)  posicion_relativa = 'intermedia';
      else if (distancia_normalizada <= 0.85)  posicion_relativa = 'periférica';
      else                                      posicion_relativa = 'marginal';

      return {
        id: ph.id || 0,
        tipo: ph.tipo || 'desconocido',
        distancia_px,
        distancia_mm,
        distancia_normalizada,
        posicion_relativa,
        dx, dy,
        angulo: Math.atan2(dy, dx) * (180 / Math.PI)
      };
    });

    // Estadísticas de distancias — FIX 1: todo en mm
    const distanciasValores = distancias.map(d => d.distancia_mm);
    const distanciaMedia = distanciasValores.length > 0 ?
      distanciasValores.reduce((a, b) => a + b, 0) / distanciasValores.length : 0;
    const distanciaMax = distanciasValores.length > 0 ? Math.max(...distanciasValores) : 0;
    const distanciaMin = distanciasValores.length > 0 ? Math.min(...distanciasValores) : 0;

    const varianzaDist = distanciasValores.length > 0 ?
      distanciasValores.reduce((sum, d) => sum + Math.pow(d - distanciaMedia, 2), 0) / distanciasValores.length : 0;
    const desviacionDist = Math.sqrt(varianzaDist);
    // FIX 2: cvDistancias es un ratio [0–∞], NO porcentaje
    const cvDistancias = distanciaMedia > 0 ? (desviacionDist / distanciaMedia) : 0;

    // Conteo de posiciones
    const _contPos = { central: 0, intermedia: 0, periférica: 0, marginal: 0 };
    distancias.forEach(d => { if (_contPos[d.posicion_relativa] !== undefined) _contPos[d.posicion_relativa]++; });
    const _nCentral    = _contPos.central;
    const _nIntermedia = _contPos.intermedia;
    const _nPerif      = _contPos.periférica;
    const _nMarginal   = _contPos.marginal;

    // Índice de simetría radial (0-1, donde 1 = perfectamente simétrico)
    const simetriaRadial = cvDistancias > 0 ? Math.max(0, 1 - cvDistancias) : 1;

    analisis.distribucionEspacial = {
      distanciaPromedio_alCentroide: distanciaMedia,
      distanciaMaxima: distanciaMax,
      distanciaMinima: distanciaMin,
      desviacionEstandar: desviacionDist,
      coeficienteVariacion: cvDistancias,
      simetriaRadial,
      simetriaAngular: 0,  // Se calculará abajo
      conteo_posiciones: _contPos
    };

    // Analizar distribución angular
    const angulos = distancias.map(d => d.angulo);

    const cuadrantes = { Q1: 0, Q2: 0, Q3: 0, Q4: 0 };
    angulos.forEach(ang => {
      if      (ang >= -45  && ang <  45)  cuadrantes.Q1++;
      else if (ang >=  45  && ang < 135)  cuadrantes.Q2++;
      else if (ang >=  135 || ang < -135) cuadrantes.Q3++;
      else                                cuadrantes.Q4++;
    });

    const expectedPerQuadrant = todasPH.length / 4;
    const chiSquare = Object.values(cuadrantes).reduce((sum, observed) => {
      return sum + Math.pow(observed - expectedPerQuadrant, 2) / expectedPerQuadrant;
    }, 0);
    const uniformidad = Math.max(0, 1 - (chiSquare / todasPH.length));

    analisis.distribucionEspacial.simetriaAngular = uniformidad;

    analisis.distribucionAngular = {
      concentracionCuadrantes: cuadrantes,
      uniformidad,
      angulosGrados: angulos
    };

    // Análisis de clustering entre pares de P/H (en mm)
    let indiceClustering = 0;
    if (todasPH.length >= 3) {
      const distanciasPares = [];
      for (let i = 0; i < todasPH.length; i++) {
        for (let j = i + 1; j < todasPH.length; j++) {
          const c1 = getCentroide(todasPH[i]);
          const c2 = getCentroide(todasPH[j]);
          const dx = (c1[0] - c2[0]) * _scaleD;
          const dy = (c1[1] - c2[1]) * _scaleD;
          distanciasPares.push(Math.sqrt(dx * dx + dy * dy));
        }
      }
      const distanciaMediaPares = distanciasPares.reduce((a, b) => a + b, 0) / distanciasPares.length;
      const varianzaPares = distanciasPares.reduce((sum, d) =>
        sum + Math.pow(d - distanciaMediaPares, 2), 0) / distanciasPares.length;
      const cvPares = distanciaMediaPares > 0 ? Math.sqrt(varianzaPares) / distanciaMediaPares : 0;
      indiceClustering = Math.min(1, cvPares);
    }

    analisis.clustering = {
      indice_clustering: indiceClustering,
      interpretacion: indiceClustering > 0.5 ? 'Agrupamiento detectado' : 'Distribución dispersa'
    };

    console.log(`✅ Análisis comparativo completado para objeto ${obj.id}`);
    console.log(`   📊 Ratios:`, analisis.ratios);
    console.log(`   📍 Distribución (mm):`, analisis.distribucionEspacial);
    console.log(`   🔄 Angular:`, analisis.distribucionAngular);
    console.log(`   🎯 Clustering:`, analisis.clustering);
    console.log(`   📌 Posiciones:`, _contPos);

    // Clasificar distribución angular basada en uniformidad
    let clasificacionAngular = 'irregular';
    if      (uniformidad > 0.8)                                    clasificacionAngular = 'simétrica_radial';
    else if (todasPH.length === 2 && uniformidad > 0.7)            clasificacionAngular = 'simétrica_bilateral';
    else if (uniformidad > 0.6)                                    clasificacionAngular = 'semi_regular';

    // FIX 2: umbrales correctos — cvDistancias es ratio [0–∞], no porcentaje
    let patron_clustering = 'disperso';
    if      (cvDistancias < 0.20) patron_clustering = 'anillo_uniforme';   // CV < 20% → distancias homogéneas
    else if (cvDistancias > 0.50) patron_clustering = 'agrupado_variable'; // CV > 50% → distancias muy dispares

    // Clasificación de zona predominante de las P/H
    let zona_predominante;
    const _totalPH = todasPH.length;
    const _pctCentral = _nCentral / _totalPH;
    if      (_pctCentral >= 0.7)                           zona_predominante = 'zona_central';
    else if ((_nPerif + _nMarginal) / _totalPH >= 0.7)     zona_predominante = 'zona_periférica';
    else if ((_nCentral + _nIntermedia) / _totalPH >= 0.7) zona_predominante = 'zona_interior';
    else                                                    zona_predominante = 'distribuida';

    // Estructura de retrocompatibilidad — FIX 1: distancias ya en mm
    analisis.simetria_distribucion = {
      distancia_media_al_centroide:   (distanciaMedia  || 0).toFixed(2),
      distancia_maxima_al_centroide:  (distanciaMax    || 0).toFixed(2),
      distancia_minima_al_centroide:  (distanciaMin    || 0).toFixed(2),
      desviacion_distancias:          (desviacionDist  || 0).toFixed(2),
      coef_variacion_distancias:      (cvDistancias    || 0).toFixed(3),
      regularidad_espacial:           cvDistancias < 0.20 ? 'Alta' : cvDistancias < 0.40 ? 'Media' : 'Baja',
      distribucion_angular:           clasificacionAngular,
      patron_clustering,
      zona_predominante,
      conteo_posiciones:              _contPos,
      detalles_posiciones: distancias.map(d => ({
        id:                  `${d.tipo === 'perforacion' ? 'P' : 'H'}${d.id}`,
        distancia_mm:        (d.distancia_mm    || 0).toFixed(2),
        distancia_norm:      (d.distancia_normalizada || 0).toFixed(3),
        posicion_relativa:   d.posicion_relativa,
        angulo_grados:       (d.angulo           || 0).toFixed(1)
      }))
    };
    
    // ============================================================================
    // 3. CLASIFICACIÓN FUNCIONAL — incluye posición relativa al centroide hull
    // ============================================================================

    let clasificacion = 'indeterminada';
    let confianza = 0;
    let descripcion = '';

    const _nP     = analisis.num_perforaciones;
    const _nH     = analisis.num_horadaciones;
    const _pctPH  = parseFloat(analisis.ratios.porcentaje_total) || 0;
    const _pctP   = parseFloat(analisis.ratios.porcentaje_perforaciones) || 0;

    // ── Reglas basadas en posición relativa ───────────────────────────────────
    // Caso 1: todas o mayoría en zona CENTRAL (eje, pivote, refuerzo)
    if (_nCentral >= 1 && _pctCentral >= 0.7 && _nP >= 1) {
      clasificacion = 'perforacion_axial';
      confianza = 0.85;
      descripcion = `${_nCentral} perforación(es) en zona central (<=15% radio). Posición axial coherente con función de eje, suspensión directa o pasador.`;
    }
    else if (_nCentral >= 1 && _pctCentral >= 0.7 && _nH >= 1 && _nP === 0) {
      clasificacion = 'horadacion_axial';
      confianza = 0.82;
      descripcion = `Horadación(es) en posición central. Indicativo de desbaste de núcleo, enmangamiento o cavidad funcional.`;
    }
    // Caso 2: múltiples perforaciones centrales + periféricas → patrón compuesto
    else if (_nCentral >= 1 && (_nPerif + _nMarginal) >= 1) {
      clasificacion = 'patron_compuesto_radial';
      confianza = 0.75;
      descripcion = `Combinación de P/H centrales (${_nCentral}) y periféricas/marginales (${_nPerif + _nMarginal}). Patrón compuesto sugiere función dual o etapas de manufactura.`;
    }
    // Caso 3: todas marginales (borde, periferia del objeto)
    else if ((_nPerif + _nMarginal) / _totalPH >= 0.85 && _nP === 1) {
      clasificacion = 'colgante_borde';
      confianza = 0.78;
      descripcion = `Perforación única en zona marginal/periférica (>60% radio). Típico de colgante con suspensión en borde.`;
    }
    else if ((_nPerif + _nMarginal) / _totalPH >= 0.85 && _nP >= 2) {
      clasificacion = 'colgante_multiperforado';
      confianza = clasificacionAngular === 'simétrica_radial' ? 0.85 : 0.70;
      descripcion = `Múltiples perforaciones en zona periférica/marginal. ${clasificacionAngular === 'simétrica_radial' ? 'Distribución Angular simétrica refuerza función de colgante complejo.' : 'Distribución asimétrica.'}`;
    }
    // Caso 4: zona intermedia — reglas clásicas de conteo
    else if (_nP >= 2 && clasificacionAngular === 'simétrica_radial') {
      clasificacion = 'colgante_multiperforado';
      confianza = 0.80;
      descripcion = 'Múltiples perforaciones simétricamente distribuidas en zona intermedia. Función de suspensión compleja o decorativa.';
    }
    else if (_nP === 2 && clasificacionAngular === 'simétrica_bilateral') {
      clasificacion = 'cuenta_biconica';
      confianza = 0.75;
      descripcion = 'Dos perforaciones opuestas en zona intermedia. Sugieren cuenta o elemento de ensartado.';
    }
    else if (_nP === 1 && _pctP < 5) {
      clasificacion = 'colgante_simple';
      confianza = 0.70;
      descripcion = 'Perforación única pequeña en zona intermedia. Función de colgante o amuleto.';
    }
    else if (_nP === 1 && _pctP >= 5) {
      clasificacion = 'elemento_estructural';
      confianza = 0.65;
      descripcion = 'Perforación única de gran tamaño. Función estructural o de ensamblaje.';
    }
    else if (_nH > 0 && _nP === 0) {
      clasificacion = 'objeto_reutilizado';
      confianza = 0.60;
      descripcion = 'Solo horadaciones presentes. Sugiere modificación posterior o reutilización del objeto.';
    }
    else if (patron_clustering === 'agrupado_variable') {
      clasificacion = 'objeto_compuesto';
      confianza = 0.55;
      descripcion = 'Distribución irregular de P/H. Sugiere función compleja o múltiples etapas de manufactura.';
    }

    // Refinamiento: agregar nota de zona si no es el factor principal ya descrito
    if (zona_predominante && clasificacion !== 'indeterminada') {
      const _zonaLabel = {
        zona_central:    'concentradas en el centro',
        zona_periférica: 'distribuidas en la periferia',
        zona_interior:   'en zona interior/intermedia',
        distribuida:     'con distribución mixta por zonas'
      }[zona_predominante] || zona_predominante;
      if (!descripcion.includes('central') && !descripcion.includes('periférica') && !descripcion.includes('marginal')) {
        descripcion += ` P/H ${_zonaLabel} del objeto.`;
      }
    }

    // Análisis de desgaste por excentricidad de perforaciones
    let patron_desgaste = 'sin_analisis';
    if (tienePerforaciones && obj.perforaciones.length > 0) {
      const excentricidades = obj.perforaciones.map(p => parseFloat(p.metricas?.excentricidad) || 0);
      const excentricidadMedia = excentricidades.reduce((a, b) => a + b, 0) / excentricidades.length;
      if      (excentricidadMedia > 0.7) { patron_desgaste = 'desgaste_asimetrico_alto';  descripcion += ' Excentricidad alta sugiere desgaste asimétrico por uso prolongado.'; }
      else if (excentricidadMedia > 0.4)   patron_desgaste = 'desgaste_moderado';
      else                                  patron_desgaste = 'sin_desgaste_aparente';
    }

    analisis.clasificacion_funcional = {
      categoria: clasificacion,
      confianza,
      descripcion,
      patron_desgaste,
      zona_predominante,
      tecnica_manufactura: analisis.ratios.coeficienteVariacion_areas < 0.15 ? 'estandarizada' : 'variable'
    };
    
    // ============================================================================
    // 4. COHERENCIA MORFOLÓGICA
    // ============================================================================
    
    // Comparar forma del objeto con formas de perforaciones/horadaciones
    const formaObjeto = metricas.forma_detectada || 'desconocida';
    const formasPerforaciones = tienePerforaciones ? obj.perforaciones.map(p => p.metricas.forma_detectada) : [];
    const formasHoradaciones = tieneHoradaciones ? obj.horadaciones.map(h => h.metricas.forma_detectada) : [];
    
    // Contar formas más comunes en perforaciones
    const formasMasComunes = {};
    [...formasPerforaciones, ...formasHoradaciones].forEach(forma => {
      formasMasComunes[forma] = (formasMasComunes[forma] || 0) + 1;
    });
    
    const formaPredomminante = Object.keys(formasMasComunes).reduce((a, b) => 
      formasMasComunes[a] > formasMasComunes[b] ? a : b, 'ninguna'
    );
    
    const coherencia = formaObjeto === formaPredomminante ? 'alta' : 'baja';
    
    // Comparar circularidad - asegurar que sean números válidos
    let circularidadObjeto = metricas.circularity_real || metricas.circularity;
    if (circularidadObjeto === undefined || circularidadObjeto === null || isNaN(circularidadObjeto)) {
      circularidadObjeto = 0;
    }
    circularidadObjeto = parseFloat(circularidadObjeto);
    
    const circularidadesPerf = tienePerforaciones ? obj.perforaciones.map(p => p.metricas.circularity) : [];
    const circularidadMediaPerf = circularidadesPerf.length > 0 ? 
      circularidadesPerf.reduce((a, b) => a + b, 0) / circularidadesPerf.length : 0;
    
    const diferenciaCircularidad = Math.abs(circularidadObjeto - circularidadMediaPerf);
    
    analisis.coherencia_morfologica = {
      forma_objeto: formaObjeto,
      forma_predominante_perforaciones: formaPredomminante,
      coherencia_formas: coherencia,
      distribucion_formas: formasMasComunes,
      circularidad_objeto: circularidadObjeto.toFixed(4),
      circularidad_media_perforaciones: circularidadMediaPerf.toFixed(4),
      diferencia_circularidad: diferenciaCircularidad.toFixed(4),
      interpretacion: coherencia === 'alta' ? 
        'Las perforaciones mantienen coherencia morfológica con el objeto, sugiriendo manufactura planificada.' :
        'Las perforaciones difieren morfológicamente del objeto, puede indicar diferentes momentos de manufactura o función especializada.'
    };
    
    // ============================================================================
    // RETROCOMPATIBILIDAD: Alias para código antiguo
    // ============================================================================
    // _areasP incluye TODAS las perforaciones (bruta) para promedio y CV de display
    const _areasP = obj.perforaciones?.map(p => getArea(p)).filter(a => a > 0) || [];
    const _areasH = areasHoradaciones.filter(a => a > 0);
    const _nContenidas = _relacionesContencion.length;
    analisis.ratios_proporciones = {
      ratio_area_perforaciones_objeto: analisis.ratios.porcentaje_perforaciones,
      ratio_area_horadaciones_objeto: analisis.ratios.porcentaje_horadaciones,
      ratio_area_total_ph_objeto: analisis.ratios.porcentaje_total,
      area_total_perforaciones: analisis.ratios.area_total_perforaciones,         // bruta (display)
      area_total_perforaciones_efectiva: analisis.ratios.area_total_perforaciones_efectiva, // neta (cálculo)
      area_total_horadaciones: analisis.ratios.area_total_horadaciones,
      area_promedio_perforaciones: _areasP.length > 0 ? _areasP.reduce((s, a) => s + a, 0) / _areasP.length : 0,
      area_promedio_horadaciones: _areasH.length > 0 ? _areasH.reduce((s, a) => s + a, 0) / _areasH.length : 0,
      area_neta_objeto: areaObjeto - areaTotalPH,
      coef_variacion_perforaciones: _areasP.length > 1 ? (() => {
        const mu = _areasP.reduce((s,a)=>s+a,0)/_areasP.length;
        return mu > 0 ? (Math.sqrt(_areasP.reduce((s,a)=>s+(a-mu)**2,0)/_areasP.length)/mu*100).toFixed(2) : '0.00';
      })() : '0.00',
      coef_variacion_horadaciones: (analisis.ratios.coeficienteVariacion_areas * 100).toFixed(2),
      // Indicador de contención para UI
      perforaciones_contenidas_en_horadaciones: _nContenidas,
      nota_contencion: _nContenidas > 0
        ? `${_nContenidas} perforac. inscrita(s) en horadación (orificio cónico). Área efectiva descontada: ${analisis.ratios.area_total_perforaciones_efectiva.toFixed(2)} mm².`
        : null
    };
    
    console.log(`✅ Análisis comparativo completado:`, analisis);
    
    return analisis;
  }

  /**
   * Finalizar todos los trazados y aplicarlos al objeto
   */
  function finalizarTodosTrazados() {
    if (trazadosPerforaciones.length === 0) {
      // Permitir eliminación total de P/H preexistentes.
      if (selectedObjectForPerforation) {
        selectedObjectForPerforation.perforaciones = [];
        selectedObjectForPerforation.horadaciones = [];
        // ADR-009: finalizar sin trazados = decisión humana «sin P/H» → limpiar
        // candidatos para que el chip deje de proponerlos (cae a «evaluado · sin P/H»).
        selectedObjectForPerforation.phCandidatos = [];

        if (currentAnalyzedObject && currentAnalyzedObject.obj) {
          currentAnalyzedObject.obj.perforaciones = [];
          currentAnalyzedObject.obj.horadaciones = [];
          currentAnalyzedObject.obj.phCandidatos = [];
          sincronizarPerforacionesEnMemoria(currentAnalyzedObject.obj);
        }

        redibujarMorphologicalCanvasConPerforaciones(
          selectedObjectForPerforation,
          currentAnalyzedObject ? currentAnalyzedObject.metricas : null
        );

        if (currentAnalyzedObject && currentAnalyzedObject.metricas) {
          actualizarTablaMorfologica(selectedObjectForPerforation, currentAnalyzedObject.metricas);
        }

        UtilityHelpers.setStatus('Se eliminaron todas las perforaciones/horadaciones del objeto.', false);
        ocultarCanvasAmpliadoPerforation();
        return;
      }

      toast.warning('No hay trazados para aplicar.');
      return;
    }
    
    console.log(`✅ Finalizando ${trazadosPerforaciones.length} trazados`);
    
    // Separar por tipo
    const perforaciones = trazadosPerforaciones.filter(t => t.tipo === 'perforacion');
    const horadaciones = trazadosPerforaciones.filter(t => t.tipo === 'horadacion');
    
    console.log(`   - Perforaciones: ${perforaciones.length}`);
    console.log(`   - Horadaciones: ${horadaciones.length}`);
    
    // Reemplazar conjunto completo para soportar edición posterior (eliminar + redetectar).
    selectedObjectForPerforation.perforaciones = [];
    selectedObjectForPerforation.horadaciones = [];
    
    // Obtener la escala del sistema (mm/px)
    const scaleToUse = scale || 1; // Usar escala global, o 1 si no está definida
    console.log(`📏 Usando escala: ${scaleToUse} mm/px`);
    
    perforaciones.forEach(t => {
      // NUEVO: Calcular métricas MORFOLÓGICAS COMPLETAS CON ESCALA
      const numeroPerforacion = selectedObjectForPerforation.perforaciones.length + 1;
      const metricas = calcularMetricasPerforacion(t.puntos, 'perforacion', numeroPerforacion, scaleToUse);
      
      if (!metricas) {
        console.warn(`⚠️ No se pudieron calcular métricas para perforación #${numeroPerforacion}`);
        return;
      }
      
      // Preservar EFA calculado en sesión (si el usuario lo ejecutó antes de finalizar)
      if (t._efa_data) metricas._efa_data = t._efa_data;
      if (t._landmarks_semiauto) metricas._landmarks_semiauto = t._landmarks_semiauto;

      selectedObjectForPerforation.perforaciones.push({
        id: numeroPerforacion,
        tipo: 'perforacion',
        puntos: t.puntos,
        contorno: t.puntos,
        poligonoTrazado: t.puntos,
        metricas: metricas, // MÉTRICAS MORFOLÓGICAS COMPLETAS
        timestamp: t.timestamp
      });
      
      console.log(`✅ Perforación #${numeroPerforacion} - Área: ${metricas.area} mm², Forma: ${metricas.forma_detectada}`);
    });
    
    horadaciones.forEach(t => {
      // NUEVO: Calcular métricas MORFOLÓGICAS COMPLETAS CON ESCALA
      const numeroHoradacion = selectedObjectForPerforation.horadaciones.length + 1;
      const metricas = calcularMetricasPerforacion(t.puntos, 'horadacion', numeroHoradacion, scaleToUse);
      
      if (!metricas) {
        console.warn(`⚠️ No se pudieron calcular métricas para horadación #${numeroHoradacion}`);
        return;
      }
      
      // Preservar EFA calculado en sesión
      if (t._efa_data) metricas._efa_data = t._efa_data;
      if (t._landmarks_semiauto) metricas._landmarks_semiauto = t._landmarks_semiauto;

      selectedObjectForPerforation.horadaciones.push({
        id: numeroHoradacion,
        tipo: 'horadacion',
        puntos: t.puntos,
        contorno: t.puntos,
        poligonoTrazado: t.puntos,
        metricas: metricas, // MÉTRICAS MORFOLÓGICAS COMPLETAS
        timestamp: t.timestamp
      });
      
      console.log(`✅ Horadación #${numeroHoradacion} - Área: ${metricas.area} mm², Forma: ${metricas.forma_detectada}`);
    });
    
    // ── Intento Python /api/ph_metrics (enriquece métricas calculadas en JS) ─
    if (window.PythonBridge && PythonBridge.isModuleActive('ph') &&
        trazadosPerforaciones.length > 0) {
      PythonBridge.ph.processMetrics(trazadosPerforaciones, scaleToUse)
        .then(phResult => {
          if (!phResult || phResult.status === 'error') return;
          // Mezclar métricas Python en los objetos ya guardados
          const _mergePH = (pyList, tipo) => {
            if (!Array.isArray(pyList)) return;
            const lista = selectedObjectForPerforation[tipo] || [];
            pyList.forEach(r => {
              const item = lista.find(x => x.id === r.id);
              if (item && r.metricas) {
                Object.assign(item.metricas, r.metricas);
                console.log(`[Python] ph: métricas enriquecidas ${tipo} #${r.id}`);
              }
            });
          };
          _mergePH(phResult.perforaciones, 'perforaciones');
          _mergePH(phResult.horadaciones,  'horadaciones');
          // Actualizar tabla si sigue visible
          if (currentAnalyzedObject && currentAnalyzedObject.metricas) {
            actualizarTablaMorfologica(selectedObjectForPerforation, currentAnalyzedObject.metricas);
          }
        })
        .catch(_e => console.warn('[Python] ph.processMetrics falló:', _e.message));
    }

    console.log(`✅ Trazados aplicados al objeto ${selectedObjectForPerforation.id}`);
    console.log(`   Perforaciones totales en objeto: ${selectedObjectForPerforation.perforaciones.length}`);
    console.log(`   Horadaciones totales en objeto: ${selectedObjectForPerforation.horadaciones.length}`);
    
    // 📊 RESUMEN DE MÉTRICAS
    if (selectedObjectForPerforation.perforaciones.length > 0) {
      console.log(`\n📊 RESUMEN DE PERFORACIONES:`);
      selectedObjectForPerforation.perforaciones.forEach(p => {
        console.log(`   P${p.id}: Área=${p.metricas.area}mm² | Forma=${p.metricas.forma_detectada} | Circularidad=${p.metricas.circularity.toFixed(2)}`);
      });
    }
    
    if (selectedObjectForPerforation.horadaciones.length > 0) {
      console.log(`\n📊 RESUMEN DE HORADACIONES:`);
      selectedObjectForPerforation.horadaciones.forEach(h => {
        console.log(`   H${h.id}: Área=${h.metricas.area}mm² | Forma=${h.metricas.forma_detectada} | Circularidad=${h.metricas.circularity.toFixed(2)}`);
      });
    }
    
    // ADR-009: al finalizar, los candidatos no confirmados se consideran revisados
    // y descartados → limpiar para que el chip refleje solo los P/H confirmados.
    selectedObjectForPerforation.phCandidatos = [];

    // IMPORTANTE: Sincronizar con currentAnalyzedObject.obj
    if (currentAnalyzedObject && currentAnalyzedObject.obj) {
      currentAnalyzedObject.obj.perforaciones = selectedObjectForPerforation.perforaciones;
      currentAnalyzedObject.obj.horadaciones = selectedObjectForPerforation.horadaciones;
      currentAnalyzedObject.obj.phCandidatos = [];
      console.log(`✅ Sincronizado con currentAnalyzedObject.obj`);

      // 🔄 SINCRONIZAR AUTOMÁTICAMENTE: Guardar cambios en analisisMorfologicos.objetos
      sincronizarPerforacionesEnMemoria(currentAnalyzedObject.obj);
    }
    
    // Redibujar en morphologicalCanvas
    console.log(`🎨 Llamando a redibujarMorphologicalCanvasConPerforaciones...`);
    redibujarMorphologicalCanvasConPerforaciones(
      selectedObjectForPerforation, 
      currentAnalyzedObject ? currentAnalyzedObject.metricas : null
    );
    
    // ✅ ACTUALIZAR TABLA DE MÉTRICAS (PRESERVANDO EL CANVAS)
    // La tabla comparativa necesita actualizarse para mostrar las métricas de las perforaciones/horadaciones
    // Usamos actualizarTablaMorfologica() que hace backup del canvas antes de llamar a mostrarAnalisisMorfologico
    if (currentAnalyzedObject && currentAnalyzedObject.metricas) {
      console.log(`🔄 Actualizando tabla de métricas con perforaciones/horadaciones...`);
      actualizarTablaMorfologica(selectedObjectForPerforation, currentAnalyzedObject.metricas);
    }
    
    console.log(`✅ Canvas morfológico actualizado con perforaciones/horadaciones (trazados preservados)`);
    
    // Limpiar y cerrar
    trazadosPerforaciones = [];
    contadorTrazados = 0;
    
    UtilityHelpers.setStatus(`${perforaciones.length} perforaciones y ${horadaciones.length} horadaciones aplicadas al objeto.`, false);
    
    // Ocultar canvas ampliado
    ocultarCanvasAmpliadoPerforation();
  }

  /**
   * Cancelar trazado de polígono
   */
  function cancelarPoligonoPerforacion() {
    perforationPolygonPoints = [];
    isDrawingPerforationPolygon = false;
    perforationPolygonClosed = false;
    
    // Redibujar para mostrar solo los trazados completados (sin el actual)
    redibujarPoligonoEnCanvasAmpliado();
    
    UtilityHelpers.setStatus('Trazado del polígono actual cancelado.', false);
  }

  /**
   * Deshacer último punto del polígono
   */
  function deshacerUltimoPuntoPoligono() {
    if (perforationPolygonPoints.length > 0) {
      perforationPolygonPoints.pop();
      
      if (perforationPolygonPoints.length === 0) {
        isDrawingPerforationPolygon = false;
        UtilityHelpers.setStatus('Polígono reiniciado. Haga clic para comenzar de nuevo.', false);
      } else {
        UtilityHelpers.setStatus(`${perforationPolygonPoints.length} puntos. Continúe trazando o doble clic para cerrar.`, false);
      }
      
      UtilityHelpers.redrawCanvas();
    }
  }

  /**
   * Procesar perforación/horadación usando polígono trazado por el usuario
   * El polígono trazado YA ES la perforación - no se buscan píxeles blancos
   */
  function procesarPerforacionConPoligono(obj, polygonPoints) {
    console.log('🔍 Procesando perforación con polígono trazado manualmente:', {
      objeto: obj.id,
      puntos: polygonPoints.length,
      tipo: perforationSelectionType
    });
    
    try {
      // El polígono trazado por el usuario ES la perforación
      // No necesitamos detectar píxeles blancos, solo calcular métricas del polígono
      
      // 1. Validar que hay suficientes puntos
      if (polygonPoints.length < 3) {
        toast.warning('El polígono debe tener al menos 3 puntos.');
        limpiarTrazadoPerforacion();
        return;
      }
      
      // 2. Convertir puntos a formato estándar [x, y]
      const contornoPoligono = polygonPoints.map(p => [p.x, p.y]);
      
      console.log('✅ Polígono del usuario:', contornoPoligono.length, 'puntos');
      
      // 3. Calcular métricas directamente del polígono trazado
      const metricas = calcularMetricasContorno(contornoPoligono, obj);
      
      if (!metricas) {
        toast.error('Error al calcular métricas de la perforación.');
        limpiarTrazadoPerforacion();
        return;
      }
      
      // 🆕 ENRIQUECER Ruta B-polígono con shape_factor, rectangularity, elongation y Feret
      {
        const _a = metricas.area_real   || 0;
        const _p = metricas.perimeter_real || 0;
        const _bb = metricas.tight_bounding_box || {};
        const _w  = _bb.width  || 1;
        const _h  = _bb.height || 1;
        const _sc = (typeof scale !== 'undefined' && scale > 0) ? scale : 1;
        metricas.shape_factor   = _a > 0 ? parseFloat(((_p * _p) / (4 * Math.PI * _a)).toFixed(4)) : null;
        metricas.rectangularity = (_w * _h) > 0 ? parseFloat((_a / (_w * _h)).toFixed(4)) : null;
        metricas.elongation     = parseFloat(Math.abs(1 - Math.min(_w, _h) / Math.max(_w, _h)).toFixed(4));
        // Normalizar a mm para consistencia con Ruta A (calcularMetricasPerforacion)
        metricas.area      = parseFloat((_a * _sc * _sc).toFixed(4));
        metricas.perimeter = parseFloat((_p * _sc).toFixed(4));
        metricas.perimetro = metricas.perimeter; // Alias para compatibilidad
        if (metricas.convex_hull && metricas.convex_hull.length >= 3) {
          try {
            const _fd = MorphometricMetrics.calcularDiametroFeret(metricas.convex_hull);
            metricas.feret_max       = parseFloat((_fd.feret_max       * _sc).toFixed(2));
            metricas.feret_min       = parseFloat((_fd.feret_min       * _sc).toFixed(2));
            metricas.feret_ratio     = parseFloat((_fd.feret_ratio          ).toFixed(4));
            metricas.feret_angulo_max = parseFloat((_fd.angulo_feret_max    ).toFixed(1));
            metricas.feret_angulo_min = parseFloat((_fd.angulo_feret_min    ).toFixed(1));
          } catch(e) { /* no bloquear si Feret falla */ }
        }
      }
      
      console.log('📊 Métricas calculadas:', {
        area: metricas.area_real.toFixed(2),
        perimetro: metricas.perimeter_real.toFixed(2),
        centroide: metricas.centroid
      });
      
      // 4. Calcular bounding box
      let minX = Infinity, maxX = -Infinity;
      let minY = Infinity, maxY = -Infinity;
      
      for (const p of polygonPoints) {
        minX = Math.min(minX, p.x);
        maxX = Math.max(maxX, p.x);
        minY = Math.min(minY, p.y);
        maxY = Math.max(maxY, p.y);
      }
      
      const boundingBox = {
        x: Math.floor(minX),
        y: Math.floor(minY),
        width: Math.ceil(maxX - minX),
        height: Math.ceil(maxY - minY)
      };
      
      // 5. Clasificación morfológica automática (puede ser sobreescrita por usuario)
      const clasificacion = clasificarPerforacionVsHoradacion(metricas, boundingBox, obj);
      
      // 6. Crear objeto de perforación/horadación
      const perforacion = {
        id: (obj.perforaciones.length + obj.horadaciones.length + 1),
        tipo: perforationSelectionType, // 'perforacion' o 'horadacion' - USUARIO DECIDE
        tipoManual: true, // Marcado manualmente por el usuario
        tipoAutomatico: clasificacion.tipo, // Clasificación automática (solo informativa)
        poligonoTrazado: polygonPoints.map(p => ({ x: p.x, y: p.y })), // Polígono original trazado
        contorno: contornoPoligono, // Mismo que polígono trazado (es lo que el usuario dibujó)
        boundingBox: boundingBox,
        metricas: metricas,
        clasificacion: clasificacion,
        timestamp: new Date().toISOString(),
        descripcion: `${perforationSelectionType === 'perforacion' ? 'Perforación' : 'Horadación'} marcada manualmente por el usuario`
      };
      
      // 7. Almacenar en el array correspondiente SEGÚN LO QUE EL USUARIO SELECCIONÓ
      if (perforationSelectionType === 'perforacion') {
        obj.perforaciones.push(perforacion);
        console.log(`✅ PERFORACIÓN #${perforacion.id} añadida al objeto ${obj.id}`);
      } else {
        obj.horadaciones.push(perforacion);
        console.log(`✅ HORADACIÓN #${perforacion.id} añadida al objeto ${obj.id}`);
      }
      
      // 🔄 SINCRONIZAR AUTOMÁTICAMENTE: Guardar cambios en analisisMorfologicos.objetos
      sincronizarPerforacionesEnMemoria(obj);
      
      // 8. Actualizar métricas del objeto (área neta)
      actualizarAreaNetaObjeto(obj);
      
      // 9. Notificar éxito
      const tipoTexto = perforationSelectionType === 'perforacion' ? 'PERFORACIÓN' : 'HORADACIÓN';
      const areaTexto = metricas.area_real.toFixed(1);
      const perimetroTexto = metricas.perimeter_real.toFixed(1);
      
      // Mostrar clasificación automática como sugerencia, pero respetar decisión del usuario
      let mensaje = `${tipoTexto} registrada correctamente.\n`;
      mensaje += `Área: ${areaTexto} px² | Perímetro: ${perimetroTexto} px\n`;
      
      // Si la clasificación automática difiere de la selección manual, informar
      if (clasificacion.tipo !== perforationSelectionType) {
        mensaje += `Nota: La clasificación automática sugiere "${clasificacion.tipo.toUpperCase()}"`;
        mensaje += `(${(clasificacion.confianza*100).toFixed(0)}% confianza), `;
        mensaje += `pero se registró como "${tipoTexto}" según su selección.`;
      } else {
        mensaje += `La clasificación automática coincide: ${clasificacion.mensaje}`;
      }
      
      UtilityHelpers.setStatus(mensaje, false);
      
      // 10. Limpiar trazado
      limpiarTrazadoPerforacion();
      
      // 11. Redibujar canvas morfológico con la perforación marcada
      // IMPORTANTE: Pasar las métricas del objeto analizado si están disponibles
      const metricasObjeto = currentAnalyzedObject ? currentAnalyzedObject.metricas : null;
      redibujarMorphologicalCanvasConPerforaciones(obj, metricasObjeto);
      
      // 12. Redibujar canvas principal
      UtilityHelpers.redrawCanvas();
      
    } catch (error) {
      console.error('❌ Error procesando perforación:', error);
      toast.error('Error al procesar la perforación. Ver consola para detalles.');
      limpiarTrazadoPerforacion();
    }
  }

  /**
   * Limpiar trazado de perforación
   */
  function limpiarTrazadoPerforacion() {
    perforationPolygonPoints = [];
    isDrawingPerforationPolygon = false;
    perforationPolygonClosed = false;
    selectedObjectForPerforation = null;
    
    // Ocultar canvas ampliado
    ocultarCanvasAmpliadoPerforation();
    
    UtilityHelpers.redrawCanvas();
  }

  /**
   * Redibujar morphologicalCanvas mostrando las perforaciones/horadaciones marcadas
   * Esta función SOLO DIBUJA las perforaciones/horadaciones ENCIMA del canvas existente
   * SIN BORRAR los trazos anteriores (contorno, convex hull, ejes, etc.)
   */
  /**
   * Redibujar perforaciones/horadaciones en el canvas morfológico
   * SIN borrar los trazados morfológicos existentes (contornos, ejes, radios, etc.)
   * 
   * @param {Object} obj - Objeto con perforaciones y horadaciones
   * @param {Object} metricas - (OPCIONAL) Métricas morfológicas del objeto para obtener centroide correcto
   */
  function redibujarMorphologicalCanvasConPerforaciones(obj, metricas = null) {
    if (!obj || !morphologicalCanvas || !morphologicalCtx) {
      console.warn('⚠️ No se puede redibujar perforaciones en morphologicalCanvas: elementos no disponibles');
      return;
    }
    
    console.log(`🎨 Dibujando perforaciones/horadaciones ENCIMA del morphologicalCanvas para objeto ${obj.id}`);
    console.log(`   - Perforaciones a dibujar: ${obj.perforaciones?.length || 0}`);
    console.log(`   - Horadaciones a dibujar: ${obj.horadaciones?.length || 0}`);
    console.log(`   - Métricas disponibles: ${!!metricas}`);
    
    // NO LIMPIAMOS EL CANVAS - queremos preservar todo lo que ya está dibujado
    // (contorno verde, convex hull naranja, ejes mayor/menor, centroide, etc.)
    
    // Función auxiliar para obtener coordenadas (soporta {x,y} y [x,y])
    const getX = (p) => p.x !== undefined ? p.x : p[0];
    const getY = (p) => p.y !== undefined ? p.y : p[1];
    
    // Dibujar PERFORACIONES (azul) ENCIMA del canvas existente
    if (obj.perforaciones && obj.perforaciones.length > 0) {
      console.log(`   🟦 Dibujando ${obj.perforaciones.length} perforaciones...`);
      
      // PALETA DE COLORES PARA PERFORACIONES (tonos azules)
      const coloresPerforaciones = [
        { fill: '#0066cc33', stroke: '#0066cc', nombre: 'Azul Primario' },      // P1
        { fill: '#1e88e533', stroke: '#1e88e5', nombre: 'Azul Claro' },        // P2
        { fill: '#3949ab33', stroke: '#3949ab', nombre: 'Azul Índigo' },       // P3
        { fill: '#00acc133', stroke: '#00acc1', nombre: 'Cian' },              // P4
        { fill: '#5e35b133', stroke: '#5e35b1', nombre: 'Púrpura' },           // P5
        { fill: '#1976d233', stroke: '#1976d2', nombre: 'Azul Medio' },        // P6
        { fill: '#0097a733', stroke: '#0097a7', nombre: 'Cian Oscuro' },       // P7
        { fill: '#512da833', stroke: '#512da8', nombre: 'Púrpura Profundo' }   // P8
      ];
      
      obj.perforaciones.forEach((perf, idx) => {
        const contorno = perf.contorno || perf.poligonoTrazado;
        if (!contorno || contorno.length === 0) {
          console.warn(`   ⚠️ Perforación ${perf.id} sin contorno válido`);
          return;
        }
        
        // Seleccionar color según índice (con ciclo si hay más de 8)
        const colorIdx = idx % coloresPerforaciones.length;
        const color = coloresPerforaciones[colorIdx];
        
        // Guardar color en el objeto para referencia
        if (!perf.color) {
          perf.color = color;
        }
        
        // Dibujar área rellena semi-transparente
        morphologicalCtx.fillStyle = color.fill; // 20% opacidad
        morphologicalCtx.beginPath();
        
        const firstPt = contorno[0];
        const x0 = getX(firstPt) - obj.minX;
        const y0 = getY(firstPt) - obj.minY;
        morphologicalCtx.moveTo(x0, y0);
        
        for (let i = 1; i < contorno.length; i++) {
          const pt = contorno[i];
          const xi = getX(pt) - obj.minX;
          const yi = getY(pt) - obj.minY;
          morphologicalCtx.lineTo(xi, yi);
        }
        morphologicalCtx.closePath();
        morphologicalCtx.fill();
        
        // Dibujar contorno sólido con color distintivo
        morphologicalCtx.strokeStyle = color.stroke;
        morphologicalCtx.lineWidth = 2.5;
        morphologicalCtx.stroke();
        
        console.log(`   ✅ Perforación P${perf.id} dibujada con ${color.nombre} (${contorno.length} puntos)`);
      });
    }
    
    // Dibujar HORADACIONES (verde) ENCIMA del canvas existente
    if (obj.horadaciones && obj.horadaciones.length > 0) {
      console.log(`   🟩 Dibujando ${obj.horadaciones.length} horadaciones...`);
      
      // PALETA DE COLORES PARA HORADACIONES (tonos verdes/tierra)
      const coloresHoradaciones = [
        { fill: '#28a74533', stroke: '#28a745', nombre: 'Verde Primario' },    // H1
        { fill: '#66bb6a33', stroke: '#66bb6a', nombre: 'Verde Claro' },       // H2
        { fill: '#43a04733', stroke: '#43a047', nombre: 'Verde Medio' },       // H3
        { fill: '#7cb34233', stroke: '#7cb342', nombre: 'Lima' },              // H4
        { fill: '#00897b33', stroke: '#00897b', nombre: 'Teal' },              // H5
        { fill: '#8d6e6333', stroke: '#8d6e63', nombre: 'Tierra' },            // H6
        { fill: '#558b2f33', stroke: '#558b2f', nombre: 'Verde Oliva' },       // H7
        { fill: '#6d4c4133', stroke: '#6d4c41', nombre: 'Marrón' }             // H8
      ];
      
      obj.horadaciones.forEach((hora, idx) => {
        const contorno = hora.contorno || hora.poligonoTrazado;
        if (!contorno || contorno.length === 0) {
          console.warn(`   ⚠️ Horadación ${hora.id} sin contorno válido`);
          return;
        }
        
        // Seleccionar color según índice (con ciclo si hay más de 8)
        const colorIdx = idx % coloresHoradaciones.length;
        const color = coloresHoradaciones[colorIdx];
        
        // Guardar color en el objeto para referencia
        if (!hora.color) {
          hora.color = color;
        }
        
        // Dibujar área rellena semi-transparente
        morphologicalCtx.fillStyle = color.fill; // 20% opacidad
        morphologicalCtx.beginPath();
        
        const firstPt = contorno[0];
        const x0 = getX(firstPt) - obj.minX;
        const y0 = getY(firstPt) - obj.minY;
        morphologicalCtx.moveTo(x0, y0);
        
        for (let i = 1; i < contorno.length; i++) {
          const pt = contorno[i];
          const xi = getX(pt) - obj.minX;
          const yi = getY(pt) - obj.minY;
          morphologicalCtx.lineTo(xi, yi);
        }
        morphologicalCtx.closePath();
        morphologicalCtx.fill();
        
        // Dibujar contorno sólido con color distintivo
        morphologicalCtx.strokeStyle = color.stroke;
        morphologicalCtx.lineWidth = 2.5;
        morphologicalCtx.stroke();
        
        console.log(`   ✅ Horadación H${hora.id} dibujada con ${color.nombre} (${contorno.length} puntos)`);
      });
    }
    
    // ============================================================================
    // 🆕 VISUALIZACIÓN DE CENTROIDES Y ANÁLISIS DE DISTRIBUCIÓN ESPACIAL
    // ============================================================================
    // Esta sección dibuja elementos adicionales para análisis de distribución espacial:
    //
    // 1. CENTROIDE DEL OBJETO (● grande naranja con borde blanco)
    //    - Representa el centro geométrico del Convex Hull (forma completa)
    //    - Sirve como punto de referencia para análisis de simetría
    //
    // 2. CENTROIDES DE CADA P/H (⬤ pequeños azul/verde)
    //    - Centro geométrico de cada perforación/horadación
    //    - Calculado desde el polígono trazado manualmente
    //    - Permite identificar el punto exacto de cada característica
    //
    // 3. LÍNEAS PUNTEADAS (azul claro/verde claro)
    //    - Conectan centroide del objeto con cada centroide de P/H
    //    - Visualizan distribución espacial y simetría
    //    - Útil para identificar patrones (anillo uniforme, agrupado, disperso)
    //    - Permite evaluar distancias relativas entre P/H
    //
    // Estos elementos son esenciales para el análisis comparativo que incluye:
    // - Simetría radial/bilateral
    // - Patrones de agrupamiento (clustering)
    // - Regularidad en distribución angular
    // - Clasificación funcional del objeto
    // ============================================================================
    // Dibujar líneas desde el centroide del objeto hacia cada perforación/horadación
    
    if ((obj.perforaciones && obj.perforaciones.length > 0) || (obj.horadaciones && obj.horadaciones.length > 0)) {
      // ============================================================================
      // CALCULAR CENTROIDE DEL OBJETO (CONVEX HULL)
      // ============================================================================
      // Si tenemos métricas, usar el centroide del Convex Hull (exacto)
      // Si no, aproximar usando el centro del bounding box (menos preciso)
      // ============================================================================
      let centroidObjX, centroidObjY;
      
      if (metricas && metricas._contour_data && metricas._contour_data.metrics) {
        // ✅ MÉTODO CORRECTO: Usar centroide del Convex Hull de las métricas
        const centroidHull = metricas._contour_data.metrics.centroid_hull || 
                            metricas._contour_data.metrics.centroid;
        
        if (centroidHull && centroidHull.length >= 2) {
          // Convertir de coordenadas absolutas a coordenadas del canvas morfológico
          centroidObjX = centroidHull[0] - obj.minX;
          centroidObjY = centroidHull[1] - obj.minY;
          
          console.log(`   ✅ Usando centroide del Convex Hull desde métricas:`);
          console.log(`      Absoluto: [${centroidHull[0].toFixed(2)}, ${centroidHull[1].toFixed(2)}]`);
          console.log(`      Relativo: (${centroidObjX.toFixed(2)}, ${centroidObjY.toFixed(2)})`);
        } else {
          // Fallback: centro del bounding box
          centroidObjX = obj.width / 2;
          centroidObjY = obj.height / 2;
          console.warn(`   ⚠️ Centroide hull no válido, usando centro del bounding box: (${centroidObjX}, ${centroidObjY})`);
        }
      } else {
        // ⚠️ MÉTODO APROXIMADO: Centro del bounding box (cuando no hay métricas)
        centroidObjX = obj.width / 2;
        centroidObjY = obj.height / 2;
        console.warn(`   ⚠️ Métricas no disponibles, aproximando centroide con centro del bounding box: (${centroidObjX}, ${centroidObjY})`);
      }
      
      // ============================================================================
      // ELEMENTO 1: DIBUJAR CENTROIDE DEL OBJETO (● NARANJA GRANDE)
      // ============================================================================
      // Punto de referencia central para análisis de distribución espacial
      // Este es el mismo centroide del Convex Hull dibujado anteriormente,
      // pero se redibuja para asegurar que quede visible encima de todo
      // ============================================================================
      morphologicalCtx.fillStyle = '#ff6600'; // Naranja
      morphologicalCtx.beginPath();
      morphologicalCtx.arc(centroidObjX, centroidObjY, 6, 0, 2 * Math.PI);
      morphologicalCtx.fill();
      
      // Borde blanco para contraste
      morphologicalCtx.strokeStyle = '#ffffff';
      morphologicalCtx.lineWidth = 2;
      morphologicalCtx.stroke();
      
      console.log(`   🎯 Centroide objeto dibujado en (${centroidObjX.toFixed(1)}, ${centroidObjY.toFixed(1)})`);
      
      // ============================================================================
      // ELEMENTOS 2 y 3: LÍNEAS PUNTEADAS + CENTROIDES DE PERFORACIONES
      // ============================================================================
      // Líneas visualizan distribución espacial desde centro del objeto
      // Centroides pequeños (⬤) marcan el centro exacto de cada P/H
      // ============================================================================
      morphologicalCtx.setLineDash([5, 5]);
      morphologicalCtx.lineWidth = 1.5;
      
      // Líneas a perforaciones (azul claro)
      if (obj.perforaciones && obj.perforaciones.length > 0) {
        morphologicalCtx.strokeStyle = '#66b3ff'; // Azul claro
        
        obj.perforaciones.forEach(perf => {
          const centPerfX = (perf.metricas?.centroid?.[0] || perf.metricas?.centroid?.x || 0) - obj.minX;
          const centPerfY = (perf.metricas?.centroid?.[1] || perf.metricas?.centroid?.y || 0) - obj.minY;
          
          // Dibujar línea punteada desde centroide objeto → centroide perforación
          morphologicalCtx.beginPath();
          morphologicalCtx.moveTo(centroidObjX, centroidObjY);
          morphologicalCtx.lineTo(centPerfX, centPerfY);
          morphologicalCtx.stroke();
          
          // Dibujar punto del centroide de la perforación (⬤ azul pequeño)
          morphologicalCtx.fillStyle = '#0066cc';
          morphologicalCtx.beginPath();
          morphologicalCtx.arc(centPerfX, centPerfY, 4, 0, 2 * Math.PI);
          morphologicalCtx.fill();
        });
      }
      
      // ============================================================================
      // ELEMENTOS 2 y 3: LÍNEAS PUNTEADAS + CENTROIDES DE HORADACIONES
      // ============================================================================
      // Líneas a horadaciones (verde claro)
      if (obj.horadaciones && obj.horadaciones.length > 0) {
        morphologicalCtx.strokeStyle = '#90ee90'; // Verde claro
        
        obj.horadaciones.forEach(hora => {
          const centHoraX = (hora.metricas?.centroid?.[0] || hora.metricas?.centroid?.x || 0) - obj.minX;
          const centHoraY = (hora.metricas?.centroid?.[1] || hora.metricas?.centroid?.y || 0) - obj.minY;
          
          // Dibujar línea punteada desde centroide objeto → centroide horadación
          morphologicalCtx.beginPath();
          morphologicalCtx.moveTo(centroidObjX, centroidObjY);
          morphologicalCtx.lineTo(centHoraX, centHoraY);
          morphologicalCtx.stroke();
          
          // Dibujar punto del centroide de la horadación (⬤ verde pequeño)
          morphologicalCtx.fillStyle = '#28a745';
          morphologicalCtx.beginPath();
          morphologicalCtx.arc(centHoraX, centHoraY, 4, 0, 2 * Math.PI);
          morphologicalCtx.fill();
        });
      }
      
      // Restaurar línea sólida
      morphologicalCtx.setLineDash([]);
      
      console.log(`   ✅ Líneas de distancia desde centroide dibujadas`);
    }
    
    // ============================================================================
    // ACTUALIZAR LEYENDA DINÁMICA CON PERFORACIONES/HORADACIONES
    // ============================================================================
    actualizarLeyendaPH(obj);
    
    console.log(`✅ Perforaciones/Horadaciones dibujadas ENCIMA del canvas morfológico preservando trazos anteriores`);
  }

  /**
   * Actualizar leyenda gráfica con colores y métricas de Perforaciones/Horadaciones
   * ✅ TODAS LAS MÉTRICAS EN MILÍMETROS (mm, mm²)
   * @param {Object} obj - Objeto con perforaciones y horadaciones
   */
  function actualizarLeyendaPH(obj) {
    console.log(`📋 Actualizando leyenda de P/H...`);
    
    // Actualizar leyenda de PERFORACIONES
    const leyendaPerf = document.getElementById('leyendaPerforaciones');
    if (leyendaPerf) {
      if (obj.perforaciones && obj.perforaciones.length > 0) {
        let htmlPerf = '';
        obj.perforaciones.forEach((perf, idx) => {
          // ✅ TODAS LAS MÉTRICAS EN MILÍMETROS
          const areaMm = perf.metricas?.area || 0;
          const perimetroMm = perf.metricas?.perimetro || perf.metricas?.perimeter || 0;
          const forma = perf.metricas?.forma_detectada || 'N/A';
          const circularidad = perf.metricas?.circularity || 0;
          
          const colorStroke = perf.color?.stroke || '#0066cc';
          const colorNombre = perf.color?.nombre || 'Azul';
          
          htmlPerf += `
            <div style="padding: 4px 0; padding-left: 8px; border-left: 3px solid ${colorStroke}; margin: 2px 0; background: rgba(0,102,204,0.05);">
              <div style="font-weight: bold;">
                <span style="color: ${colorStroke}; font-size: 14px;">█</span> 
                <strong>P${perf.id}</strong> 
                <span style="color: ${colorStroke}; font-size: 9px;">(${colorNombre})</span>
                <span style="color: #666; font-size: 10px; margin-left: 6px;">${forma}</span>
              </div>
              <div style="font-size: 10px; color: #555; margin-left: 20px;">
                Área: <strong>${areaMm.toFixed(2)} mm²</strong>• 
                Perímetro: ${perimetroMm.toFixed(2)} mm • 
                ⭕ Circularidad: ${(circularidad * 100).toFixed(0)}%
              </div>
            </div>
          `;
        });
        leyendaPerf.innerHTML = htmlPerf;
      } else {
        leyendaPerf.innerHTML = `
          <span style="padding: 2px 0; padding-left: 8px; color: #6c757d; font-style: italic; grid-column: 1 / -1;">
            (Sin perforaciones detectadas)
          </span>
        `;
      }
    }
    
    // Actualizar leyenda de HORADACIONES
    const leyendaHora = document.getElementById('leyendaHoradaciones');
    if (leyendaHora) {
      if (obj.horadaciones && obj.horadaciones.length > 0) {
        let htmlHora = '';
        obj.horadaciones.forEach((hora, idx) => {
          // ✅ TODAS LAS MÉTRICAS EN MILÍMETROS
          const areaMm = hora.metricas?.area || 0;
          const perimetroMm = hora.metricas?.perimetro || hora.metricas?.perimeter || 0;
          const forma = hora.metricas?.forma_detectada || 'N/A';
          const circularidad = hora.metricas?.circularity || 0;
          
          const colorStroke = hora.color?.stroke || '#28a745';
          const colorNombre = hora.color?.nombre || 'Verde';
          
          htmlHora += `
            <div style="padding: 4px 0; padding-left: 8px; border-left: 3px solid ${colorStroke}; margin: 2px 0; background: rgba(40,167,69,0.05);">
              <div style="font-weight: bold;">
                <span style="color: ${colorStroke}; font-size: 14px;">█</span> 
                <strong>H${hora.id}</strong> 
                <span style="color: ${colorStroke}; font-size: 9px;">(${colorNombre})</span>
                <span style="color: #666; font-size: 10px; margin-left: 6px;">${forma}</span>
              </div>
              <div style="font-size: 10px; color: #555; margin-left: 20px;">
                Área: <strong>${areaMm.toFixed(2)} mm²</strong>• 
                Perímetro: ${perimetroMm.toFixed(2)} mm • 
                ⭕ Circularidad: ${(circularidad * 100).toFixed(0)}%
              </div>
            </div>
          `;
        });
        leyendaHora.innerHTML = htmlHora;
      } else {
        leyendaHora.innerHTML = `
          <span style="padding: 2px 0; padding-left: 8px; color: #6c757d; font-style: italic; grid-column: 1 / -1;">
            (Sin horadaciones detectadas)
          </span>
        `;
      }
    }
    
    console.log(`   ✅ Leyenda actualizada: ${obj.perforaciones?.length || 0} perforaciones, ${obj.horadaciones?.length || 0} horadaciones`);
    
    // ❌ LÓGICA DE BOTÓN P/H ELIMINADA - Ahora incluido en exportación unificada

    // 💾 AUTO-GUARDAR CANVAS POST-P/H — actualiza el respaldo con las marcas de
    // perforaciones/horadaciones ya dibujadas.
    requestAnimationFrame(() => {
      const _objTarget = (typeof objects !== 'undefined' && objects)
        ? (objects.find(o => o.id === obj.id) || obj)
        : obj;
      guardarCanvasEnObjeto(_objTarget);
    });
  }

  /**
   * Procesar perforación/horadación detectada (VERSIÓN ANTIGUA CON RECTÁNGULO)
   * Detecta píxeles BLANCOS (fondo) dentro del área seleccionada del objeto
   * NOTA: Esta función se mantiene por compatibilidad pero ya no se usa
   */
  function procesarPerforacion(obj, area) {
    console.log('🔍 Procesando perforación/horadación:', {
      objeto: obj.id,
      area: area,
      tipo: perforationSelectionType
    });
    
    try {
      // 1. Crear canvas temporal para extraer la región
      const tempCanvas = canvasPool.getCanvas(area.width, area.height);
      const tempCtx = tempCanvas.getContext('2d');
      
      // 2. Extraer región de la imagen original
      tempCtx.drawImage(
        image,
        area.x, area.y, area.width, area.height,
        0, 0, area.width, area.height
      );
      
      // 3. Obtener datos de imagen
      const imageData = tempCtx.getImageData(0, 0, area.width, area.height);
      const data = imageData.data;
      
      // 4. Crear máscara INVERTIDA: detectar píxeles BLANCOS (fondo) dentro del objeto
      // Esto es lo opuesto a la detección normal de objetos
      const binaryMask = new Uint8Array(area.width * area.height);
      let whitePixels = 0;
      
      // Umbral para considerar un píxel como "blanco" (fondo/perforación)
      const WHITE_THRESHOLD = 240;
      
      for (let i = 0; i < data.length; i += 4) {
        const r = data[i];
        const g = data[i + 1];
        const b = data[i + 2];
        const idx = i / 4;
        
        // Detectar píxeles BLANCOS (inversión de lógica)
        // Si todos los canales son suficientemente claros, es fondo/perforación
        if (r >= WHITE_THRESHOLD && g >= WHITE_THRESHOLD && b >= WHITE_THRESHOLD) {
          binaryMask[idx] = 1; // Marcar como perforación
          whitePixels++;
        } else {
          binaryMask[idx] = 0; // Marcar como objeto sólido
        }
      }
      
      console.log(`📊 Píxeles blancos detectados: ${whitePixels} de ${binaryMask.length} (${(whitePixels/binaryMask.length*100).toFixed(1)}%)`);
      
      // Validar que hay suficientes píxeles blancos
      if (whitePixels < 10) {
        toast.warning('No se detectó una perforación clara. Intenta con un área con más píxeles blancos.');
        canvasPool.releaseCanvas(tempCanvas);
        UtilityHelpers.redrawCanvas();
        return;
      }
      
      // 5. Aplicar morfología para limpiar la máscara
      const maskaCerrada = aplicarCierre(binaryMask, area.width, area.height, 2);
      const mascaraLimpia = eliminarComponentesPequenos(maskaCerrada, area.width, area.height, 5);
      
      // 6. Trazar contorno de la perforación usando Moore
      const contorno = ContourExtraction.trazarContornoMoore(mascaraLimpia, area.width, area.height);
      
      if (!contorno || contorno.length < 4) {
        toast.warning('No se pudo trazar el contorno. Intenta con un área más grande o con mayor contraste.');
        canvasPool.releaseCanvas(tempCanvas);
        UtilityHelpers.redrawCanvas();
        return;
      }
      
      console.log(`✅ Contorno trazado: ${contorno.length} puntos`);
      
      // 7. Convertir contorno a coordenadas globales (relativas a la imagen completa)
      const contornoGlobal = contorno.map(p => [
        p[0] + area.x,
        p[1] + area.y
      ]);
      
      // 8. Calcular métricas del contorno
      const metricas = calcularMetricasContorno(contornoGlobal, obj);
      
      if (!metricas) {
        toast.error('Error al calcular métricas de la perforación.');
        canvasPool.releaseCanvas(tempCanvas);
        UtilityHelpers.redrawCanvas();
        return;
      }
      
      // 🆕 ENRIQUECER Ruta B-rectángulo con shape_factor, rectangularity, elongation y Feret
      {
        const _a = metricas.area_real   || 0;
        const _p = metricas.perimeter_real || 0;
        const _bb = metricas.tight_bounding_box || {};
        const _w  = _bb.width  || 1;
        const _h  = _bb.height || 1;
        const _sc = (typeof scale !== 'undefined' && scale > 0) ? scale : 1;
        metricas.shape_factor   = _a > 0 ? parseFloat(((_p * _p) / (4 * Math.PI * _a)).toFixed(4)) : null;
        metricas.rectangularity = (_w * _h) > 0 ? parseFloat((_a / (_w * _h)).toFixed(4)) : null;
        metricas.elongation     = parseFloat(Math.abs(1 - Math.min(_w, _h) / Math.max(_w, _h)).toFixed(4));
        // Normalizar a mm para consistencia con Ruta A (calcularMetricasPerforacion)
        metricas.area      = parseFloat((_a * _sc * _sc).toFixed(4));
        metricas.perimeter = parseFloat((_p * _sc).toFixed(4));
        metricas.perimetro = metricas.perimeter; // Alias para compatibilidad
        if (metricas.convex_hull && metricas.convex_hull.length >= 3) {
          try {
            const _fd = MorphometricMetrics.calcularDiametroFeret(metricas.convex_hull);
            metricas.feret_max       = parseFloat((_fd.feret_max       * _sc).toFixed(2));
            metricas.feret_min       = parseFloat((_fd.feret_min       * _sc).toFixed(2));
            metricas.feret_ratio     = parseFloat((_fd.feret_ratio          ).toFixed(4));
            metricas.feret_angulo_max = parseFloat((_fd.angulo_feret_max    ).toFixed(1));
            metricas.feret_angulo_min = parseFloat((_fd.angulo_feret_min    ).toFixed(1));
          } catch(e) { /* no bloquear si Feret falla */ }
        }
      }
      
      // 9. Clasificación morfológica automática (puede ser sobreescrita por usuario)
      const clasificacion = clasificarPerforacionVsHoradacion(metricas, area, obj);
      
      // 10. Crear objeto de perforación/horadación
      const perforacion = {
        id: (obj.perforaciones.length + obj.horadaciones.length + 1),
        tipo: perforationSelectionType, // 'perforacion' o 'horadacion'
        tipoManual: true, // Marcado manualmente por el usuario
        tipoAutomatico: clasificacion.tipo, // Clasificación automática
        area: area, // Área de selección original
        contorno: contornoGlobal, // Contorno en coordenadas globales
        metricas: metricas,
        clasificacion: clasificacion,
        timestamp: new Date().toISOString()
      };
      
      // 11. Almacenar en el array correspondiente
      if (perforationSelectionType === 'perforacion') {
        obj.perforaciones.push(perforacion);
        console.log(`✅ Perforación #${perforacion.id} añadida al objeto ${obj.id}`);
      } else {
        obj.horadaciones.push(perforacion);
        console.log(`✅ Horadación #${perforacion.id} añadida al objeto ${obj.id}`);
      }
      
      // 12. Actualizar métricas del objeto (área neta)
      actualizarAreaNetaObjeto(obj);
      
      // 13. Liberar recursos
      canvasPool.releaseCanvas(tempCanvas);
      
      // 14. Notificar éxito
      const tipoTexto = perforationSelectionType === 'perforacion' ? 'PERFORACIÓN' : 'HORADACIÓN';
      UtilityHelpers.setStatus(`${tipoTexto} detectada correctamente. Área: ${metricas.area_real.toFixed(1)} px². ${clasificacion.mensaje}`, false);
      
      // 15. Redibujar canvas con la perforación
      UtilityHelpers.redrawCanvas();
      
      // 16. Limpiar selección
      selectedObjectForPerforation = null;
      
    } catch (error) {
      console.error('❌ Error procesando perforación:', error);
      toast.error('Error al procesar la perforación. Ver consola para detalles.');
      UtilityHelpers.redrawCanvas();
    }
  }

  /**
   * Clasificar automáticamente si es perforación o horadación
   * Basado en características morfológicas
   */
  function clasificarPerforacionVsHoradacion(metricas, area, obj) {
    // Características para clasificación:
    const areaPerforacion = metricas.area_real;
    const perimetro = metricas.perimeter_real;
    const convexHullArea = metricas.convex_hull_area;
    
    // 1. Circularidad (cuán circular es)
    const circularidad = (4 * Math.PI * areaPerforacion) / (perimetro * perimetro);
    
    // 2. Solidez (ratio área real / área convex hull)
    const solidez = convexHullArea > 0 ? areaPerforacion / convexHullArea : 0;
    
    // 3. Ratio de aspecto
    const boundingBox = metricas.tight_bounding_box;
    const aspectRatio = boundingBox.width / boundingBox.height;
    const isElongated = aspectRatio > 2.0 || aspectRatio < 0.5;
    
    // 4. Tamaño relativo al objeto padre
    const areaObjeto = obj.area || (obj.width * obj.height);
    const ratioTamaño = areaPerforacion / areaObjeto;
    
    console.log('📊 Análisis morfológico:', {
      circularidad: circularidad.toFixed(3),
      solidez: solidez.toFixed(3),
      aspectRatio: aspectRatio.toFixed(2),
      ratioTamaño: (ratioTamaño * 100).toFixed(1) + '%'
    });
    
    // CRITERIOS DE CLASIFICACIÓN
    let tipo = 'horadacion'; // Por defecto
    let confianza = 0.5;
    let caracteristicas = [];
    
    // Criterio 1: Alta circularidad + buena solidez = PERFORACIÓN
    if (circularidad > 0.75 && solidez > 0.85) {
      tipo = 'perforacion';
      confianza = 0.9;
      caracteristicas.push('forma circular regular');
      caracteristicas.push('contorno continuo');
    }
    // Criterio 2: Baja solidez = forma irregular = HORADACIÓN
    else if (solidez < 0.7) {
      tipo = 'horadacion';
      confianza = 0.85;
      caracteristicas.push('forma irregular');
      caracteristicas.push('posible depresión parcial');
    }
    // Criterio 3: Elongada + baja circularidad = HORADACIÓN
    else if (isElongated && circularidad < 0.6) {
      tipo = 'horadacion';
      confianza = 0.8;
      caracteristicas.push('forma alargada');
      caracteristicas.push('posible marca de uso');
    }
    // Criterio 4: Circularidad moderada = probablemente PERFORACIÓN
    else if (circularidad > 0.6 && solidez > 0.75) {
      tipo = 'perforacion';
      confianza = 0.75;
      caracteristicas.push('forma relativamente circular');
    }
    
    // Ajustar por tamaño relativo
    if (ratioTamaño < 0.01) {
      caracteristicas.push('muy pequeña relativa al objeto');
    } else if (ratioTamaño > 0.3) {
      caracteristicas.push('grande relativa al objeto');
    }
    
    const mensaje = `Clasificación automática: ${tipo.toUpperCase()} (${(confianza*100).toFixed(0)}% confianza). ${caracteristicas.join(', ')}.`;
    
    return {
      tipo: tipo,
      confianza: confianza,
      circularidad: circularidad,
      solidez: solidez,
      aspectRatio: aspectRatio,
      ratioTamaño: ratioTamaño,
      caracteristicas: caracteristicas,
      mensaje: mensaje
    };
  }

  /**
   * Actualizar área neta del objeto restando perforaciones
   */
  function actualizarAreaNetaObjeto(obj) {
    // Área bruta (original, sin restar perforaciones) — siempre en px² como referencia
    if (!obj.area_bruta) {
      obj.area_bruta = obj.area || 0;
    }
    
    // Calcular área total de perforaciones (con deduplicación por contención)
    // areaTotalPH devuelve mm² cuando hay escala configurada, px² si no hay escala
    const _phef = calcularAreaEfectivaPH(obj.perforaciones || [], obj.horadaciones || []);
    const areaPerforaciones = _phef.areaTotalPH;
    
    // FUENTE CANÓNICA DE ÁREA BRUTA:
    // Usar metricas.area (Convex Hull, Shoelace × scale²) en lugar del conteo crudo de píxeles
    // (obj.area × scale²). Esto garantiza que area_neta sea consistente con lo que muestran
    // "Dimensiones Básicas" y el cálculo en calcularAnalisisComparativo.
    const _scaleSq = (typeof scale !== 'undefined' && scale > 0) ? scale * scale : 1;
    const _hullAreaMM2 = parseFloat(obj.metricas?.area || 0);
    const areaBrutaConvertida = _hullAreaMM2 > 0
      ? _hullAreaMM2                // ← Convex Hull area (misma fuente que Dims Básicas) [mm²]
      : obj.area_bruta * _scaleSq;  // ← fallback: píxeles × escala² si aún no hay métricas
    
    // Área neta = Área bruta (convertida) - Perforaciones (misma unidad)
    obj.area_neta = areaBrutaConvertida - areaPerforaciones;
    obj.area_perforaciones_total = areaPerforaciones;
    obj.num_perforaciones = obj.perforaciones ? obj.perforaciones.length : 0;
    obj.num_horadaciones = obj.horadaciones ? obj.horadaciones.length : 0;

    // Perímetro neto = perímetro externo objeto + Σ perímetros P/H (todas las fronteras reales)
    const _scaleP = (typeof scale !== 'undefined' && scale > 0) ? scale : 1;
    const _getPer = (ph) => {
      if (ph.metricas?.perimeter)      return parseFloat(ph.metricas.perimeter) || 0;       // mm (finalizarTrazados)
      if (ph.metricas?.perimeter_real) return (parseFloat(ph.metricas.perimeter_real)||0) * _scaleP; // px→mm
      if (ph.perimetro !== undefined)  return parseFloat(ph.perimetro) || 0;
      return 0;
    };
    const _periExterno = parseFloat(obj.metricas?.perimeter || obj.perimetro || 0);
    const _periPH = [...(obj.perforaciones||[]), ...(obj.horadaciones||[])].reduce((s,ph) => s + _getPer(ph), 0);
    obj.perimetro_neto = _periExterno + _periPH;
    obj.perimetro_bruto = _periExterno;
    obj.perimetro_perforaciones_total = _periPH;

    const unidad = (_scaleSq > 1) ? 'mm²' : 'px²';
    console.log(`📊 Área actualizada para ${obj.id}:`, {
      area_bruta: areaBrutaConvertida.toFixed(1) + ` ${unidad}`,
      area_perforaciones: areaPerforaciones.toFixed(1) + ` ${unidad}`,
      area_neta: obj.area_neta.toFixed(1) + ` ${unidad}`,
      perforaciones: obj.num_perforaciones,
      horadaciones: obj.num_horadaciones
    });
  }

