  // === FUNCIÓN PARA COMPARAR GEOMETRÍA REAL VS CAJA CONTENEDORA ===
  function compararGeometriaReal(obj, metricas) {
    if (!metricas.contour_extraction_successful) {
      console.log(`⚠️ Objeto ${obj.id}: Usando aproximación rectangular (no se pudo extraer contorno real)`);
      return;
    }
    
    // Métricas de caja contenedora (método tradicional)
    const areaRectangular = obj.width * obj.height;
    const perimetroRectangular = 2 * (obj.width + obj.height);
    const circularidadRectangular = (4 * Math.PI * areaRectangular) / (perimetroRectangular * perimetroRectangular);
    
    // Métricas de contorno real
    const areaReal = parseFloat(metricas.area_real_px);
    const perimetroReal = parseFloat(metricas.perimeter_real_px);
    const circularidadReal = parseFloat(metricas.circularity_real);
    
    // Calcular diferencias porcentuales
    const diferenciaArea = ((Math.abs(areaReal - areaRectangular) / areaRectangular) * 100).toFixed(1);
    const diferenciaPerimetro = ((Math.abs(perimetroReal - perimetroRectangular) / perimetroRectangular) * 100).toFixed(1);
    const diferenciaCircularidad = ((Math.abs(circularidadReal - circularidadRectangular) / circularidadRectangular) * 100).toFixed(1);
    
    console.log(`
=====================================================
   COMPARACIÓN DETALLADA - OBJETO ${obj.id}
=====================================================

MÉTODO TRADICIONAL (Caja Contenedora):
   • Área: ${areaRectangular.toFixed(1)} px²
   • Perímetro: ${perimetroRectangular.toFixed(1)} px  
   • Circularidad: ${circularidadRectangular.toFixed(4)}
   • Método: Aproximación rectangular

MÉTODO MAO (Contorno Real):
   • Área: ${areaReal.toFixed(1)} px² 
   • Perímetro: ${perimetroReal.toFixed(1)} px
   • Circularidad: ${circularidadReal}
   • Método: ${metricas.analysis_method}

DIFERENCIAS PORCENTUALES:
   • Área: ${diferenciaArea}% de diferencia
   • Perímetro: ${diferenciaPerimetro}% de diferencia  
   • Circularidad: ${diferenciaCircularidad}% de diferencia

ANÁLISIS DE PRECISIÓN:
   ${diferenciaArea >10 ? 'DIFERENCIA SIGNIFICATIVA en área (>10%)': 'Diferencia moderada en área (<10%)'}
   ${diferenciaPerimetro >15 ? 'DIFERENCIA SIGNIFICATIVA en perímetro (>15%)': 'Diferencia moderada en perímetro (<15%)'}
   ${diferenciaCircularidad >20 ? 'DIFERENCIA CRÍTICA en circularidad (>20%)': 'Diferencia aceptable en circularidad (<20%)'}

INTERPRETACIÓN:
   ${diferenciaArea > 15 || diferenciaPerimetro > 20 ? 
     'FORMA COMPLEJA: El contorno real revela geometría muy diferente a la caja rectangular':
     'FORMA SIMPLE: La aproximación rectangular es relativamente precisa'}

FORMA DETECTADA: ${metricas.forma_detectada} (Confianza: ${(parseFloat(metricas.forma_confianza) * 100).toFixed(1)}%)
   Razón: ${metricas.forma_razon}
=====================================================`);
  }
  
