  // Actualizar estadísticas de la tabla
  function actualizarEstadisticasTabla(objetos) {
    document.getElementById('totalObjects').textContent = objetos.length;
    document.getElementById('visibleColumns').textContent = document.querySelectorAll('th:not(.hidden)').length;
    
    // Calcular área promedio
    let sumaArea = 0;
    objetos.forEach(obj => {
      if (obj.metrics && obj.metrics.area_real_px) {
        sumaArea += parseFloat(obj.metrics.area_real_px);
      }
    });
    const areaPromedio = (sumaArea / objetos.length).toFixed(1);
    document.getElementById('avgArea').textContent = `${areaPromedio} px²`;
    
    // Última actualización
    const ahora = new Date();
    document.getElementById('lastAnalysis').textContent = ahora.toLocaleTimeString();
  }
  
  // Agregar event listeners para funcionalidad de la tabla
  function agregarEventListenersTabla() {
    // Ordenamiento de columnas
    document.querySelectorAll('th.sortable').forEach(th => {
      th.addEventListener('click', function() {
        const column = this.dataset.column;
        ordenarTabla(column);
      });
    });
    
    // Búsqueda
    const tableSearch = document.getElementById('tableSearch');
    if (tableSearch) {
      tableSearch.addEventListener('input', function() {
        filtrarTabla(this.value);
      });
    }
    
    // Filtros por categoría
    document.querySelectorAll('.category-tab').forEach(tab => {
      tab.addEventListener('click', function() {
        document.querySelectorAll('.category-tab').forEach(t => t.classList.remove('active'));
        this.classList.add('active');
        const category = this.dataset.category;
        filtrarPorCategoria(category);
      });
    });
  }
  
  // Ordenar tabla por columna
  let ordenActual = { columna: null, ascendente: true };
  
  function ordenarTabla(columna) {
    const tbody = document.getElementById('metricsTableBody');
    const filas = Array.from(tbody.querySelectorAll('tr'));
    
    // Determinar dirección de ordenamiento
    if (ordenActual.columna === columna) {
      ordenActual.ascendente = !ordenActual.ascendente;
    } else {
      ordenActual.columna = columna;
      ordenActual.ascendente = true;
    }
    
    // Obtener índice de columna
    const headers = Array.from(document.querySelectorAll('#metricsTableHeader th'));
    const colIndex = headers.findIndex(th => th.dataset.column === columna);
    
    // Ordenar filas
    filas.sort((a, b) => {
      const cellA = a.cells[colIndex].textContent.trim();
      const cellB = b.cells[colIndex].textContent.trim();
      
      // Manejar valores numéricos
      const numA = parseFloat(cellA.replace(/[^0-9.-]/g, ''));
      const numB = parseFloat(cellB.replace(/[^0-9.-]/g, ''));
      
      if (!isNaN(numA) && !isNaN(numB)) {
        return ordenActual.ascendente ? numA - numB : numB - numA;
      }
      
      // Comparación de strings
      return ordenActual.ascendente ? 
        cellA.localeCompare(cellB) : 
        cellB.localeCompare(cellA);
    });
    
    // Re-insertar filas ordenadas
    filas.forEach(fila => tbody.appendChild(fila));
    
    // Actualizar iconos de ordenamiento
    headers.forEach(th => {
      const icon = th.querySelector('.sort-icon');
      if (icon) {
        if (th.dataset.column === columna) {
          icon.textContent = ordenActual.ascendente ? '↑' : '↓';
        } else {
          icon.textContent = '⇅';
        }
      }
    });
  }
  
  // Filtrar tabla por búsqueda
  function filtrarTabla(termino) {
    const tbody = document.getElementById('metricsTableBody');
    const filas = tbody.querySelectorAll('tr');
    const terminoLower = termino.toLowerCase();
    
    filas.forEach(fila => {
      const texto = fila.textContent.toLowerCase();
      fila.style.display = texto.includes(terminoLower) ? '' : 'none';
    });
  }
  
  // Filtrar por categoría
  function filtrarPorCategoria(category) {
    const headers = document.querySelectorAll('#metricsTableHeader th');
    const tbody = document.getElementById('metricsTableBody');
    const filas = tbody.querySelectorAll('tr');
    
    headers.forEach((th, index) => {
      if (category === 'all') {
        th.style.display = '';
        filas.forEach(fila => {
          if (fila.cells[index]) fila.cells[index].style.display = '';
        });
      } else {
        const mostrar = th.classList.contains(category) || index === 0; // Siempre mostrar ID
        th.style.display = mostrar ? '' : 'none';
        filas.forEach(fila => {
          if (fila.cells[index]) fila.cells[index].style.display = mostrar ? '' : 'none';
        });
      }
    });
  }
  
  // Descargar tabla como CSV completo
  async function descargarTablaCSV() {
    if (!objects || objects.length === 0) {
      UtilityHelpers.setStatus('Error: No hay datos para exportar.', true);
      return;
    }
    
    const objetosConMetricas = objects.filter(obj => obj.metrics);
    
    if (objetosConMetricas.length === 0) {
      UtilityHelpers.setStatus('Error: No hay objetos con métricas calculadas.', true);
      return;
    }
    
    console.log(`📁 Exportando tabla CSV con ${objetosConMetricas.length} objetos...`);
    
    let csvContent = '';
    
    // ========================================================================
    // METADATOS DEL PROYECTO
    // ========================================================================
    if (projectManager?.activeProject) {
      csvContent += `# PROYECTO\n`;
      csvContent += `Nombre del Proyecto,${projectManager.activeProject.name || 'N/A'}\n`;
      if (projectManager.activeProject.descripcion) {
        csvContent += `Descripcion,${projectManager.activeProject.descripcion}\n`;
      }
      if (projectManager.activeProject.sitio) {
        csvContent += `Sitio Arqueologico,${projectManager.activeProject.sitio}\n`;
      }
      if (projectManager.activeProject.investigadorResponsable) {
        csvContent += `Investigador Responsable,${projectManager.activeProject.investigadorResponsable}\n`;
      }
      if (projectManager.activeProject.institucionResponsable) {
        csvContent += `Institucion Responsable,${projectManager.activeProject.institucionResponsable}\n`;
      }
      csvContent += `\n`;
    }
    // ========================================================================
    
    // Crear encabezados CSV
    const primeraMetrica = objetosConMetricas[0].metrics;
    const columnas = Object.keys(primeraMetrica).filter(key => 
      !key.startsWith('_') && // Excluir campos privados
      key !== 'vertices_coords' && // Excluir arrays grandes
      key !== 'convex_hull_points'
    );
    
    csvContent += columnas.join(',') + '\n';
    
    // Agregar filas
    objetosConMetricas.forEach(obj => {
      const valores = columnas.map(col => {
        let valor = obj.metrics[col];
        if (valor === undefined || valor === null) return 'N/A';
        if (typeof valor === 'string' && valor.includes(',')) return `"${valor}"`;
        return valor;
      });
      csvContent += valores.join(',') + '\n';
    });
    
    // Descargar archivo con diálogo
    const filename = `coleccion_${objetosConMetricas.length}_objetos`;
    
    await saveFileWithDialog(filename, csvContent, 'csv');
    URL.revokeObjectURL(link.href);
    
    UtilityHelpers.setStatus(`Tabla CSV exportada: ${filename}`, false);
    console.log(`✅ CSV exportado: ${filename} (${objetosConMetricas.length} objetos, ${columnas.length} columnas)`);
  }
  
