    const toggleObjectsBtn = document.getElementById('toggleObjectsBtn');
    if (toggleObjectsBtn) { toggleObjectsBtn.style.display = 'none'; toggleObjectsBtn.textContent = 'Ocultar objetos individuales'; }
    const morphologicalObjectTitle = document.getElementById('morphologicalObjectTitle');
    if (morphologicalObjectTitle) morphologicalObjectTitle.textContent = 'Objeto Analizado (Convex Hull)';
    const morphologicalScaleInfo = document.getElementById('morphologicalScaleInfo');
    if (morphologicalScaleInfo) morphologicalScaleInfo.textContent = '-';
    console.log('   ✅ UI de resultados limpiada');

